def _safe_json(obj: Any) -> str:

    try:

        return json.dumps(obj, ensure_ascii=False, indent=2)

    except Exception:

        return str(obj)



def _alphanum_key(s: str):

    """Trả về key cho natural sort: tách chuỗi thành các phần chữ/số."""

    parts = re.split(r'(\d+)', s)

    return [int(p) if p.isdigit() else p.lower() for p in parts]



def natural_sort_paths(paths: List[Path]) -> List[Path]:

    """Sắp xếp list[Path] theo natural order dựa trên stem (tên không extension)."""

    return sorted(paths, key=lambda p: _alphanum_key(p.stem))



def _extract_strings_recursive(obj: Any, keys: Tuple[str, ...]) -> List[str]:

    results: List[str] = []

    try:

        if isinstance(obj, dict):

            for k, v in obj.items():

                if isinstance(k, str) and k in keys and isinstance(v, str):

                    results.append(v)

                results.extend(_extract_strings_recursive(v, keys))

        elif isinstance(obj, (list, tuple)):

            for item in obj:

                results.extend(_extract_strings_recursive(item, keys))

    except Exception:

        pass

    return results





def _extract_file_urls(obj: Any) -> List[str]:

    # Google có thể trả về fileUrl hoặc fifeUrl hoặc các tên tương tự

    # Mở rộng danh sách các key có thể chứa URL

    candidates = _extract_strings_recursive(obj, (

        "fileUrl", "fifeUrl", "downloadUrl", "mediaUrl", "imageUrl",

        "url", "link", "href", "src", "path", "uri", "videoUrl",

        "thumbnailUrl", "previewUrl", "outputUrl", "resultUrl",

        # Thêm các key patterns khác có thể xuất hiện

        "file", "media", "video", "image", "download", "content"

    ))



    # print(f"🔍 _extract_file_urls: Found {len(candidates)} candidates")

    # for i, c in enumerate(candidates[:10]):  # Show first 10 for debugging

    #     print(f"  {i+1}: {c[:150]}...")



    # Lọc những URL hợp lệ

    urls: List[str] = []

    for u in candidates:

        if isinstance(u, str) and u.startswith("http"):

            lower_u = u.lower()

            # Ưu tiên URL có phần mở rộng tệp

            if any(ext in lower_u for ext in [".mp4", ".jpg", ".png", ".gif", ".webp", ".jpeg", ".mov", ".avi", ".webm"]):

                urls.append(u)

                # print(f"✅ Added URL (file ext): {u[:150]}...")

            # Hoặc URL từ Google storage/CDN

            elif any(domain in lower_u for domain in ["googleapis.com", "googleusercontent.com", "storage.cloud.google.com", "storage.googleapis.com"]):

                urls.append(u)

                # print(f"✅ Added URL (Google domain): {u[:150]}...")

            # Hoặc URL có pattern video/media

            elif any(pattern in lower_u for pattern in ["/video/", "/media/", "/file/", "/download/"]):

                urls.append(u)

                # print(f"✅ Added URL (path pattern): {u[:150]}...")

            # else:

            #     print(f"❌ Rejected URL (no match): {u[:150]}...")



    # Nếu không tìm thấy URL nào, thử tìm kiếm sâu hơn trong nested objects

    if not urls and isinstance(obj, dict):

        # print("🔍 No URLs found, searching nested objects...")

        # Tìm trong các nested arrays và objects

        for key, value in obj.items():

            if isinstance(value, (list, dict)):

                nested_urls = _extract_file_urls(value)

                urls.extend(nested_urls)

            elif isinstance(value, str) and value.startswith("http") and any(ext in value.lower() for ext in [".mp4", ".mov", ".avi", ".webm"]):

                urls.append(value)

                # print(f"✅ Found nested video URL in key '{key}': {value[:150]}...")

    

    elif not urls and isinstance(obj, list):

        # print("🔍 No URLs found, searching list items...")

        for item in obj:

            nested_urls = _extract_file_urls(item)

            urls.extend(nested_urls)



    # Loại trùng

    dedup: List[str] = []

    seen = set()

    for u in urls:

        if u not in seen:

            seen.add(u)

            dedup.append(u)

    

    # print(f"🔍 _extract_file_urls: Returning {len(dedup)} unique URLs")

    return dedup





class GuiLogger:

    def __init__(self, log_queue: "queue.Queue[str]") -> None:

        self.log_queue = log_queue



    def write(self, text: str) -> None:

        if text:

            self.log_queue.put(text)



    def flush(self) -> None:

        pass





