    def _ensure_mp4_path(self, path: Path) -> Path:

        """Ensure the given Path ends with .mp4 if it has no suffix.

        Does not alter paths that already have any suffix.

        """

        try:

            if isinstance(path, Path) and (path.suffix or "").lower() != "":

                return path

            return path.with_suffix(".mp4")

        except Exception:

            return path



    def _ensure_unique_filename(self, path: Path) -> Path:

        """Ensure the filename is unique by adding numbers if file exists.

        Returns a unique Path that doesn't exist on filesystem.

        """

        try:

            # First ensure proper extension

            path = self._ensure_mp4_path(path)

            

            # If file doesn't exist, return as-is

            if not path.exists():

                return path

            

            # File exists, need to make it unique

            base_name = path.stem

            extension = path.suffix

            parent = path.parent

            

            # Try adding numbers until we find a unique name

            counter = 1

            while True:

                new_name = f"{base_name}_{counter:03d}{extension}"

                new_path = parent / new_name

                if not new_path.exists():

                    return new_path

                counter += 1

                

                # Safety check to prevent infinite loop

                if counter > 9999:

                    # Use timestamp as fallback

                    import time

                    timestamp = int(time.time())

                    fallback_name = f"{base_name}_{timestamp}{extension}"

                    return parent / fallback_name

                    

        except Exception as e:

            # Fallback to original path with timestamp

            import time

            timestamp = int(time.time())

            try:

                base = path.stem if path.stem else "file"

                ext = path.suffix if path.suffix else ".mp4"

                fallback_name = f"{base}_{timestamp}{ext}"

                return path.parent / fallback_name

            except Exception:

                return path



    def _prepare_image_for_upload(self, image_path: str) -> str:

        """Prepare image with proper aspect ratio for video generation.

        Returns path to processed image (may be same as input if no processing needed).

        """

        try:

            from PIL import Image

            import tempfile



            # Open and check image

            with Image.open(image_path) as img:

                width, height = img.size



                # Define target aspect ratios

                landscape_ratio = 16/9  # 1.777...

                portrait_ratio = 9/16   # 0.5625

                square_ratio = 1.0



                current_ratio = width / height



                # Determine target ratio and dimensions

                if current_ratio > 1.2:  # Landscape

                    target_ratio = landscape_ratio

                    mode = "landscape"

                elif current_ratio < 0.8:  # Portrait

                    target_ratio = portrait_ratio

                    mode = "portrait"

                else:  # Square

                    target_ratio = square_ratio

                    mode = "square"



                # Check if resize/crop needed

                ratio_diff = abs(current_ratio - target_ratio)

                if ratio_diff < 0.05:  # Close enough, no processing needed

                    return image_path



                self._log(f"📐 Điều chỉnh ảnh từ {width}x{height} (tỉ lệ {current_ratio:.2f}) sang {mode}\n")



                # Calculate new dimensions maintaining quality

                if target_ratio > current_ratio:

                    # Need to crop height or add padding

                    new_width = width

                    new_height = int(width / target_ratio)

                else:

                    # Need to crop width or add padding

                    new_height = height

                    new_width = int(height * target_ratio)



                # Crop to center

                if new_width <= width and new_height <= height:

                    # Crop image

                    left = (width - new_width) // 2

                    top = (height - new_height) // 2

                    right = left + new_width

                    bottom = top + new_height

                    img_processed = img.crop((left, top, right, bottom))

                else:

                    # Resize to fit

                    img_processed = img.resize((new_width, new_height), Image.Resampling.LANCZOS)



                # Save to temp file

                temp_dir = Path(tempfile.gettempdir())

                temp_file = temp_dir / f"resized_{Path(image_path).name}"

                img_processed.save(str(temp_file), quality=95)



                return str(temp_file)



        except Exception as e:

            self._log(f"⚠️ Không thể xử lý ảnh: {e}\n") 

            return image_path  # Return original if processing fails

    def _schedule(self, fn, *args, **kwargs) -> None:

        try:

            self.root.after(0, lambda: fn(*args, **kwargs))

        except Exception:

            pass



    def _center_window(self, win, width: int, height: int) -> None:

        try:

            win.update_idletasks()

            screen_w = win.winfo_screenwidth()

            screen_h = win.winfo_screenheight()

            x = int((screen_w / 2) - (width / 2))

            y = int((screen_h / 2) - (height / 2))

            win.geometry(f"{width}x{height}+{x}+{y}")

        except Exception:

            pass



    def _ensure_default_directories(self) -> None:

        """Tạo thư mục mặc định nếu chưa có"""

        try:

            # Thư mục cho video

            video_dir = Path.cwd() / "downloaded_videos"

            video_dir.mkdir(exist_ok=True)



            # Thư mục cho ảnh

            image_dir = Path.cwd() / "downloaded_images"

            image_dir.mkdir(exist_ok=True)



            # Thư mục cho profile (cố định)

            profile_dir = Path.cwd() / "workflow"

            profile_dir.mkdir(exist_ok=True)



            self._log(f"📁 Đã tạo thư mục mặc định:\n")

            self._log(f"   - Video: {video_dir}\n")

            self._log(f"   - Ảnh: {image_dir}\n")

            self._log(f"   - Profile: {profile_dir}\n")

        except Exception as e:

            self._log(f"⚠️ Không thể tạo thư mục mặc định: {e}\n")



    # ---------------- Cookie Pool Management -----------------

    def _load_cookie_pool(self) -> None:

        """Load cookie pool from JSON file"""

        try:

            cookie_file = Path.cwd() / "cookie_pool.json"

            if cookie_file.exists():

                with open(cookie_file, 'r', encoding='utf-8') as f:

                    data = json.load(f)

                    self.cookie_pool = data.get('cookies', [])

                    self._safe_log(f"📥 Đã tải {len(self.cookie_pool)} cookie từ file\n")

        except Exception as e:

            self._safe_log(f"⚠️ Không thể tải cookie pool: {e}\n")

            self.cookie_pool = []



    def _safe_log(self, message: str) -> None:

        """Safe logging that doesn't depend on log_queue being initialized"""

        try:

            if hasattr(self, 'log_queue') and self.log_queue:

                self._log(message)

            else:

                # Fallback to print if log_queue not ready yet

                print(f"[CookiePool] {message}", end='', flush=True)

        except Exception:

            # Final fallback - just ignore the error

            pass



    def _save_cookie_pool(self) -> None:

        """Save cookie pool to JSON file"""

        try:

            cookie_file = Path.cwd() / "cookie_pool.json"

            data = {'cookies': self.cookie_pool}

            with open(cookie_file, 'w', encoding='utf-8') as f:

                json.dump(data, f, ensure_ascii=False, indent=2)

        except Exception as e:

            self._safe_log(f"⚠️ Không thể lưu cookie pool: {e}\n")



    def _add_cookie_to_pool(self, name: str, cookies: str, video_jobs: int = 5, image_jobs: int = 3, upscale_jobs: int = 3) -> bool:

        """Add a new cookie to the pool"""

        try:

            with self.cookie_pool_lock:

                # Check if cookie already exists

                for cookie in self.cookie_pool:

                    if cookie.get('cookies') == cookies:

                        self._safe_log(f"⚠️ Cookie đã tồn tại trong pool: {name}\n")

                        return False



                # Add new cookie with custom thread counts

                new_cookie = {

                    'name': name,

                    'cookies': cookies,

                    'active': True,

                    'threads': {

                        'video': video_jobs,

                        'image': image_jobs,

                        'upscale': upscale_jobs

                    },

                    'usage_count': 0,

                    'last_used': None

                }

                self.cookie_pool.append(new_cookie)

                self._save_cookie_pool()

                self._safe_log(f"✅ Đã thêm cookie vào pool: {name} (V:{video_jobs} I:{image_jobs} U:{upscale_jobs})\n")

                return True

        except Exception as e:

            self._safe_log(f"❌ Lỗi thêm cookie vào pool: {e}\n")

            return False



    def _remove_cookie_from_pool(self, name: str) -> bool:

        """Remove a cookie from the pool"""

        try:

            with self.cookie_pool_lock:

                original_count = len(self.cookie_pool)

                self.cookie_pool = [c for c in self.cookie_pool if c.get('name') != name]

                if len(self.cookie_pool) < original_count:

                    self._save_cookie_pool()

                    self._safe_log(f"✅ Đã xóa cookie khỏi pool: {name}\n")

                    return True

                else:

                    self._safe_log(f"⚠️ Không tìm thấy cookie: {name}\n")

                    return False

        except Exception as e:

            self._safe_log(f"❌ Lỗi xóa cookie khỏi pool: {e}\n")

            return False



    def _get_next_cookie(self) -> Optional[Dict[str, Any]]:

        """Get next available cookie using round-robin"""

        try:

            with self.cookie_pool_lock:

                if not self.cookie_pool:

                    return None



                # Filter active cookies

                active_cookies = [c for c in self.cookie_pool if c.get('active', True)]

                if not active_cookies:

                    return None



                # Round-robin selection

                cookie = active_cookies[self.current_cookie_index % len(active_cookies)]

                self.current_cookie_index += 1



                # Update usage stats

                cookie['usage_count'] = cookie.get('usage_count', 0) + 1

                cookie['last_used'] = _t.time()



                return cookie

        except Exception as e:

            self._safe_log(f"❌ Lỗi lấy cookie tiếp theo: {e}\n")

            return None



    def _calculate_max_threads(self) -> Dict[str, int]:

        """Calculate maximum threads based on active cookies and their individual thread counts"""

        try:

            with self.cookie_pool_lock:

                active_cookies = [c for c in self.cookie_pool if c.get('active', True)]



                if not active_cookies:

                    return dict(self.default_per_cookie_threads)



                # Calculate total threads by summing individual cookie thread counts

                total_threads = {

                    'video': 0,

                    'image': 0,

                    'upscale': 0

                }



                for cookie in active_cookies:

                    cookie_threads = cookie.get('threads', {})

                    total_threads['video'] += cookie_threads.get('video', self.default_per_cookie_threads['video'])

                    total_threads['image'] += cookie_threads.get('image', self.default_per_cookie_threads['image'])

                    total_threads['upscale'] += cookie_threads.get('upscale', self.default_per_cookie_threads['upscale'])



                # Apply safety limit per thread type

                for thread_type in total_threads:

                    total_threads[thread_type] = min(total_threads[thread_type], self.max_total_threads)



                return total_threads

        except Exception as e:

            self._safe_log(f"❌ Lỗi tính toán thread: {e}\n")

            return dict(self.default_per_cookie_threads)



    def _calculate_max_concurrent_jobs(self) -> int:

        """Calculate max concurrent jobs based on active cookies and upscale setting"""

        try:

            with self.cookie_pool_lock:

                active_cookies = [c for c in self.cookie_pool if c.get('active', True)]

                if not active_cookies:

                    # Default: 1 cookie worth of threads

                    return 5  # Default video threads per cookie

                

                # Check if upscale is enabled

                upscale_enabled = False

                if hasattr(self, 'var_do_upscale'):

                    try:

                        upscale_enabled = self.var_do_upscale.get()

                    except Exception:

                        pass

                

                # 1 cookie = 5 video + 3 image threads, OR 3 video + 3 image if upscale enabled

                max_per_cookie = 3 if upscale_enabled else 5

                return len(active_cookies) * max_per_cookie

        except Exception as e:

            self._safe_log(f"❌ Lỗi tính toán max concurrent jobs: {e}\n")

            return 5  # Safe default



