    def _refresh_cookie_tree(self) -> None:

        """Refresh cookie treeview"""

        try:

            if hasattr(self, 'cookie_tree'):

                # Clear existing items

                for item in self.cookie_tree.get_children():

                    self.cookie_tree.delete(item)



                # Add cookies to tree

                for i, cookie in enumerate(self.cookie_pool):

                    name = cookie.get('name', f'Cookie {i+1}')

                    active = cookie.get('active', True)



                    # Get thread counts

                    threads = cookie.get('threads', {})

                    video_jobs = threads.get('video', 5)

                    image_jobs = threads.get('image', 3)

                    upscale_jobs = threads.get('upscale', 3)

                    threads_str = f"{video_jobs}/{image_jobs}/{upscale_jobs}"



                    status = "✅ Active" if active else "❌ Inactive"

                    status_tag = "active" if active else "inactive"



                    self.cookie_tree.insert("", "end", values=(

                        name, status, threads_str

                    ), tags=(status_tag,))



                # Configure tags

                self.cookie_tree.tag_configure("active", foreground="green")

                self.cookie_tree.tag_configure("inactive", foreground="red")



        except Exception as e:

            self._log(f"❌ Lỗi refresh cookie tree: {e}\n")



    def _on_cookie_tree_select(self, event) -> None:

        """Handle cookie tree selection"""

        try:

            selection = self.cookie_tree.selection()

            if selection:

                item = selection[0]

                values = self.cookie_tree.item(item, "values")

                if values:

                    name = values[0]

                    # Find cookie in pool

                    for cookie in self.cookie_pool:

                        if cookie.get('name') == name:

                            self.ent_cookie_name.delete(0, 'end')

                            self.ent_cookie_name.insert(0, cookie.get('name', ''))

                            self.txt_cookie_content.delete('1.0', 'end')

                            self.txt_cookie_content.insert('1.0', cookie.get('cookies', ''))



                            # Load thread counts

                            threads = cookie.get('threads', {})

                            video_jobs = threads.get('video', 5)

                            image_jobs = threads.get('image', 3)

                            upscale_jobs = threads.get('upscale', 3)



                            if hasattr(self, 'cmb_video_jobs'):

                                self.cmb_video_jobs.set(str(video_jobs))

                            if hasattr(self, 'cmb_image_jobs'):

                                self.cmb_image_jobs.set(str(image_jobs))

                            if hasattr(self, 'cmb_upscale_jobs'):

                                self.cmb_upscale_jobs.set(str(upscale_jobs))

                            break

        except Exception as e:

            self._log(f"❌ Lỗi chọn cookie: {e}\n")



    def _on_cookie_double_click(self, event) -> None:

        """Handle double click to edit"""

        self._on_cookie_tree_select(event)



    def _clear_cookie_form(self) -> None:

        """Clear cookie form"""

