    def on_choose_extend_txt_file(self) -> None:

        """Chọn file txt chứa các đoạn text"""

        try:

            path = filedialog.askopenfilename(

                title="Chọn file TXT",

                filetypes=[("Text files", "*.txt"), ("All files", "*.*")]

            )

            if path:

                self.ent_extend_txt_file.delete(0, "end")

                self.ent_extend_txt_file.insert(0, path)

                

                # Preview số dòng và tính số projects

                try:

                    from extend_videos import parse_text_file

                    segments = parse_text_file(path)

                    group_size = int(self.cmb_extend_group_size.get())

                    num_projects = (len(segments) + group_size - 1) // group_size

                    

                    info = f"📝 {len(segments)} đoạn → {num_projects} project(s) (mỗi project {group_size} đoạn)"

                    self.lbl_extend_info.configure(text=info)

                    self._log(f"{info}\n")

                except Exception:

                    pass

        except Exception as e:

            self._log(f"❌ Lỗi chọn file: {e}\n")

    

    def _on_extend_task_click(self, event) -> None:

        """Xử lý click vào task - nếu có lỗi thì hiện popup để sửa prompt"""

        try:

            # Identify clicked row and column

            row_id = self.lst_extend_tasks.identify_row(event.y)

            col_id = self.lst_extend_tasks.identify_column(event.x)

            

            if not row_id:

                return

            

            # Check if clicked on action column

            col_index = int(col_id.replace('#', '')) - 1

            if col_index == 4:  # Action column

                vals = self.lst_extend_tasks.item(row_id, "values")

                if len(vals) >= 5:

                    status = vals[3]

                    # Nếu có lỗi hoặc có nút warning

                    if "❌" in status or "⚠️" in vals[4]:

                        self._show_edit_prompt_dialog(row_id, vals)

        except Exception as e:

            self._log(f"⚠️ Lỗi xử lý click: {e}\n")

    

    def _show_edit_prompt_dialog(self, row_id: str, vals: tuple) -> None:

        """Hiện dialog để sửa prompt khi có lỗi"""

        try:

            project_name = vals[0]

            segment_info = vals[1]

            old_text = vals[2]

            

            # Tạo popup dialog

            dialog = tb.Toplevel(self.root)

            dialog.title(f"⚠️ Sửa Prompt - {project_name} - {segment_info}")

            dialog.geometry("600x300")

            

            with suppress(Exception):

                self._center_window(dialog, 600, 300)

            

            frame = tb.Frame(dialog, padding=20)

            frame.pack(fill="both", expand=True)

            

            # Info

            tb.Label(frame, text=f"Project: {project_name} | Đoạn: {segment_info}", 

                    font=("Arial", 10, "bold")).pack(anchor="w", pady=(0, 10))

            

            # Text editor

            tb.Label(frame, text="Sửa prompt (Enter để lưu, Esc để hủy):").pack(anchor="w")

            txt_edit = scrolledtext.ScrolledText(frame, height=6, wrap="word")

            txt_edit.pack(fill="both", expand=True, pady=4)

            txt_edit.insert("1.0", old_text)

            txt_edit.focus_set()

            

            # Buttons

            btn_frame = tb.Frame(frame)

            btn_frame.pack(fill="x", pady=(10, 0))

            

            def save_and_retry():

                new_text = txt_edit.get("1.0", "end").strip()

                if new_text and new_text != old_text:

                    # Update text in table

                    new_vals = list(vals)

                    new_vals[2] = new_text

                    new_vals[3] = "🔄 Đang thử lại..."

                    new_vals[4] = ""

                    self.lst_extend_tasks.item(row_id, values=new_vals)

                    

                    # TODO: Trigger retry cho segment này

                    self._log(f"🔄 Đã cập nhật prompt, sẽ thử lại...\n")

                    

                dialog.destroy()

            

            tb.Button(btn_frame, text="Lưu & Thử lại", bootstyle="success", 

                     command=save_and_retry, width=16).pack(side="left", padx=4)

            tb.Button(btn_frame, text="Hủy", command=dialog.destroy, width=10).pack(side="left", padx=4)

            

            # Shortcuts

            txt_edit.bind("<Control-Return>", lambda e: save_and_retry())

            dialog.bind("<Escape>", lambda e: dialog.destroy())

            

            dialog.transient(self.root)

            dialog.grab_set()

            

        except Exception as e:

            self._log(f"❌ Lỗi hiện dialog sửa prompt: {e}\n")



    def on_extend_video_start(self) -> None:

        """Bắt đầu xử lý extend video với logic gom nhóm"""

        try:

            # Validate inputs

            txt_file = self.ent_extend_txt_file.get().strip()

            if not txt_file or not Path(txt_file).exists():

                Messagebox.show_error("Vui lòng chọn file TXT hợp lệ!")

                return

            

            cookies = self._get_cookies_source()

            if not cookies:

                Messagebox.show_error("Vui lòng nhập Cookie ở tab Video!")

                return

            

            # Get group size

            try:

                group_size = int(self.cmb_extend_group_size.get())

            except:

                group_size = 5

            

            # Disable controls

            self.btn_extend_start.configure(state="disabled")

            self.btn_extend_stop.configure(state="normal")

            self.var_extend_status.set("Đang xử lý...")

            self.pb_extend.start(10)

            

            # Clear project table

            for item in self.lst_extend_projects.get_children():

                self.lst_extend_projects.delete(item)

            

            # Initialize stop event

            if not hasattr(self, 'extend_stop_event'):

                self.extend_stop_event = threading.Event()

            self.extend_stop_event.clear()

            

            # Start processing in background

            threading.Thread(

                target=self._extend_worker,

                args=(txt_file, group_size, cookies),

                daemon=True

            ).start()

            

        except Exception as e:

            self._log(f"❌ Lỗi bắt đầu extend: {e}\n")

            self._finalize_extend()

    

    def on_extend_video_stop(self) -> None:

        """Dừng extend processing"""

        try:

            if hasattr(self, 'extend_stop_event'):

                self.extend_stop_event.set()

            self.var_extend_status.set("Đang dừng...")

            self._log("🛑 Đang dừng extend...\n")

        except Exception:

            pass

    

    def _extend_worker(self, txt_file: str, group_size: int, cookies: str) -> None:

        """Worker thread xử lý extend video"""

        try:

            from extend_videos import parse_text_file, create_projects_from_segments, ExtendVideoProcessor

            

            self._log(f"\n{'='*70}\n")

            self._log(f"🎬 BẮT ĐẦU EXTEND VIDEO\n")

            self._log(f"{'='*70}\n")

            

            # Parse file txt

            segments = parse_text_file(txt_file)

            if not segments:

                self._log("❌ File txt rỗng hoặc không đọc được\n")

                self._schedule(Messagebox.show_error, "File txt rỗng!")

                return

            

            self._log(f"📄 Đọc được {len(segments)} đoạn từ file\n")

            

            # Tạo projects

            projects = create_projects_from_segments(segments, group_size)

            self._log(f"📦 Tạo {len(projects)} project(s), mỗi project {group_size} đoạn\n\n")

            

            # Build client

            client = self._build_client(cookies)

            if not client or not client.fetch_access_token():

                self._log("❌ Không thể tạo client hoặc lấy token\n")

                return

            

            # Process từng project song song (max 3 projects cùng lúc)

            from concurrent.futures import ThreadPoolExecutor, as_completed

            max_workers = min(3, len(projects))

            

            self._log(f"🚀 Xử lý {len(projects)} project(s) song song (max {max_workers} workers)\n\n")

            

            # Add rows to project table (1 row per project)

            self.extend_projects_data = {}  # Map project_name -> project_data

            self.extend_project_row_map = {}  # Map project_name -> row_id

            

            for project in projects:

                # Store project data in memory

                self.extend_projects_data[project.project_name] = project

                

                # Add project row to table

                row_id = self.lst_extend_projects.insert("", "end", values=(

                        project.project_name,

                    f"{len(project.segments)} đoạn",

                        "⏳ Đang chờ...",

                    "0%",

                        ""

                    ))

                self.extend_project_row_map[project.project_name] = row_id

            

            # Process projects in parallel

            with ThreadPoolExecutor(max_workers=max_workers) as executor:

                # Submit all projects

                future_to_project = {}

                for project in projects:

                    if self.extend_stop_event.is_set():

                        break

                    

                    # Create processor for this project

                    processor = ExtendVideoProcessor(client, log_callback=self._log)

                    

                    # Submit project

                    future = executor.submit(

                        self._process_extend_project,

                        processor,

                        project,

                        txt_file  # Pass txt_file parameter

                    )

                    future_to_project[future] = project

                

                # Wait for completion

                completed_count = 0

                for future in as_completed(future_to_project):

                    if self.extend_stop_event.is_set():

                        break

                    

                    project = future_to_project[future]

                    try:

                        success = future.result()

                        completed_count += 1

                        if success:

                            self._log(f"✅ {project.project_name} hoàn thành ({completed_count}/{len(projects)})\n")

                        else:

                            self._log(f"❌ {project.project_name} thất bại ({completed_count}/{len(projects)})\n")

                    except Exception as e:

                        self._log(f"❌ {project.project_name} lỗi: {e}\n")

            

            self._log(f"\n🎉 HOÀN TẤT EXTEND VIDEO!\n")

            self._schedule(self.var_extend_status.set, "Hoàn tất")

            

        except Exception as e:

            self._log(f"❌ Lỗi extend worker: {e}\n")

            import traceback

            self._log(f"🔍 Traceback: {traceback.format_exc()}\n")

        finally:

            self._schedule(self._finalize_extend)

    

    def _process_extend_project(self, processor, project, txt_file: str) -> bool:

        """Xử lý 1 project extend"""

        try:

            # Status callback để update UI (project-based)

            def status_callback(global_idx: int, status: str, message: str):

                try:

                    # Find segment and update its status

                    for segment in project.segments:

                        if segment.global_index == global_idx:

                            if status == "processing":

                                segment.status = "processing"

                            elif status == "completed":

                                segment.status = "completed"

                            elif status == "error":

                                segment.status = "error"

                                segment.error_message = message

                                

                                # Show error notification

                                self._schedule(self._show_segment_error_notification, project, segment)

                            break

                    

                    # Update project table immediately

                    self._schedule(self._update_project_table_row, project)

                    

                    # Update segments tree in modal if it exists

                    self._schedule(self._refresh_segments_tree, project)

                except Exception:

                    pass

            

            # Get output directory from UI

            output_dir_str = self.ent_extend_output_folder.get().strip()

            if not output_dir_str:

                output_dir_str = str(Path.home() / "Downloads" / "Extended_Videos")

            

            # Process project with proper parameters

            self._log(f"🚀 Bắt đầu xử lý project: {project.project_name}\n")

            success = processor.process_project(

                project=project,

                output_dir=output_dir_str,  # Pass as string

                txt_filename=txt_file,      # Pass txt filename

                status_callback=status_callback

            )

            

            if success:

                self._log(f"✅ Project {project.project_name} xử lý thành công!\n")

                

                # Check if concat_url is already a local file or needs download

                if project.concat_url:

                    # Check if concat_url is local file path (not HTTP URL)

                    if isinstance(project.concat_url, str) and not project.concat_url.startswith("http"):

                        # It's a local file path - already saved by extend_videos.py

                        local_path = Path(project.concat_url)

                        if local_path.exists():

                            self._log(f"✅ Video đã được lưu sẵn: {local_path}\n")

                            self._log(f"📁 Đường dẫn: {local_path.absolute()}\n")

                            self._log(f"📊 Kích thước: {local_path.stat().st_size / 1024 / 1024:.2f} MB\n")

                            # Mark project as completed

                            project.status = "completed"

                            self._schedule(self._update_project_table_row, project)

                        else:

                            self._log(f"⚠️ Video path không tồn tại: {local_path}\n")

                    else:

                        # It's a URL - need to download

                        self._log(f"📥 Bắt đầu download video từ URL: {project.concat_url}\n")

                    

                    try:

                        output_dir = Path(self.ent_extend_output_folder.get().strip())

                        output_dir.mkdir(parents=True, exist_ok=True)

                        

                        filename = output_dir / f"{project.project_name}_extended.mp4"

                        self._log(f"💾 Lưu video vào: {filename}\n")

                        

                        # Download video

                        download_success = self._download_via_requests_simple(project.concat_url, filename)

                        

                        if download_success:

                            self._log(f"✅ Đã lưu video thành công: {filename.name}\n")

                            self._log(f"📁 Đường dẫn: {filename.absolute()}\n")

                            # Mark project as completed

                            project.status = "completed"

                            self._schedule(self._update_project_table_row, project)

                        else:

                            self._log(f"❌ Lỗi download video: {project.project_name}\n")

                            

                    except Exception as e:

                        self._log(f"❌ Lỗi download video: {e}\n")

                        import traceback

                        self._log(f"🔍 Traceback: {traceback.format_exc()}\n")

                else:

                    self._log(f"⚠️ Project {project.project_name} thành công nhưng không có concat_url\n")

            else:

                self._log(f"❌ Project {project.project_name} thất bại\n")

            

            return success

            

        except Exception as e:

            self._log(f"❌ Lỗi process extend project: {e}\n")

            import traceback

            self._log(f"🔍 Traceback: {traceback.format_exc()}\n")

            return False

    

    def _finalize_extend(self) -> None:

        """Kết thúc extend processing"""

        try:

            self.btn_extend_start.configure(state="normal")

            self.btn_extend_stop.configure(state="disabled")

            self.pb_extend.stop()

            if self.var_extend_status.get() != "Hoàn tất":

                self.var_extend_status.set("Sẵn sàng")

        except Exception:

            pass



    def _extend_text_to_video_start(self) -> None:

        """Process all .txt files in selected folder: one video per prompt using Video tab configs."""

        try:

            # Validate cookies from Video tab

            cookies_src = self._get_cookies_source()

            if not cookies_src:

                Messagebox.show_error("Vui lòng nhập Cookie ở tab Video.")

                return



            # Read folder of txt

            txt_dir = getattr(self, 'ent_extend_txt_folder', None).get().strip() if hasattr(self, 'ent_extend_txt_folder') else ""

            if not txt_dir or not os.path.isdir(txt_dir):

                Messagebox.show_error("Vui lòng chọn thư mục chứa các file .txt hợp lệ.")

                return



            out_dir = getattr(self, 'ent_extend_output_folder', None).get().strip() if hasattr(self, 'ent_extend_output_folder') else ""

            if not out_dir:

                out_dir = str(Path.cwd() / "downloaded_videos")

            Path(out_dir).mkdir(parents=True, exist_ok=True)



            # Collect txt files

            all_txt = [p for p in sorted(Path(txt_dir).glob("*.txt")) if p.is_file()]

            if not all_txt:

                self._log("[Extend] Không tìm thấy file .txt nào.\n")

                return



            self._log(f"[Extend] Tìm thấy {len(all_txt)} file .txt\n")



            # Build client once

            client = self._build_client(cookies_src)

            if client is None:

                return

            if not client.fetch_access_token():

                self._log("[Extend] Lấy access token thất bại.\n")

                return



            # Use Video tab configs

            # Force model for Extend Text-to-Video as requested

            model_key = "veo_3_1_t2v_fast_ultra"

            tool = self.ent_tool.get().strip() if hasattr(self, 'ent_tool') else "PINHOLE"

            tier = self.cmb_tier.get().strip() if hasattr(self, 'cmb_tier') else "PAYGATE_TIER_TWO"

            # Force landscape aspect ratio for this flow

            aspect = "VIDEO_ASPECT_RATIO_LANDSCAPE"



            # Submit batch log like Video tab

            client.submit_batch_log(tool)



            # Sequentially process each prompt file, one video per prompt

            for idx, txt_path in enumerate(all_txt, 1):

                if hasattr(self, 'extend_stop_event') and self.extend_stop_event.is_set():

                    break



                try:

                    prompt = txt_path.read_text(encoding="utf-8").strip()

                except Exception as e:

                    self._log(f"[Extend] Lỗi đọc {txt_path.name}: {e}\n")

                    continue

                if not prompt:

                    self._log(f"[Extend] Bỏ qua {txt_path.name}: prompt rỗng\n")

                    continue



                # Add row to table

                iid = self.lst_extend_tasks.insert("", "end", values=(txt_path.name, prompt[:60] + ("..." if len(prompt) > 60 else ""), "Đang tạo", "0%"))



                # Generate exactly 1 video

                import uuid as _uuid

                project = str(_uuid.uuid4())

                operations = client.generate_videos(

                    project_id=project,

                    tool=tool,

                    user_tier=tier or "PAYGATE_TIER_TWO",

                    prompt=prompt,

                    model_key=model_key,

                    num_videos=1,

                    aspect_ratio=aspect,

                )

                if not operations:

                    self._log(f"[Extend] Bắt đầu tạo video thất bại: {txt_path.name}\n")

                    # Ghi lỗi vào error log riêng cho file này

                    try:

                        from datetime import datetime

                        timestamp = datetime.now().strftime("%Y%m%d_%H%M%S")

                        error_log_path = Path(out_dir) / f"error_log_{txt_path.stem}_{timestamp}.txt"

                        with open(error_log_path, 'a', encoding='utf-8') as ef:

                            ef.write(f"[{datetime.now().strftime('%Y-%m-%d %H:%M:%S')}] [File: {txt_path.name}] {prompt} -> Bắt đầu tạo video thất bại\n")

                        self._log(f"📝 Đã ghi lỗi vào file: {error_log_path}\n")

                    except Exception as log_e:

                        self._log(f"⚠️ Không thể ghi error log: {log_e}\n")

                    try:

                        self.lst_extend_tasks.set(iid, "status", "Lỗi")

                    except Exception:

                        pass

                    continue



                # Poll like Video tab

                max_wait = int(self.spn_max_wait.get()) if hasattr(self, 'spn_max_wait') else 360

                poll_interval = int(self.spn_poll.get()) if hasattr(self, 'spn_poll') else 10

                deadline = _t.time() + max_wait

                last_status = None

                while _t.time() < deadline and not (hasattr(self, 'extend_stop_event') and self.extend_stop_event.is_set()):

                    status = client.check_video_status(operations)

                    if status is not None:

                        last_status = status

                        # small UI update

                        try:

                            self.lst_extend_tasks.set(iid, "status", "Đang xử lý")

                        except Exception:

                            pass

                        # completion check

                        if isinstance(status, dict) and "operations" in status:

                            done = any("COMPLETE" in str(op.get("status", "")).upper() or "SUCCESS" in str(op.get("status", "")).upper() for op in status["operations"])

                            # Kiểm tra lỗi và ghi vào error log

                            for op in status["operations"]:

                                s = str(op.get("status", "")).upper()

                                if "FAIL" in s or "ERROR" in s:

                                    # Ghi lỗi vào error log riêng cho file này

                                    try:

                                        error_msg = "Unknown error"

                                        if "operation" in op and "error" in op["operation"]:

                                            error_info = op["operation"]["error"]

                                            error_msg = error_info.get("message", "Unknown error")

                                            error_code = error_info.get("code", "Unknown")

                                            error_msg = f"{error_msg} (Code: {error_code})"

                                        

                                        from datetime import datetime

                                        timestamp = datetime.now().strftime("%Y%m%d_%H%M%S")

                                        error_log_path = Path(out_dir) / f"error_log_{txt_path.stem}_{timestamp}.txt"

                                        with open(error_log_path, 'a', encoding='utf-8') as ef:

                                            ef.write(f"[{datetime.now().strftime('%Y-%m-%d %H:%M:%S')}] [File: {txt_path.name}] {prompt} -> {error_msg}\n")

                                        self._log(f"📝 Đã ghi lỗi vào file: {error_log_path}\n")

                                    except Exception as log_e:

                                        self._log(f"⚠️ Không thể ghi error log: {log_e}\n")

                            if done:

                                break

                    _t.sleep(poll_interval)



                final = last_status or {}

                urls = _extract_file_urls(final)

                if urls:

                    url = urls[0]

                    # Build filename from prompt file name

                    safe_name = txt_path.stem.replace(" ", "_")

                    filename = Path(out_dir) / f"extend_tv_{safe_name}.mp4"

                    try:

                        self._download_via_requests_simple(url, filename)

                        try:

                            self.lst_extend_tasks.set(iid, "status", "Hoàn tất")

                            self.lst_extend_tasks.set(iid, "progress", "100%")

                        except Exception:

                            pass

                        self._log(f"[Extend] ✅ Tải về: {filename.name}\n")

                        # === PHASE 2: Extend video segments using extend endpoint (multiple) ===

                        # Determine iterations from target seconds (<=141s)

                        try:

                            target_secs = int(self.spn_extend_target_seconds.get()) if hasattr(self, 'spn_extend_target_seconds') else 32

                        except Exception:

                            target_secs = 32

                        remaining = max(0, min(141, target_secs) - 8)  # first clip ~8s

                        extend_count = (remaining + 7) // 8  # ceil



                        try:

                            base_ids = self._extract_media_ids(final) if hasattr(self, '_extract_media_ids') else []

                        except Exception:

                            base_ids = []

                        if base_ids:

                            base_media_id = base_ids[0]

                            self._log(f"[Extend] 🎯 Base mediaId: {base_media_id}\n")



                            all_segment_urls = []

                            # Include the first 8s url

                            all_segment_urls.append(url)



                            for ei in range(extend_count):

                                if hasattr(self, 'extend_stop_event') and self.extend_stop_event.is_set():

                                    break

                                extend_ops = self._extend_request_extend_video(

                                    client=client,

                                    base_media_id=base_media_id,

                                    prompt=prompt,

                                    aspect=aspect,

                                    model_key="veo_3_1_extend_fast_landscape_ultra",

                                    start_idx=168,

                                    end_idx=191,

                                )

                                if not extend_ops:

                                    self._log("[Extend] ⚠ Extend operation không khởi tạo được.\n")

                                    # Ghi lỗi vào error log riêng cho file này

                                    try:

                                        from datetime import datetime

                                        timestamp = datetime.now().strftime("%Y%m%d_%H%M%S")

                                        error_log_path = Path(out_dir) / f"error_log_{txt_path.stem}_{timestamp}.txt"

                                        with open(error_log_path, 'a', encoding='utf-8') as ef:

                                            ef.write(f"[{datetime.now().strftime('%Y-%m-%d %H:%M:%S')}] [File: {txt_path.name}] {prompt} -> Extend operation không khởi tạo được\n")

                                        self._log(f"📝 Đã ghi lỗi vào file: {error_log_path}\n")

                                    except Exception as log_e:

                                        self._log(f"⚠️ Không thể ghi error log: {log_e}\n")

                                    break



                                self._log(f"[Extend] ⏳ Poll extend operation {ei+1}/{extend_count}...\n")

                                deadline2 = _t.time() + max_wait

                                last_status2 = None

                                while _t.time() < deadline2 and not (hasattr(self, 'extend_stop_event') and self.extend_stop_event.is_set()):

                                    st2 = client.check_video_status(extend_ops)

                                    if st2 is not None:

                                        last_status2 = st2

                                        if isinstance(st2, dict) and "operations" in st2:

                                            done2 = any("COMPLETE" in str(op.get("status", "")).upper() or "SUCCESS" in str(op.get("status", "")).upper() for op in st2["operations"])

                                            if done2:

                                                break

                                    _t.sleep(poll_interval)



                                # Extract URL for this extend segment and download

                                seg_urls = _extract_file_urls(last_status2 or {})

                                if seg_urls:

                                    seg_url = seg_urls[0]

                                    all_segment_urls.append(seg_url)

                                else:

                                    self._log("[Extend] ⚠ Không tìm thấy URL cho đoạn extend.\n")

                                    # Ghi lỗi vào error log riêng cho file này

                                    try:

                                        from datetime import datetime

                                        timestamp = datetime.now().strftime("%Y%m%d_%H%M%S")

                                        error_log_path = Path(out_dir) / f"error_log_{txt_path.stem}_{timestamp}.txt"

                                        with open(error_log_path, 'a', encoding='utf-8') as ef:

                                            ef.write(f"[{datetime.now().strftime('%Y-%m-%d %H:%M:%S')}] [File: {txt_path.name}] {prompt} -> Không tìm thấy URL cho đoạn extend\n")

                                        self._log(f"📝 Đã ghi lỗi vào file: {error_log_path}\n")

                                    except Exception as log_e:

                                        self._log(f"⚠️ Không thể ghi error log: {log_e}\n")

                                    break



                            # Fallback local concatenation using ffmpeg if multiple segments exist

                            if len(all_segment_urls) > 1:

                                try:

                                    concat_dir = Path(out_dir)

                                    concat_dir.mkdir(parents=True, exist_ok=True)

                                    # Download all segments to temp files

                                    temp_files = []

                                    for si, su in enumerate(all_segment_urls):

                                        tmp_path = concat_dir / f"seg_{safe_name}_{si}.mp4"

                                        self._download_via_requests_simple(su, tmp_path)

                                        temp_files.append(tmp_path)

                                    # Write list file for ffmpeg concat demuxer

                                    list_path = concat_dir / f"list_{safe_name}.txt"

                                    with open(list_path, "w", encoding="utf-8") as lf:

                                        for fp in temp_files:

                                            lf.write(f"file '{fp.as_posix()}'\n")

                                    # Output file

                                    final_path = concat_dir / f"extend_concat_{safe_name}.mp4"

                                    # Run ffmpeg concat demuxer

                                    import subprocess

                                    import os

                                    cmd = [

                                        str(Path.cwd() / "ffmpeg.exe"), "-y", "-f", "concat", "-safe", "0",

                                        "-i", str(list_path), "-c", "copy", str(final_path)

                                    ]

                                    creationflags = subprocess.CREATE_NO_WINDOW if os.name == 'nt' else 0

                                    subprocess.run(cmd, check=True, stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL,

                                                   creationflags=creationflags)

                                    self._log(f"[Extend] ✅ Ghép cục bộ xong: {final_path.name}\n")

                                except Exception as le:

                                    self._log(f"[Extend] ❌ Lỗi ghép cục bộ: {le}\n")

                                    # Ghi lỗi vào error log riêng cho file này

                                    try:

                                        from datetime import datetime

                                        timestamp = datetime.now().strftime("%Y%m%d_%H%M%S")

                                        error_log_path = Path(out_dir) / f"error_log_{txt_path.stem}_{timestamp}.txt"

                                        with open(error_log_path, 'a', encoding='utf-8') as ef:

                                            ef.write(f"[{datetime.now().strftime('%Y-%m-%d %H:%M:%S')}] [File: {txt_path.name}] {prompt} -> Lỗi ghép cục bộ: {le}\n")

                                        self._log(f"📝 Đã ghi lỗi vào file: {error_log_path}\n")

                                    except Exception as log_e:

                                        self._log(f"⚠️ Không thể ghi error log: {log_e}\n")

                    except Exception as de:

                        self._log(f"[Extend] ❌ Lỗi tải video: {de}\n")

                        # Ghi lỗi vào error log riêng cho file này

                        try:

                            from datetime import datetime

                            timestamp = datetime.now().strftime("%Y%m%d_%H%M%S")

                            error_log_path = Path(out_dir) / f"error_log_{txt_path.stem}_{timestamp}.txt"

                            with open(error_log_path, 'a', encoding='utf-8') as ef:

                                ef.write(f"[{datetime.now().strftime('%Y-%m-%d %H:%M:%S')}] [File: {txt_path.name}] {prompt} -> Lỗi tải video: {de}\n")

                            self._log(f"📝 Đã ghi lỗi vào file: {error_log_path}\n")

                        except Exception as log_e:

                            self._log(f"⚠️ Không thể ghi error log: {log_e}\n")

                        try:

                            self.lst_extend_tasks.set(iid, "status", "Lỗi tải")

                        except Exception:

                            pass

                else:

                    self._log(f"[Extend] ⚠ Không tìm thấy URL video cho {txt_path.name}\n")

                    # Ghi lỗi vào error log riêng cho file này

                    try:

                        from datetime import datetime

                        timestamp = datetime.now().strftime("%Y%m%d_%H%M%S")

                        error_log_path = Path(out_dir) / f"error_log_{txt_path.stem}_{timestamp}.txt"

                        with open(error_log_path, 'a', encoding='utf-8') as ef:

                            ef.write(f"[{datetime.now().strftime('%Y-%m-%d %H:%M:%S')}] [File: {txt_path.name}] {prompt} -> Không tìm thấy URL video\n")

                        self._log(f"📝 Đã ghi lỗi vào file: {error_log_path}\n")

                    except Exception as log_e:

                        self._log(f"⚠️ Không thể ghi error log: {log_e}\n")

                    try:

                        self.lst_extend_tasks.set(iid, "status", "Không có URL")

                    except Exception:

                        pass



        except Exception as e:

            self._log(f"[Extend] Lỗi xử lý Text-to-Video: {e}\n")

        finally:

            with suppress(Exception):

                self.btn_extend_start.configure(state="normal")

                self.btn_extend_stop.configure(state="disabled")

                self.var_extend_status.set("Sẵn sàng")

                self.pb_extend.stop()



    # === Helpers for Extend flow ===

    def _extend_request_extend_video(self, client, base_media_id: str, prompt: str, aspect: str, model_key: str, start_idx: int, end_idx: int):

        """Call extend-video endpoint for one segment and return operations array."""

        try:

            url = "https://aisandbox-pa.googleapis.com/v1/video:batchAsyncGenerateVideoExtendVideo"

            headers = client._aisandbox_headers() if hasattr(client, '_aisandbox_headers') else {}

            import uuid as _uuid

            payload = {

                "clientContext": {

                    "tool": "PINHOLE",

                    "userPaygateTier": "PAYGATE_TIER_TWO"

                },

                "requests": [

                    {

                        "textInput": {"prompt": prompt},

                        "videoInput": {

                            "mediaId": base_media_id,

                            "startFrameIndex": int(start_idx),

                            "endFrameIndex": int(end_idx)

                        },

                        "videoModelKey": model_key,

                        "aspectRatio": aspect,

                        "seed": int(_t.time()) % 100000,

                        "metadata": {"sceneId": str(_uuid.uuid4())}

                    }

                ]

            }

            self._log("[Extend] 🚀 Gửi extend request...\n")

            resp = client.session.post(url, headers=headers, json=payload, timeout=120)

            self._log(f"[Extend] 📥 Extend status: {resp.status_code}\n")

            if resp.status_code == 200:

                js = resp.json()

                ops = js.get("operations", [])

                if ops:

                    return ops

            else:

                try:

                    self._log(f"[Extend] ❌ Extend error: {resp.text[:200]}\n")

                except Exception:

                    pass

            return None

        except Exception as e:

            self._log(f"[Extend] ❌ Lỗi extend request: {e}\n")

            return None



    def _extend_concatenate_videos(self, media_ids: list) -> Optional[str]:

        """Submit concatenate request. Requires labs session cookies; return operation name if submitted."""

        try:

            # NOTE: This endpoint requires browser session cookies (labs). If unavailable, skip.

            labs_cookie = ""

            try:

                if hasattr(self, 'ent_extend_labs_cookie'):

                    labs_cookie = self.ent_extend_labs_cookie.get().strip()

            except Exception:

                pass

            if not labs_cookie:

                labs_cookie = os.environ.get("LABS_FX_COOKIE", "")

            if not labs_cookie:

                self._log("[Extend] ⚠ Thiếu Labs FX cookie (LABS_FX_COOKIE). Bỏ qua concat.\n")

                return None



            import requests as _req

            url = "https://labs.google/fx/api/trpc/videoFx.runConcatenateVideos"

            headers = {

                "accept": "*/*",

                "content-type": "application/json",

                "user-agent": "Mozilla/5.0",

                "origin": "https://labs.google",

                "referer": "https://labs.google/fx/tools/flow",

            }

            cookies = {}

            # If full cookie header provided, pass via headers (simple support)

            headers["cookie"] = labs_cookie



            # Build inputs from media_ids, default 8s chunks

            inputs = []

            for i, mid in enumerate(media_ids):

                inputs.append({

                    "mediaGenerationId": mid,

                    "lengthNanos": 8000,

                    "startTimeOffset": "0.000000000s" if i == 0 else "1.000000000s",

                    "endTimeOffset": "8.000000000s"

                })



            payload = {"json": {"requestInput": {"inputVideos": inputs}}}

            self._log("[Extend] 🚀 Gửi concat request...\n")

            r = _req.post(url, headers=headers, json=payload, timeout=60)

            self._log(f"[Extend] 📥 Concat status: {r.status_code}\n")

            if r.status_code == 200:

                try:

                    js = r.json()

                    # Try extracting operation name if present

                    op = js.get("operation") if isinstance(js, dict) else None

                    if isinstance(op, dict):

                        inner = op.get("operation") or {}

                        name = inner.get("name") or op.get("name")

                        if isinstance(name, str) and name:

                            return name

                except Exception:

                    pass

                return ""  # submitted but no name

            return None

        except Exception as e:

            self._log(f"[Extend] ❌ Lỗi concat request: {e}\n")

            return None



    def _extend_poll_concat_status(self, client, operation_name: str, timeout_s: int = 300, poll_interval: int = 5) -> Optional[str]:

        """Poll concatenation status via aisandbox check endpoint; return outputUri when ready."""

        try:

            if not operation_name:

                return None

            url = "https://aisandbox-pa.googleapis.com/v1:runVideoFxCheckConcatenationStatus"

            headers = client._aisandbox_headers() if hasattr(client, '_aisandbox_headers') else {}

            payload = {"operation": {"operation": {"name": operation_name}}}

            deadline = _t.time() + max(30, timeout_s)

            while _t.time() < deadline and not (hasattr(self, 'extend_stop_event') and self.extend_stop_event.is_set()):

                resp = client.session.post(url, headers=headers, json=payload, timeout=30)

                if resp.status_code == 200:

                    js = resp.json()

                    status = str(js.get("status", "")).upper()

                    output = js.get("outputUri", "")

                    if output:

                        return output

                    if "FAILED" in status or "ERROR" in status:

                        self._log("[Extend] ❌ Concat FAILED\n")

                        return None

                else:

                    try:

                        self._log(f"[Extend] ⚠ Concat poll status: {resp.status_code}\n")

                    except Exception:

                        pass

                _t.sleep(poll_interval)

            return None

        except Exception as e:

            self._log(f"[Extend] ❌ Lỗi poll concat: {e}\n")

            return None



    def _jsonp_log(self, s: str) -> None:

        try:

            self.txt_jsonp_log.insert("end", s)

            self.txt_jsonp_log.see("end")

        except Exception:

            pass



    # ----- Super Sync Tab -----

    def _sync_log(self, s: str) -> None:

        def _do():

            try:

                self.txt_sync_result.insert("end", s)

                self.txt_sync_result.see("end")

            except Exception:

                pass

        try:

            # Ensure UI update happens on Tk main thread

            self.root.after(0, _do)

        except Exception:

            _do()

    

    def _sync_log_header(self, title: str) -> None:

        """Log header với format đẹp"""

        import time as _t

        timestamp = _t.strftime("%H:%M:%S")

        self._sync_log(f"\n{'='*60}\n")

        self._sync_log(f"🕐 {timestamp} | {title}\n")

        self._sync_log(f"{'='*60}\n")

    

    def _sync_log_step(self, step_num: int, total_steps: int, description: str, status: str = "") -> None:

        """Log từng bước với progress indicator"""

        progress = f"[{step_num}/{total_steps}]"

        if status:

            self._sync_log(f"📋 {progress} {description} | {status}\n")

        else:

            self._sync_log(f"📋 {progress} {description}\n")

    

    def _sync_log_success(self, message: str) -> None:

        """Log thành công"""

        self._sync_log(f"✅ {message}\n")

    

    def _sync_log_error(self, message: str) -> None:

        """Log lỗi"""

        self._sync_log(f"❌ {message}\n")

    

    def _sync_log_warning(self, message: str) -> None:

        """Log cảnh báo"""

        self._sync_log(f"⚠️ {message}\n")

    

    def _sync_log_info(self, message: str) -> None:

        """Log thông tin"""

        self._sync_log(f"ℹ️ {message}\n")

    

    def _sync_log_progress(self, current: int, total: int, description: str) -> None:

        """Log tiến trình với phần trăm"""

        percentage = int((current / total) * 100) if total > 0 else 0

        bar_length = 20

        filled_length = int(bar_length * current // total) if total > 0 else 0

        bar = "█" * filled_length + "░" * (bar_length - filled_length)

        self._sync_log(f"📊 {description} [{bar}] {percentage}% ({current}/{total})\n")

    

    def _add_sync_task_to_video_tree(self, task_name: str, scene_id: str, operation: str, status: str, detail: str = "") -> str:

        """Add task from Sync tab to Video tab task status tree"""

        try:

            # Generate unique iid for sync tasks

            iid = f"SYNC_{scene_id}_{operation}_{int(_t.time())}"

            

            # Add to video tree

            self.tree.insert("", "end", iid=iid, values=(

                task_name, scene_id, operation, status, detail, "Mở | Sao chép"

            ), tags=(self._status_tag(status),))

            

            # Initialize row controls

            self.row_controls[iid] = {"can_stop": False, "can_pause": False, "can_resume": False}

            

            self._sync_log(f"📊 Đã thêm task vào Video tab: {task_name}\n")

            return iid

        except Exception as e:

            self._sync_log(f"❌ Lỗi thêm task vào Video tab: {e}\n")

            return ""

    

    def _update_sync_task_status(self, iid: str, status: str, detail: str = "") -> None:

        """Update sync task status in video tree"""

        try:

            if iid and iid in self.tree.get_children(""):

                values = list(self.tree.item(iid, "values"))

                if len(values) >= 4:

                    values[3] = status

                    if detail and len(values) >= 5:

                        values[4] = detail

                    self.tree.item(iid, values=values, tags=(self._status_tag(status),))

                    

                    # Update row controls based on status

                    can_stop = status in ("Đang xử lý", "Đang đợi")

                    self.row_controls[iid] = {"can_stop": can_stop, "can_pause": False, "can_resume": False}

        except Exception as e:

            self._sync_log(f"❌ Lỗi cập nhật task status: {e}\n")

    

