    def _analyze_story_context(self, lines: List[str]) -> Dict[str, str]:

        """Analyze story context to extract setting, characters, and continuity elements"""

        try:

            full_text = " ".join(lines).lower()

            

            # Extract setting/location

            setting = "Unknown"

            if "thuyền" in full_text or "boat" in full_text or "ship" in full_text:

                setting = "On a boat/ship"

            elif "biển" in full_text or "sea" in full_text or "ocean" in full_text:

                setting = "At sea"

            elif "nhà" in full_text or "house" in full_text or "home" in full_text:

                setting = "At home"

            elif "vườn" in full_text or "garden" in full_text:

                setting = "In garden"

            elif "phố" in full_text or "street" in full_text or "city" in full_text:

                setting = "In city"

            elif "rừng" in full_text or "forest" in full_text:

                setting = "In forest"

            

            # Extract weather/conditions

            weather = "Normal"

            if "bão" in full_text or "storm" in full_text:

                weather = "Stormy"

            elif "mưa" in full_text or "rain" in full_text:

                weather = "Rainy"

            elif "nắng" in full_text or "sunny" in full_text:

                weather = "Sunny"

            elif "tối" in full_text or "dark" in full_text:

                weather = "Dark"

            

            # Extract emotional tone

            emotion = "Neutral"

            if "hoảng sợ" in full_text or "fear" in full_text or "scared" in full_text:

                emotion = "Fearful"

            elif "vui" in full_text or "happy" in full_text or "joy" in full_text:

                emotion = "Joyful"

            elif "buồn" in full_text or "sad" in full_text:

                emotion = "Sad"

            elif "tức giận" in full_text or "angry" in full_text:

                emotion = "Angry"

            

            return {

                "setting": setting,

                "weather": weather,

                "emotion": emotion,

                "total_scenes": len(lines),

                "story_type": "Continuous narrative"

            }

        except Exception as e:

            self._sync_log_error(f"Lỗi phân tích story context: {e}")

            return {"setting": "Unknown", "weather": "Normal", "emotion": "Neutral"}

    

    def _extract_character_ids_from_bible(self, character_bible_text: str) -> Dict[str, str]:

        """Extract character IDs and their details from Character Bible text"""

        character_data = {}

        try:

            import json as _json

            import re

            

            # Split by "Character Bible:" to get individual character entries

            entries = re.split(r'Character Bible:', character_bible_text)

            

            for entry in entries:

                if not entry.strip():

                    continue

                    

                # Clean up the entry

                entry = entry.strip()

                if entry.startswith('{'):

                    # Find the complete JSON object

                    brace_count = 0

                    json_end = 0

                    for i, char in enumerate(entry):

                        if char == '{':

                            brace_count += 1

                        elif char == '}':

                            brace_count -= 1

                            if brace_count == 0:

                                json_end = i + 1

                                break

                    

                    if json_end > 0:

                        json_str = entry[:json_end]

                        try:

                            char_data = _json.loads(json_str)

                            name_id = char_data.get("Name_ID", "")

                            gen_id = char_data.get("GEN_ID", "")

                            if name_id and gen_id:

                                character_data[gen_id] = json_str

                        except _json.JSONDecodeError:

                            continue

            

            return character_data

        except Exception as e:

            self._sync_log_error(f"Lỗi extract character IDs: {e}")

            return {}

    

    def _replace_character_ids_in_prompt(self, prompt: str, character_data: Dict[str, str]) -> str:

        """Replace CHARACTER_ID placeholders with actual character details"""

        try:

            import re

            

            # Find all CHARACTER_ID patterns in the prompt

            pattern = r'([A-Z_]+_ID)'

            matches = re.findall(pattern, prompt)

            

            for char_id in matches:

                if char_id in character_data:

                    # Replace with character name and key details

                    char_json = character_data[char_id]

                    import json as _json

                    char_data = _json.loads(char_json)

                    

                    # Extract key details for replacement

                    details = char_data.get("Details", {})

                    appearance = details.get("appearance", {})

                    

                    fur_color = appearance.get("fur_or_hair_color", "")

                    eye_color = appearance.get("eye_color", "")

                    body_shape = appearance.get("body_shape", "")

                    

                    # Create replacement text

                    replacement = f"{char_id} ({fur_color}, {eye_color}, {body_shape})"

                    prompt = prompt.replace(char_id, replacement)

            

            return prompt

        except Exception as e:

            self._sync_log_error(f"Lỗi replace character IDs: {e}")

            return prompt



