    def _on_sync_total_secs_changed(self) -> None:

        """Tự động cập nhật số video và phân cảnh khi thay đổi tổng thời gian"""

        try:

            total_secs = int(self.spn_sync_total_secs.get())

            # Tính số video VEO 3 (mỗi video 8 giây)

            num_videos = max(1, (total_secs + 7) // 8)  # Làm tròn lên

            # Số phân cảnh = số video (mỗi video là 1 phân cảnh)

            num_stages = num_videos



            # Cập nhật labels

            self.lbl_sync_num_videos.config(text=str(num_videos))

            self.lbl_sync_num_stages.config(text=str(num_stages))



            # Log thông tin

            self._sync_log(f"📊 Tổng thời gian: {total_secs}s → {num_videos} video VEO 3 (8s mỗi video)\n")

        except Exception:

            pass

    

    def _on_sync_script_changed_debounced(self) -> None:

        """Debounced version of script change handler"""

        try:

            # Cancel existing timer if any

            if self._script_change_timer:

                self.root.after_cancel(self._script_change_timer)

            

            # Set new timer to execute after 500ms delay

            self._script_change_timer = self.root.after(500, self._on_sync_script_changed)

        except Exception:

            pass

    

    def _on_sync_script_changed(self) -> None:

        """Tự động tính toán số giây dựa trên số dòng kịch bản"""

        try:

            # Đọc kịch bản và đếm số dòng

            script_text = self.txt_sync_script.get("1.0", "end").strip()

            lines = [line.strip() for line in script_text.splitlines() if line.strip()]

            num_lines = len(lines)

            

            if num_lines > 0:

                # Tính số giây: số dòng × 8 giây

                total_seconds = num_lines * 8

                

                # Cập nhật spinbox

                self.spn_sync_total_secs.delete(0, "end")

                self.spn_sync_total_secs.insert(0, str(total_seconds))

                

                # Gọi method cập nhật số video

                self._on_sync_total_secs_changed()

                

                # Log thông tin

                self._sync_log(f"📝 Tự động tính: {num_lines} dòng × 8s = {total_seconds}s\n")

            else:

                # Nếu không có dòng nào, reset về 40 giây

                self.spn_sync_total_secs.delete(0, "end")

                self.spn_sync_total_secs.insert(0, "40")

                self._on_sync_total_secs_changed()

                

        except Exception as e:

            # Nếu có lỗi, không làm gì để tránh crash

            pass

    

