    def on_sync_open_output_folder(self) -> None:

        """Open output folder in file explorer"""

        try:

            output_dir = Path(self.ent_sync_outdir.get().strip())

            if output_dir.exists():

                import subprocess

                import platform

                

                if platform.system() == "Windows":

                    subprocess.Popen(f'explorer "{output_dir}"')

                elif platform.system() == "Darwin":  # macOS

                    subprocess.Popen(["open", str(output_dir)])

                else:  # Linux

                    subprocess.Popen(["xdg-open", str(output_dir)])

                

                self._sync_log(f"📁 Đã mở thư mục: {output_dir}\n")

            else:

                self._sync_log("⚠️ Thư mục output không tồn tại\n")

        except Exception as e:

            self._sync_log(f"❌ Lỗi mở thư mục: {e}\n")

    

    def on_sync_play_video(self, event) -> None:

        """View selected character image"""

        try:

            selection = self.sync_character_tree.selection()

            if not selection:

                return

            

            item = self.sync_character_tree.item(selection[0])

            character_name = item['values'][0]

            

            # Open character image if available

            if character_name in self.character_images:

                image_path = self.character_images[character_name]

                if Path(image_path).exists():

                    import webbrowser

                    webbrowser.open(f"file://{image_path}")

                    self._sync_log(f"📖 Opened image for {character_name}\n")

                else:

                    self._sync_log(f"❌ Image file not found: {image_path}\n")

            else:

                self._sync_log(f"❌ No image available for {character_name}\n")

                

        except Exception as e:

            self._sync_log(f"❌ Lỗi view character image: {e}\n")

    

