    def on_sync_generate_prompts_new(self) -> None:

        """New process: Character → Scene/Shot → Image/Video"""

        # Validate inputs first (quick validation on main thread)

        project = "Project"  # Default project name

        # Auto-generate seed

        seed = self._generate_auto_seed()

