    def _clean_json_response(self, response: str) -> str:

        """Clean JSON response from Gemini"""

        try:

            import json as _json

            import re

            

            # Remove code fences if present

            response = re.sub(r'```json\s*', '', response)

            response = re.sub(r'```\s*$', '', response)

            

            # Find JSON object

            json_match = re.search(r'\{.*\}', response, re.DOTALL)

            if json_match:

                json_str = json_match.group()

                # Validate JSON

                _json.loads(json_str)

                return json_str

            

            return response.strip()

        except Exception as e:

            self._sync_log_error(f"Lỗi clean JSON: {e}")

            return response

    

    def _clean_video_response(self, response: str) -> str:

        """Clean video response from Gemini"""

        try:

            # Remove code fences if present

            import re

            response = re.sub(r'```\w*\s*', '', response)

            response = re.sub(r'```\s*$', '', response)

            

            return response.strip()

        except Exception as e:

            self._sync_log_error(f"Lỗi clean video response: {e}")

            return response

    

    def _validate_json(self, json_str: str) -> bool:

        """Validate JSON string"""

        try:

            import json as _json

            _json.loads(json_str)

            return True

        except:

            return False

    

    # ----- Project Management -----

    def _load_projects_combobox(self):

        """Load projects into combobox"""

        try:

            # Use get_all_projects directly to avoid get_project_list issues

            all_projects = self.project_manager.get_all_projects()

            self._log(f"📋 Found {len(all_projects)} projects in memory\n")

            

            # Convert to list format

            projects = []

            for project_id, data in all_projects.items():

                try:

                    projects.append({

                        "id": project_id,

                        "name": data.get("name", "Unknown"),

                        "description": data.get("description", ""),

                        "created_at": data.get("created_at", data.get("updated_at", "")),

                        "updated_at": data.get("updated_at", ""),

                        "stats": data.get("stats", {"total_videos": 0, "completed_videos": 0, "failed_videos": 0})

                    })

                except Exception as e:

                    self._log(f"❌ Error converting project {project_id}: {e}\n")

            

            # Sort by updated_at

            projects.sort(key=lambda x: x["updated_at"], reverse=True)

            

            project_names = [f"{p['name']} ({p['id'][:8]})" for p in projects]

            

            self.cmb_current_project['values'] = project_names

            self._log(f"📋 Loaded {len(project_names)} projects into combobox\n")

            

            # Auto-select first project if available

            if projects and not self.current_project_id:

                self.current_project_id = projects[0]['id']

                self.cmb_current_project.current(0)

                self._load_project_settings(self.current_project_id)

                self._log(f"🎯 Auto-selected first project: {projects[0]['name']}\n")

        except Exception as e:

            self._log(f"❌ Lỗi load projects combobox: {e}\n")

    

    def _open_project_manager(self):

        """Mở dialog quản lý project và refresh combobox sau khi đóng."""

        try:

            if ProjectDialog is None:

                self._log("⚠️ ProjectDialog không khả dụng (tkinter không có)\n")

                return

            

            dialog = ProjectDialog(self.root, self.project_manager, self._on_project_selected_from_dialog)

            # Wait until dialog window closed (ProjectDialog should be a Toplevel)

            try:

                # If dialog created a Toplevel, wait for it to close before refreshing

                if hasattr(dialog, "wait_window"):

                    dialog.wait_window()

            except Exception:

                pass



            # After dialog closes, always reload project list into combobox

            try:

                self._load_projects_combobox()

                # If nothing selected, and there are projects, select the last one

                projects = self.project_manager.get_project_list() or []

                self._log(f"🔄 Refresh combobox: Found {len(projects)} projects\n")

                if projects and not self.current_project_id:

                    self.current_project_id = projects[-1]["id"]

                    # find index in combobox values and set selection

                    for i, v in enumerate(self.cmb_current_project['values'] or []):

                        if projects[-1]["name"] in str(v):

                            try:

                                self.cmb_current_project.current(i)

                                self._log(f"✅ Auto-selected project: {projects[-1]['name']}\n")

                            except Exception:

                                pass

                            break

            except Exception as e:

                self._log(f"⚠️ Không thể refresh danh sách project: {e}\n")

        except Exception as e:

            Messagebox.show_error(f"Lỗi mở project manager: {e}")

    

    def _on_project_selected_from_dialog(self, project: dict):

        """Khi chọn project từ dialog"""

        try:

            self.current_project_id = project['id']

            self._load_project_settings(self.current_project_id)

            self._load_projects_combobox()

            

            # Update combobox selection

            projects = self.project_manager.get_project_list()

            for i, p in enumerate(projects):

                if p['id'] == self.current_project_id:

                    self.cmb_current_project.current(i)

                    break

        except Exception as e:

            Messagebox.show_error(f"Lỗi load project: {e}")

    

    def _on_project_selected(self, event):

        """Khi chọn project từ combobox"""

        try:

            selection = self.cmb_current_project.get()

            if selection:

                # Extract project ID from selection

                project_id = selection.split('(')[-1].rstrip(')')

                

                # Find project by ID

                projects = self.project_manager.get_project_list()

                for project in projects:

                    if project['id'].startswith(project_id):

                        self.current_project_id = project['id']

                        self._load_project_settings(self.current_project_id)

                        break

        except Exception as e:

            print(f"Lỗi chọn project: {e}")

    

    def _load_project_settings(self, project_id: str):

        """Load settings từ project"""

        try:

            project = self.project_manager.get_project(project_id)

            if not project:

                return

            

            settings = project.get('settings', {})

            

            # Load settings vào UI

            # Project name is now hardcoded to "Project"

            

            # Removed: cmb_sync_style UI element removed

            

            if hasattr(self, 'spn_sync_total_secs'):

                total_secs = settings.get('total_seconds', '40')

                self.spn_sync_total_secs.delete(0, 'end')

                self.spn_sync_total_secs.insert(0, total_secs)

            

            # Removed: ent_sync_seed UI element removed (auto-generated now)

            

            if hasattr(self, 'ent_sync_outdir'):

                outdir = settings.get('output_dir', '')

                self.ent_sync_outdir.delete(0, 'end')

                self.ent_sync_outdir.insert(0, outdir)

            

            # Load cookie nếu có

            cookie = project.get('cookie', '')

            if cookie and hasattr(self, 'ent_cookie'):

                self.ent_cookie.delete(0, 'end')

                self.ent_cookie.insert(0, cookie)

            

        except Exception as e:

            print(f"Lỗi load project settings: {e}")

    

    def _save_current_project_settings(self):

        """Save settings hiện tại vào project"""

        try:

            if not self.current_project_id:

                return

            

            settings = {}

            

            # Removed: cmb_sync_style UI element removed

            

            if hasattr(self, 'spn_sync_total_secs'):

                settings['total_seconds'] = self.spn_sync_total_secs.get()

            

            # Removed: ent_sync_seed UI element removed (auto-generated now)

            

            if hasattr(self, 'ent_sync_outdir'):

                settings['output_dir'] = self.ent_sync_outdir.get()

            

            # Save cookie

            cookie = ""

            if hasattr(self, 'ent_cookie'):

                cookie = self.ent_cookie.get()

            

            self.project_manager.update_project(

                self.current_project_id,

                cookie=cookie,

                settings=settings

            )

            

        except Exception as e:

            print(f"Lỗi save project settings: {e}")

    

    def _create_new_project_if_needed(self):

        """Tạo project mới nếu chưa có project nào"""

        try:

            projects = self.project_manager.get_project_list()

            if not projects:

                # Tạo project mặc định

                project_id = self.project_manager.create_project(

                    name="Default Project",

                    description="Project mặc định",

                    cookie=""

                )

                self.current_project_id = project_id

                self._load_projects_combobox()

        except Exception as e:

            print(f"Lỗi tạo project mặc định: {e}")

    

    def _process_video_tasks_parallel(self, total: int, img_files: List, vid_files: List, 

                                    sync_video_tasks: Dict, client,

                                    i2v_model: str, t2v_model: str, vid_aspect: str, 

                                    seed: int, subj_mgid: str, scene_mgid: str, style_mgid: str):

        """Process video tasks respecting user configuration from Video tab"""

        try:

            # Create tasks list

            tasks = []

            for idx in range(1, total + 1):

                img_file = img_files[(idx - 1) % max(1, len(img_files))] if img_files else None

                vid_file = vid_files[(idx - 1) % max(1, len(vid_files))] if vid_files else None

                

                if img_file and vid_file:

                    tasks.append({

                        'idx': idx,

                        'img_file': img_file,

                        'vid_file': vid_file,

                        'task_iid': sync_video_tasks.get(idx)

                    })

            

            if not tasks:

                self._jsonp_log("✗ Không có task nào để xử lý\n")

                return

            

            # Get user configuration from Video tab

            try:

                user_mode = self.cmb_mode.get().strip()

                user_concurrent_jobs = self._get_concurrent_jobs_value()

                self._jsonp_log(f"⚙️ Cấu hình người dùng: Chế độ={user_mode}, Số công việc đồng thời={user_concurrent_jobs}\n")

            except Exception as e:

                user_mode = "Tuần tự"

                user_concurrent_jobs = 2

                self._jsonp_log(f"⚠️ Không đọc được cấu hình, sử dụng mặc định: {user_mode}, {user_concurrent_jobs}\n")

            

            # Determine processing approach based on user config

            if user_mode == "Tuần tự":

                self._jsonp_log(f"🔄 Xử lý TUẦN TỰ {len(tasks)} video tasks (1 task tại một thời điểm)\n")

                self._process_video_tasks_sequential(tasks, i2v_model, t2v_model, vid_aspect, seed, subj_mgid, scene_mgid, style_mgid)

            else:

                # Parallel mode - respect user's concurrent jobs setting

                max_workers = min(user_concurrent_jobs, len(tasks))  # Respect user setting

                self._jsonp_log(f"🚀 Xử lý SONG SONG {len(tasks)} video tasks (max {max_workers} workers)\n")

                self._process_video_tasks_parallel_executor(tasks, max_workers, i2v_model, t2v_model, vid_aspect, seed, subj_mgid, scene_mgid, style_mgid)

            

        except Exception as e:

            self._jsonp_log(f"❌ Lỗi xử lý video tasks: {e}\n")

    

    def _process_video_tasks_sequential(self, tasks: List, i2v_model: str, t2v_model: str, 

                                      vid_aspect: str, seed: int, subj_mgid: str, 

                                      scene_mgid: str, style_mgid: str):

        """Process video tasks sequentially (one by one)"""

        try:

            completed = 0

            for task in tasks:

                self._jsonp_log(f"🔄 Xử lý task {task['idx']}/{len(tasks)} (tuần tự)...\n")

                result = self._process_single_video_task_with_client(

                    task['idx'], task['img_file'], task['vid_file'], task['task_iid'],

                    i2v_model, t2v_model, vid_aspect, 

                    seed, subj_mgid, scene_mgid, style_mgid

                )

                completed += 1

                if result:

                    self._jsonp_log(f"✅ Task {task['idx']} hoàn thành ({completed}/{len(tasks)})\n")

                else:

                    self._jsonp_log(f"❌ Task {task['idx']} thất bại ({completed}/{len(tasks)})\n")

            

            self._jsonp_log(f"🎉 Hoàn thành xử lý tuần tự {len(tasks)} video tasks\n")

        except Exception as e:

            self._jsonp_log(f"❌ Lỗi xử lý tuần tự: {e}\n")

    

    def _process_video_tasks_parallel_executor(self, tasks: List, max_workers: int,

                                             i2v_model: str, t2v_model: str, vid_aspect: str, 

                                             seed: int, subj_mgid: str, scene_mgid: str, style_mgid: str):

        """Process video tasks in parallel using ThreadPoolExecutor"""

        try:

            self._jsonp_log(f"⚠️ CHÚ Ý: Chỉ {max_workers} task sẽ chạy cùng lúc, các task khác sẽ đợi trong queue\n")

            

            # Use semaphore to ensure only max_workers tasks run concurrently

            import threading

            semaphore = threading.Semaphore(max_workers)

            

            def _process_task_with_semaphore(task_data):

                """Process task with semaphore control"""

                with semaphore:  # This ensures only max_workers tasks can run at once

                    return self._process_single_video_task_with_client(

                        task_data['idx'], task_data['img_file'], task_data['vid_file'], task_data['task_iid'],

                        i2v_model, t2v_model, vid_aspect, 

                        seed, subj_mgid, scene_mgid, style_mgid

                    )

            

            with ThreadPoolExecutor(max_workers=len(tasks)) as executor:  # Allow all tasks to be submitted

                # Submit all tasks

                future_to_task = {}

                self._jsonp_log(f"📋 Đang submit {len(tasks)} tasks vào ThreadPoolExecutor với semaphore control...\n")

                for i, task in enumerate(tasks, 1):

                    self._jsonp_log(f"📤 Submit task {task['idx']} ({i}/{len(tasks)})\n")

                    future = executor.submit(_process_task_with_semaphore, task)

                    future_to_task[future] = task

                self._jsonp_log(f"✅ Đã submit tất cả {len(tasks)} tasks. Semaphore sẽ chỉ cho phép {max_workers} task chạy cùng lúc.\n")

                

                # Process completed tasks

                completed = 0

                for future in as_completed(future_to_task):

                    task = future_to_task[future]

                    try:

                        result = future.result()

                        completed += 1

                        if result:

                            self._jsonp_log(f"✅ Task {task['idx']} hoàn thành ({completed}/{len(tasks)})\n")

                        else:

                            self._jsonp_log(f"❌ Task {task['idx']} thất bại ({completed}/{len(tasks)})\n")

                    except Exception as e:

                        completed += 1

                        self._jsonp_log(f"❌ Task {task['idx']} lỗi: {e} ({completed}/{len(tasks)})\n")

            

            self._jsonp_log(f"🎉 Hoàn thành xử lý song song {len(tasks)} video tasks\n")

        except Exception as e:

            self._jsonp_log(f"❌ Lỗi xử lý song song: {e}\n")

    

    def _process_single_video_task_with_client(self, idx: int, img_file, vid_file, task_iid: str,

                                             i2v_model: str, t2v_model: str,

                                             vid_aspect: str, seed: int, subj_mgid: str, 

                                             scene_mgid: str, style_mgid: str) -> bool:

        """Process a single video task with its own client instance"""

        try:

            self._jsonp_log(f"🎬 Task {idx}: Bắt đầu xử lý...\n")

            

            # Create a new client instance for this task to avoid conflicts

            cookies = self._get_cookies_source()

            if not cookies:

                self._jsonp_log(f"✗ Task {idx}: Không có cookies hợp lệ\n")

                return False

            

            self._jsonp_log(f"🔑 Task {idx}: Đang tạo client...\n")

            from complete_flow import LabsFlowClient, _parse_cookie_string

            task_client = LabsFlowClient(_parse_cookie_string(cookies))

            

            self._jsonp_log(f"🔑 Task {idx}: Đang lấy access token...\n")

            if not task_client.fetch_access_token():

                self._jsonp_log(f"✗ Task {idx}: Không lấy được access token\n")

                return False

            

            self._jsonp_log(f"✅ Task {idx}: Client sẵn sàng, bắt đầu xử lý...\n")

            

            # Process the task with the new client

            return self._process_single_video_task(

                idx, img_file, vid_file, task_iid,

                task_client, i2v_model, t2v_model,

                vid_aspect, seed, subj_mgid, scene_mgid, style_mgid

            )

        except Exception as e:

            self._jsonp_log(f"✗ Task {idx}: Lỗi tạo client: {e}\n")

            return False



    def _process_single_video_task(self, idx: int, img_file, vid_file, task_iid: str,

                                 client, i2v_model: str, t2v_model: str,

                                 vid_aspect: str, seed: int, subj_mgid: str, 

                                 scene_mgid: str, style_mgid: str) -> bool:

        """Process a single video task"""

        try:

            # Read JSON files

            try:

                img_prompt = img_file.read_text(encoding="utf-8").strip()

                vid_prompt = vid_file.read_text(encoding="utf-8").strip()

                self._jsonp_log(f"→ Dòng {idx}: {img_file.name} ↔ {vid_file.name}\n")

            except Exception as e:

                self._jsonp_log(f"✗ Dòng {idx}: Lỗi đọc file JSON: {e}\n")

                return False

            

            # 1) Generate image

            try:

                if task_iid:

                    self._update_sync_video_task(task_iid, "Đang xử lý", "Đang tạo ảnh...")

                

                # Create new workflow for each task

                task_workflow_id = client.create_whisk_workflow()

                if not task_workflow_id:

                    self._jsonp_log(f"✗ Dòng {idx}: Không tạo được workflow cho ảnh\n")

                    return False

                

                # Generate image with whisk if available

                if hasattr(client, 'generate_image_whisk') and callable(getattr(client, 'generate_image_whisk')):

                    img_res = client.generate_image_whisk(

                        workflow_id=task_workflow_id,

                        prompt=img_prompt,

                        model_key="IMAGEN_3_5",

                        aspect_ratio=self._image_aspect_map.get(self.cmb_jsonp_img_aspect.get().strip(), "IMAGE_ASPECT_RATIO_LANDSCAPE"),

                        subject_mgid=subj_mgid,

                        scene_mgid=scene_mgid,

                        style_mgid=style_mgid,

                        seed=seed,

                    )

                else:

                    # Fallback to simple generate

                    img_res = client.generate_image_from_text(

                        workflow_id=task_workflow_id,

                        prompt=img_prompt,

                        image_model="R2I",

                        aspect_ratio=self._image_aspect_map.get(self.cmb_jsonp_img_aspect.get().strip(), "IMAGE_ASPECT_RATIO_LANDSCAPE"),

                        seed=seed if seed is not None else None

                    )

                

                if not img_res:

                    self._jsonp_log(f"✗ Dòng {idx}: Lỗi tạo ảnh\n")

                    return False

            except Exception as e:

                self._jsonp_log(f"✗ Dòng {idx}: Lỗi tạo ảnh: {e}\n")

                if task_iid:

                    self._update_sync_video_task(task_iid, "Lỗi", f"Lỗi tạo ảnh: {e}")

                return False

            

            # 2) Get media ID from image

            urls = _extract_file_urls(img_res)

            media_id = None

            if not urls:

                self._jsonp_log(f"⚠ Dòng {idx}: Không thấy URL ảnh ngay\n")

            else:

                self._jsonp_log(f"✓ Dòng {idx}: Ảnh đã tạo: {urls[0]}\n")

            

            try:

                mgids = _extract_strings_recursive(img_res, ("mediaId", "mediaGenerationId"))

                if mgids:

                    media_id = mgids[0]

            except Exception:

                pass

            

            if not media_id:

                self._jsonp_log(f"✗ Dòng {idx}: Không lấy được mediaId của ảnh\n")

                return False

            

            # 3) Generate video from image

            try:

                if task_iid:

                    self._update_sync_video_task(task_iid, "Đang xử lý", "Đang tạo video từ ảnh...")

                

                ops = client.generate_videos_from_image(

                    project_id=str(__import__('uuid').uuid4()),

                    tool="PINHOLE",

                    user_tier="PAYGATE_TIER_TWO",

                    prompt=vid_prompt,

                    media_id=media_id,

                    model_key=i2v_model,

                    num_videos=1,

                    aspect_ratio=vid_aspect,

                    fixed_seed=seed,

                    crop_coordinates=None,

                )

                

                if not ops:

                    self._jsonp_log(f"✗ Dòng {idx}: Tạo video thất bại (I2V). Thử fallback T2V...\n")

                    if task_iid:

                        self._update_sync_video_task(task_iid, "Đang xử lý", "Fallback T2V...")

                    

                    # Fallback to T2V

                    ops = client.generate_videos(

                        project_id=str(__import__('uuid').uuid4()),

                        tool="PINHOLE",

                        user_tier="PAYGATE_TIER_TWO",

                        prompt=vid_prompt,

                        model_key=t2v_model,

                        num_videos=1,

                        aspect_ratio=vid_aspect,

                        fixed_seed=seed,

                    )

                    

                    if not ops:

                        self._jsonp_log(f"✗ Dòng {idx}: Tạo video thất bại (T2V)\n")

                        return False

            except Exception as e:

                self._jsonp_log(f"✗ Dòng {idx}: Lỗi tạo video: {e}\n")

                if task_iid:

                    self._update_sync_video_task(task_iid, "Lỗi", f"Lỗi tạo video: {e}")

                return False

            

            # 4) Poll and enqueue downloads

            try:

                if task_iid:

                    self._update_sync_video_task(task_iid, "Đang xử lý", "Đang đợi video hoàn thành...")

                

                # Use Video tab settings for timeout and poll interval (same as Text-to-Video)

                max_wait = int(self.spn_max_wait.get()) if hasattr(self, 'spn_max_wait') else 300

                poll_interval = int(self.spn_poll.get()) if hasattr(self, 'spn_poll') else 10

                self._jsonp_log(f"🔍 Using Video tab settings: max_wait={max_wait}s, poll_interval={poll_interval}s\n")

                self._jsonp_log(f"⏱️ Starting polling for line {idx}, will timeout after {max_wait}s...\n")

                

                import time

                start_time = time.time()

                status = client.poll_until_complete(ops, max_wait_seconds=max_wait, poll_interval=poll_interval)

                elapsed_time = time.time() - start_time

                self._jsonp_log(f"⏱️ Polling completed for line {idx} after {elapsed_time:.1f}s\n")

                

                # Enhanced Debug: Log response structure for troubleshooting

                self._jsonp_log(f"🔍 Debug response structure for line {idx}: {type(status)}\n")

                if isinstance(status, dict):

                    self._jsonp_log(f"🔍 Response keys: {list(status.keys())}\n")

                    

                    # Check for common response patterns and operation status

                    if "operations" in status:

                        ops = status["operations"]

                        if isinstance(ops, list):

                            self._jsonp_log(f"🔍 Found {len(ops)} operations\n")

                            failed_ops = []

                            success_ops = []

                            for i, op in enumerate(ops):

                                if isinstance(op, dict):

                                    op_status = op.get("status", "unknown")

                                    self._jsonp_log(f"🔍 Operation {i}: status={op_status}, keys={list(op.keys())}\n")

                                    

                                    # Check for errors

                                    if "operation" in op and "error" in op["operation"]:

                                        error = op["operation"]["error"]

                                        error_msg = error.get("message", "Unknown error")

                                        self._jsonp_log(f"❌ Operation {i} failed: {error_msg}\n")

                                        

                                        # Check if it's a timeout error (can potentially retry)

                                        if "TIMED_OUT" in error_msg:

                                            failed_ops.append(f"Op{i}: TIMEOUT")

                                        else:

                                            failed_ops.append(f"Op{i}: {error_msg}")

                                    elif "FAILED" in op_status.upper():

                                        failed_ops.append(f"Op{i}: {op_status}")

                                    elif "COMPLETE" in op_status.upper() or "SUCCESS" in op_status.upper():

                                        success_ops.append(f"Op{i}: {op_status}")

                            

                            # Log summary

                            if failed_ops:

                                self._jsonp_log(f"❌ Failed operations: {failed_ops}\n")

                            if success_ops:

                                self._jsonp_log(f"✅ Successful operations: {success_ops}\n")

                            

                            # Check if operations are still active (not completed yet)

                            active_ops = []

                            for i, op in enumerate(ops):

                                if isinstance(op, dict):

                                    op_status = op.get("status", "unknown")

                                    if "ACTIVE" in op_status.upper() or "PENDING" in op_status.upper():

                                        active_ops.append(f"Op{i}: {op_status}")

                            

                            if active_ops:

                                self._jsonp_log(f"⏳ Operations still active (may have timed out): {active_ops}\n")

                                if task_iid:

                                    self._update_sync_video_task(task_iid, "Timeout", f"Video generation timed out, operations still active: {'; '.join(active_ops)}")

                                return False

                            

                            # If all operations failed, don't try to extract URLs

                            if failed_ops and not success_ops:

                                self._jsonp_log(f"❌ All operations failed, skipping URL extraction\n")

                                

                                # Check if failures are due to timeout (VEO 3 overload)

                                timeout_count = sum(1 for op in failed_ops if "TIMEOUT" in op)

                                if timeout_count > 0:

                                    self._jsonp_log(f"⚠️ {timeout_count} operations timed out - VEO 3 may be overloaded\n")

                                    self._jsonp_log(f"💡 Suggestion: Reduce concurrent jobs in Video tab to 1-2 to avoid VEO 3 timeout\n")

                                

                                if task_iid:

                                    error_summary = "; ".join(failed_ops)

                                    if timeout_count > 0:

                                        self._update_sync_video_task(task_iid, "VEO3 Timeout", f"VEO 3 timeout (overloaded): {error_summary}")

                                    else:

                                        self._update_sync_video_task(task_iid, "Lỗi", f"Video generation failed: {error_summary}")

                                return False

                    

                    if "videos" in status:

                        videos = status["videos"]

                        self._jsonp_log(f"🔍 Found 'videos' key with {len(videos) if isinstance(videos, list) else 'non-list'} items\n")

                    

                    # Log a sample of the response (first 1000 chars for better visibility)

                    import json

                    try:

                        response_sample = json.dumps(status, indent=2)[:1000]

                        self._jsonp_log(f"🔍 Response sample (1000 chars): {response_sample}...\n")

                    except:

                        self._jsonp_log(f"🔍 Response sample: {str(status)[:1000]}...\n")

                else:

                    self._jsonp_log(f"🔍 Response is not a dict: {str(status)[:500]}...\n")

                

                urls = _extract_file_urls(status)

                self._jsonp_log(f"🔍 Extracted URLs count: {len(urls)}\n")

                

                # Fallback: Try alternative extraction methods if no URLs found

                if not urls:

                    self._jsonp_log("🔍 No URLs found with standard extraction, trying alternatives...\n")

                    

                    # Method 1: Look for 'videos' array like in text-to-video

                    if isinstance(status, dict) and "videos" in status:

                        videos = status["videos"]

                        if isinstance(videos, list) and videos:

                            for video in videos:

                                if isinstance(video, dict):

                                    video_url = video.get("fileUrl") or video.get("fifeUrl") or video.get("url")

                                    if video_url:

                                        urls.append(video_url)

                                        self._jsonp_log(f"🔍 Found video URL in 'videos' array: {video_url}\n")

                    

                    # Method 2: Look for operations array with completed status

                    if isinstance(status, dict) and "operations" in status:

                        operations = status["operations"]

                        if isinstance(operations, list):

                            for op in operations:

                                if isinstance(op, dict):

                                    op_status = str(op.get("status", "")).upper()

                                    if "COMPLETE" in op_status or "SUCCESS" in op_status:

                                        video_url = op.get("videoUrl") or op.get("fileUrl") or op.get("url")

                                        if video_url:

                                            urls.append(video_url)

                                            self._jsonp_log(f"🔍 Found video URL in completed operation: {video_url}\n")

                    

                    # Method 3: Deep search for any HTTP URLs ending with video extensions

                    if not urls:

                        def find_video_urls_deep(obj, path=""):

                            found = []

                            if isinstance(obj, dict):

                                for k, v in obj.items():

                                    new_path = f"{path}.{k}" if path else k

                                    if isinstance(v, str) and v.startswith("http") and any(ext in v.lower() for ext in [".mp4", ".mov", ".avi", ".webm"]):

                                        found.append(v)

                                        self._jsonp_log(f"🔍 Deep search found URL at {new_path}: {v}\n")

                                    elif isinstance(v, (dict, list)):

                                        found.extend(find_video_urls_deep(v, new_path))

                            elif isinstance(obj, list):

                                for i, item in enumerate(obj):

                                    new_path = f"{path}[{i}]" if path else f"[{i}]"

                                    found.extend(find_video_urls_deep(item, new_path))

                            return found

                        

                        deep_urls = find_video_urls_deep(status)

                        urls.extend(deep_urls)

                

                if urls:

                    self._jsonp_log(f"✓ Dòng {idx}: Video hoàn tất: {urls[0]}\n")

                    

                    if task_iid:

                        self._update_sync_video_task(task_iid, "Hoàn thành", f"Video đã tạo: {urls[0]}")

                    

                    # Use Video tab's download logic directly - no custom logic needed

                    try:

                        # Create a PromptTask object for compatibility with Video tab download method

                        from dataclasses import dataclass

                        @dataclass

                        class SyncPromptTask:

                            prompt_text: str

                            prompt_index: int

                            output_folder: str = ""

                        

                        sync_task = SyncPromptTask(

                            prompt_text=vid_prompt[:50] + "..." if len(vid_prompt) > 50 else vid_prompt,

                            prompt_index=idx,

                            output_folder=f"sync_video_{idx:03d}"

                        )

                        

                        # Use Video tab's download method with all its configurations

                        self._enqueue_downloads_from_status(sync_task, status)

                        

                    except Exception as e:

                        self._jsonp_log(f"⚠️ Không thể xếp hàng tải (Video tab method): {e}\n")

                    

                    return True

                else:

                    self._jsonp_log(f"✗ Dòng {idx}: Không lấy được URL video\n")

                    

                    # Enhanced debugging: Save full response to file for analysis

                    try:

                        import json

                        debug_file = Path(self.ent_sync_outdir.get().strip()) / f"debug_response_line_{idx:02d}.json"

                        with open(debug_file, 'w', encoding='utf-8') as f:

                            json.dump(status, f, indent=2, ensure_ascii=False)

                        self._jsonp_log(f"🔍 Full response saved to: {debug_file}\n")

                    except Exception as debug_e:

                        self._jsonp_log(f"⚠️ Could not save debug response: {debug_e}\n")

                    

                    # Try manual URL search in the response

                    self._jsonp_log("🔍 Attempting manual URL search...\n")

                    manual_urls = self._manual_url_search(status)

                    if manual_urls:

                        self._jsonp_log(f"🔍 Manual search found {len(manual_urls)} URLs: {manual_urls}\n")

                        # Use the manually found URLs

                        urls = manual_urls

                        # Continue with download logic using Video tab method

                        self._jsonp_log(f"✓ Dòng {idx}: Video hoàn tất (manual): {urls[0]}\n")

                        

                        if task_iid:

                            self._update_sync_video_task(task_iid, "Hoàn thành", f"Video đã tạo: {urls[0]}")

                        

                        # Use Video tab's download logic directly

                        try:

                            from dataclasses import dataclass

                            @dataclass

                            class SyncPromptTask:

                                prompt_text: str

                                prompt_index: int

                                output_folder: str = ""

                            

                            sync_task = SyncPromptTask(

                                prompt_text=vid_prompt[:50] + "..." if len(vid_prompt) > 50 else vid_prompt,

                                prompt_index=idx,

                                output_folder=f"sync_video_{idx:03d}"

                            )

                            

                            # Use Video tab's download method with all its configurations

                            self._enqueue_downloads_from_status(sync_task, status)

                            

                        except Exception as e:

                            self._jsonp_log(f"⚠️ Không thể xếp hàng tải (manual, Video tab method): {e}\n")

                        

                        return True

                    else:

                        self._jsonp_log("🔍 Manual search also failed to find URLs\n")

                    

                    if task_iid:

                        self._update_sync_video_task(task_iid, "Lỗi", "Không lấy được URL video")

                    return False

                    

            except Exception as e:

                self._jsonp_log(f"✗ Dòng {idx}: Lỗi poll video: {e}\n")

                if task_iid:

                    self._update_sync_video_task(task_iid, "Lỗi", f"Lỗi poll video: {e}")

                return False

                

        except Exception as e:

            self._jsonp_log(f"✗ Dòng {idx}: Lỗi tổng quát: {e}\n")

            if task_iid:

                self._update_sync_video_task(task_iid, "Lỗi", f"Lỗi: {e}")

            return False



    def _manual_url_search(self, response_data: Any) -> List[str]:

        """Manual URL search with comprehensive patterns"""

        urls = []

        

        def search_recursive(obj, path=""):

            if isinstance(obj, dict):

                for key, value in obj.items():

                    current_path = f"{path}.{key}" if path else key

                    

                    # Check if this key might contain a URL

                    if isinstance(value, str) and value.startswith("http"):

                        # Check for video file patterns

                        if any(pattern in value.lower() for pattern in [

                            ".mp4", ".mov", ".avi", ".webm", ".m4v",

                            "video", "media", "file", "download",

                            "googleapis.com", "googleusercontent.com", "storage.cloud.google.com"

                        ]):

                            urls.append(value)

                            self._jsonp_log(f"🔍 Manual search found URL at {current_path}: {value[:100]}...\n")

                    

                    # Recurse into nested structures

                    elif isinstance(value, (dict, list)):

                        search_recursive(value, current_path)

                        

            elif isinstance(obj, list):

                for i, item in enumerate(obj):

                    current_path = f"{path}[{i}]" if path else f"[{i}]"

                    search_recursive(item, current_path)

        

        try:

            search_recursive(response_data)

            

            # Additional specific searches based on known API response patterns

            if isinstance(response_data, dict):

                # Pattern 1: Look for 'results' or 'data' arrays

                for results_key in ['results', 'data', 'items', 'content', 'outputs']:

                    if results_key in response_data:

                        search_recursive(response_data[results_key], results_key)

                

                # Pattern 2: Look for status-based structures

                if 'status' in response_data:

                    status_obj = response_data['status']

                    if isinstance(status_obj, dict):

                        # Look for completed items

                        for key, value in status_obj.items():

                            if isinstance(value, list):

                                for item in value:

                                    if isinstance(item, dict) and item.get('status') in ['COMPLETE', 'SUCCESS', 'DONE']:

                                        search_recursive(item, f"status.{key}")

                

                # Pattern 3: Look for operation-based structures

                if 'operations' in response_data:

                    operations = response_data['operations']

                    if isinstance(operations, list):

                        for i, op in enumerate(operations):

                            if isinstance(op, dict):

                                op_status = str(op.get('status', '')).upper()

                                if any(status in op_status for status in ['COMPLETE', 'SUCCESS', 'DONE', 'FINISHED']):

                                    search_recursive(op, f"operations[{i}]")

            

        except Exception as e:

            self._jsonp_log(f"⚠️ Error in manual URL search: {e}\n")

        

        # Remove duplicates

        unique_urls = list(dict.fromkeys(urls))  # Preserves order

        return unique_urls



    def on_sync_generate_prompts(self) -> None:

        self._sync_log_header("🤖 TẠO JSON PROMPTS VỚI GEMINI")

        

        # Step 1: Khởi tạo

        self._sync_log_step(1, 6, "Khởi tạo", "Đang thiết lập...")

        project = "Project"  # Default project name

        # Auto-generate seed

        seed = self._generate_auto_seed()

        seed_int = seed

        

        self._sync_log_info(f"Dự án: {project}")

        self._sync_log_info(f"Seed: {seed}")

        self._sync_log_success("Đã khởi tạo thành công")

        

        # Step 2: Skip style config check (removed style UI)

        self._sync_log_step(2, 6, "Bỏ qua style config", "Style UI đã được loại bỏ")

        style_config = {}  # Empty config, not used anymore

        self._sync_log_success("Đã bỏ qua style config check")

        # Step 3: Phân tích kịch bản

