    def _clear_old_workflow_data(self) -> None:

        """🚨 TRIỆT ĐỂ XÓA TOÀN BỘ: KỊCH BẢN + PROMPT + NHÂN VẬT CACHE"""

        try:

            import shutil

            import time

            import hashlib

            

            self._sync_log_info("🧹 Đang XÓA TRIỆT ĐỂ TOÀN BỘ cache...")

            

            # 1. 💾 CLEAR IN-MEMORY DATA - Tất cả biến cache

            self.character_images = {}

            self.extracted_characters = []

            

            if hasattr(self, 'sync_video_media_ids'):

                self.sync_video_media_ids = []

            

            # Clear script hash để force fresh detection

            if hasattr(self, '_last_script_hash'):

                delattr(self, '_last_script_hash')

                self._sync_log_info("🗑️ Reset script hash tracker")

            

            # 2. 📋 CLEAR UI CACHE FIELDS - CHỈ xóa cache fields, KHÔNG xóa script user vừa nhập

            ui_fields_to_clear = [

                ('txt_veo3_topic', 'Veo3 Topic'),  # Clear topic để force đọc từ script

                # KHÔNG xóa txt_sync_script - user vừa copy vào đấy!

                # KHÔNG xóa spn_sync_total_secs - sẽ tự update theo script

                # Removed: spn_veo3_num_prompts UI element removed

            ]

            

            for field_name, field_desc in ui_fields_to_clear:

                try:

                    if hasattr(self, field_name):

                        field = getattr(self, field_name)

                        if hasattr(field, 'delete'):

                            field.delete("1.0" if "txt" in field_name else 0, "end")

                            self._sync_log_info(f"🗑️ Cleared {field_desc}")

                except Exception as e:

                    self._sync_log_warning(f"⚠️ Lỗi clear {field_desc}: {e}")

            

            # 3. 🗂️ XÓA TRIỆT ĐỂ TẤT CẢ THỨ MỤC CACHE

            locations_to_clear = [

                Path(self.ent_sync_outdir.get().strip()),  # Output directory  

                Path.cwd(),  # Project root

                Path.cwd() / "dist",  # Dist folder if exists

            ]

            

            folders_to_delete = [

                "json_prompt_outputs",    # CRITICAL: Chứa character images + prompts

                "image_json",             # Image prompts  

                "video_json",             # Video prompts - CHÍNH CÁI NÀY CACHE NHÂN VẬT

                "integrate_videos",       # Generated videos

                "downloaded_images",      # Downloaded images

                "downloaded_videos",      # Downloaded videos

                "images",                 # Images cache

                "videos",                 # Videos cache

                "characters",             # Character data

                "character_images"        # Character images

            ]

            

            deleted_count = 0

            for location in locations_to_clear:

                if not location.exists():

                    continue

                    

                for folder_name in folders_to_delete:

                    folder_path = location / folder_name

                    if folder_path.exists():

                        try:

                            self._sync_log_info(f"🗑️ XÓA TRIỆT ĐỂ: {location.name}/{folder_name}")

                            shutil.rmtree(folder_path, ignore_errors=False)

                            deleted_count += 1

                            time.sleep(0.1)  # Ensure complete deletion

                        except Exception as e:

                            self._sync_log_warning(f"⚠️ Lỗi xóa {folder_path}: {e}")

                            # Force delete với system command

                            try:

                                import subprocess

                                if folder_path.exists():

                                    subprocess.run(['rmdir', '/s', '/q', str(folder_path)], shell=True, check=False)

                            except:

                                pass

            

            # 4. 📄 XÓA CÁC FILE RỜI RẠC CÓ THỂ CHỨA CHARACTER CACHE

            file_patterns = [

                "line_*.json",      # Video prompts - CHỨA CHARACTER NAMES

                "scene_*.json",     # Scene files

                "char_*.json",      # Character files  

                "*.mp4", "*.avi",   # Video files

                "*.jpg", "*.png", "*.jpeg",  # Image files

                "*.txt"             # Text caches

            ]

            

            for location in locations_to_clear:

                for pattern in file_patterns:

                    try:

                        for file_path in location.glob(pattern):

                            if file_path.is_file():

                                file_path.unlink(missing_ok=True)

                                self._sync_log_info(f"🗑️ Xóa file cache: {file_path.name}")

                    except Exception:

                        pass

            

            # 5. 🏗️ TẠO LẠI CẤU TRÚC THƯ MỤC SẠCH

            essential_dirs = [

                Path(self.ent_sync_outdir.get().strip()) / "image_json",

                Path(self.ent_sync_outdir.get().strip()) / "video_json", 

                Path(self.ent_sync_outdir.get().strip()) / "json_prompt_outputs" / "character_images",

                Path(self.ent_sync_outdir.get().strip()) / "json_prompt_outputs" / "image_json",

                Path(self.ent_sync_outdir.get().strip()) / "json_prompt_outputs" / "video_json",

                Path.cwd() / "image_json",

                Path.cwd() / "video_json", 

                Path.cwd() / "json_prompt_outputs" / "character_images"

            ]

            

            for dir_path in essential_dirs:

                dir_path.mkdir(parents=True, exist_ok=True)

            

            # 6. 🔄 RESET UI COMPONENTS

            try:

                self.root.after(0, self._update_character_tree)  # Clear character tree

                self.root.after(0, self._refresh_sync_video_tree)  # Clear video tree if exists

            except Exception:

                pass

            

            self._sync_log_success(f"✅ ĐÃ XÓA TRIỆT ĐỂ {deleted_count} thư mục CACHE!")

            self._sync_log_success("🚨 KỊCH BẢN + PROMPT + NHÂN VẬT cache đã được loại bỏ hoàn toàn!")

            self._sync_log_success("🔄 Hệ thống đã sẵn sàng cho dữ liệu hoàn toàn mới!")

            

        except Exception as e:

            self._sync_log_error(f"❌ Lỗi clear triệt để: {e}")

            import traceback

            self._sync_log_error(f"Chi tiết: {traceback.format_exc()}")

    

    def _smart_character_matching(self, prompt_text: str, scene_id: str) -> List[str]:

        """UNIVERSAL character matching - bao quát mọi loại kịch bản"""

        try:

            if not self.extracted_characters:

                return []

            

            # Character relevance scoring system

            char_relevance = {}

            prompt_lower = prompt_text.lower()

            

            # Score each character based on relevance to this prompt

            for char in self.extracted_characters:

                char_name = char.get("name", "").strip()

                if not char_name:

                    continue

                    

                score = 0

                

                # 1. DIRECT NAME MATCHING (highest priority)

                char_name_lower = char_name.lower()

                if char_name_lower in prompt_lower:

                    score += 100  # Full name match

                

                # 2. WORD-BY-WORD MATCHING

                char_words = char_name_lower.split()

                for word in char_words:

                    if len(word) > 2:  # Skip short words like "Mr", "Ms"

                        if word in prompt_lower:

                            score += 50  # Each word match

                

                # 3. ALIASES MATCHING (if provided by Gemini extraction)

                aliases = char.get("aliases", [])

                if isinstance(aliases, list):

                    for alias in aliases:

                        if isinstance(alias, str) and alias.lower().strip() in prompt_lower:

                            score += 30

                

                # 4. DESCRIPTION KEYWORD MATCHING

                desc = char.get("description", "").lower()

                if desc:

                    # Common descriptive keywords

                    desc_words = desc.split()

                    for word in desc_words:

                        if len(word) > 3 and word in prompt_lower:

                            score += 10

                

                # 5. ROLE-BASED BONUS (main characters more likely to appear)

                role = char.get("role", "supporting").lower()

                if role == "main":

                    score += 15

                elif role == "supporting":

                    score += 5

                

                # Store score if character has any relevance

                if score > 0:

                    char_relevance[char_name] = score

            

            # Select top 3 most relevant characters

            if char_relevance:

                # Sort by score (descending) and take top 3

                sorted_chars = sorted(char_relevance.items(), key=lambda x: x[1], reverse=True)

                top_chars = [name for name, score in sorted_chars[:3]]  # STRICT limit: 3

                

                # Debug log with scores

                score_debug = ", ".join([f"{name}({score})" for name, score in sorted_chars[:3]])

                self._sync_log_info(f"  🎭 {scene_id}: {score_debug}")

                

                return top_chars

            else:

                # NO DIRECT MATCHES - intelligent fallback

                # Distribute characters evenly across scenes for variety

                if self.extracted_characters:

                    # Extract scene number for rotation

                    try:

                        scene_num = int(scene_id.split('_')[-1]) if '_' in scene_id else 1

                    except:

                        scene_num = 1

                    

                    # Rotate starting character based on scene number

                    start_idx = (scene_num - 1) % len(self.extracted_characters)

                    

                    result = []

                    for i in range(min(3, len(self.extracted_characters))):  # Max 3 or available count

                        idx = (start_idx + i) % len(self.extracted_characters)

                        char_name = self.extracted_characters[idx].get("name", "")

                        if char_name:

                            result.append(char_name)

                    

                    self._sync_log_info(f"  🔄 {scene_id} fallback rotation: {', '.join(result)}")

                    return result

                

                return []  # No characters available

            

        except Exception as e:

            self._sync_log_warning(f"⚠️ Lỗi universal matching {scene_id}: {e}")

            # Safe emergency fallback

            try:

                emergency = [char.get("name", "") for char in self.extracted_characters[:3] if char.get("name", "")]

                return emergency[:3]  # Even emergency respects 3-limit

            except:

                return []





    def _get_api_keys(self) -> List[str]:

        """Get API keys from profile or use default"""

        api_key_entry = getattr(self, "ent_profile_gemini_key", None)

        raw_keys = ""

        if api_key_entry and hasattr(api_key_entry, "get"):

            raw_keys = api_key_entry.get().strip()

        

        keys = []

        if raw_keys:

            for part in raw_keys.split("\n"):

                k = part.strip()

                if k:

                    keys.append(k)

        

        if not keys:

            keys = list(DEFAULT_GEMINI_KEYS)

            self._sync_log_info("Sử dụng API keys mặc định")

        else:

            self._sync_log_info(f"Sử dụng {len(keys)} API keys từ Profiles")

            

        return keys



    # ----- Smart Character Video Workflow -----  

    def on_sync_smart_character_video(self) -> None:

        """Smart Character Video workflow: Extract Characters → Generate Character Images → Create Videos with Integrate"""

        try:

            self._sync_log_header("🎭 BẮT ĐẦU SMART CHARACTER VIDEO WORKFLOW")

            

            # Step 1: Validate inputs

            lines = self._sync_parse_script_lines()

            if not lines:

                self._sync_log_error("Vui lòng nhập kịch bản trước khi bắt đầu!")

                return

                

            # Step 2: Check if we have video JSON prompts (from Veo3 generation)

            outdir = Path(self.ent_sync_outdir.get().strip())

            vid_dir = outdir / "video_json"

            

            if not vid_dir.exists() or not any(vid_dir.glob("line_*.json")):

                self._sync_log_warning("Chưa có video JSON prompts!")

                self._sync_log_info("Hãy chạy 'Gen Veo3 Prompts' trước để tạo video prompts.")

                return

            

            # Step 3: Extract characters from script

            self._sync_log_step(1, 4, "Extract Characters", "Đang phân tích nhân vật...")

            characters = self._extract_characters_from_script(lines)

            

            if not characters:

                self._sync_log_error("Không tìm thấy nhân vật nào trong kịch bản!")

                return

                

            self.extracted_characters = characters

            self._update_character_tree()

            self._sync_log_success(f"Đã tìm thấy {len(characters)} nhân vật")

            

            # Step 4: Generate character images

            self._sync_log_step(2, 4, "Generate Character Images", "Đang tạo ảnh nhân vật...")

            self._generate_character_images_background()

            

        except Exception as e:

            self._sync_log_error(f"❌ Lỗi Smart Character Video workflow: {e}")



