            main_container.pack(fill="both", expand=True)

            

            # Header

            header_frame = tb.Frame(main_container)

            header_frame.pack(fill="x", pady=(0, 15))

            

            tb.Label(header_frame, text="📸 Upload ảnh cho nhân vật", 

                    font=("Arial", 14, "bold"), bootstyle="primary").pack()

            tb.Label(header_frame, text=f"Tổng số nhân vật: {len(self.extracted_characters)}", 

                    font=("Arial", 10), bootstyle="secondary").pack(pady=(5, 0))

            

            # Scrollable frame for character list

            scrollable_frame = ScrolledFrame(main_container, autohide=True, bootstyle="round")

            scrollable_frame.pack(fill="both", expand=True, pady=(0, 15))

            

            # Footer with status info (defined early so handlers can access it)

            footer_frame = tb.Frame(main_container)

            footer_frame.pack(fill="x", pady=(10, 0))

            

            status_info = tb.Label(footer_frame, text=f"Đã chọn: 0/{len(self.extracted_characters)} ảnh", 

                                 font=("Arial", 9), bootstyle="secondary")

            status_info.pack(side="left")

            

            # Store character-image mappings temporarily

            temp_image_paths = {}

            

            # Store labels for each character (to fix closure issue)

            character_labels = {}

            

            # Create row for each character

            for i, char in enumerate(self.extracted_characters):

                char_name = char.get("name", f"Character_{i}")

                char_desc = char.get("description", "No description")

                

                # Character card with border

                char_card = tb.Frame(scrollable_frame, bootstyle="light", padding=15)

                char_card.pack(fill="x", pady=8, padx=5)

                

                # Character info section

