                info_section.pack(fill="x", pady=(0, 10))

                

                # Character name and number

                name_frame = tb.Frame(info_section)

                name_frame.pack(fill="x", pady=(0, 5))

                

                tb.Label(name_frame, text=f"{i+1}. {char_name}", 

                        font=("Arial", 11, "bold"), bootstyle="primary").pack(side="left")

                

                # Description

                desc_text = char_desc[:100] + "..." if len(char_desc) > 100 else char_desc

                tb.Label(info_section, text=desc_text, 

                        font=("Arial", 9), bootstyle="secondary", wraplength=600).pack(anchor="w")

                

                # Image selection section

                img_section = tb.Frame(char_card)

                img_section.pack(fill="x")

                

                # Status label (left side)

                status_frame = tb.Frame(img_section)

                status_frame.pack(side="left", fill="x", expand=True)

                

                current_img_path = self.character_images.get(char_name, "")

                img_status_label = tb.Label(status_frame, text="", font=("Arial", 9))

                img_status_label.pack(side="left", padx=(0, 10))

                

                # Store label for this character

