            self._sync_log_success("Đã khởi tạo T2V project")

            

            # Step 2: Chuẩn bị tích hợp với Video tab

            self._sync_log_step(2, 4, "Chuẩn bị tích hợp Video tab", "Đang thiết lập...")

            self._sync_log_info("Sẽ tạo từng task riêng cho từng video T2V")

