    def on_jsonp_run_images_only(self) -> None:

        cookies = self._get_cookies_source()

        if not cookies:

            Messagebox.show_error("Hãy nhập cookies hợp lệ ở tab Video.")

            return

        client = LabsFlowClient(_parse_cookie_string(cookies))

        if not client.fetch_access_token():

            Messagebox.show_error("Không lấy được access token từ cookies.")

            return



        img_folder = getattr(self, 'ent_jsonp_img_folder', None).get().strip() if hasattr(self, 'ent_jsonp_img_folder') else ""

        if not img_folder or not Path(img_folder).exists():

            Messagebox.show_error("Hãy chọn thư mục Image JSON hợp lệ.")

            return



        subject_img = getattr(self, 'ent_subject_image', None).get().strip() if hasattr(self, 'ent_subject_image') else ""

        if not subject_img:

            subject_img = getattr(self, 'ent_jsonp_subject_image', None).get().strip() if hasattr(self, 'ent_jsonp_subject_image') else ""

        scene_img = getattr(self, 'ent_scene_image', None).get().strip() if hasattr(self, 'ent_scene_image') else ""

        if not scene_img:

            scene_img = getattr(self, 'ent_jsonp_scene_image', None).get().strip() if hasattr(self, 'ent_jsonp_scene_image') else ""

        style_img = getattr(self, 'ent_style_image', None).get().strip() if hasattr(self, 'ent_style_image') else ""

        if not style_img:

            style_img = getattr(self, 'ent_jsonp_style_image', None).get().strip() if hasattr(self, 'ent_jsonp_style_image') else ""



        img_aspect = self._image_aspect_map.get(self.cmb_jsonp_img_aspect.get().strip(), "IMAGE_ASPECT_RATIO_LANDSCAPE")

        seed = self._get_jsonp_seed()



        def _worker_images_only():

            try:

                self._jsonp_log("🚀 Bắt đầu tạo ảnh (chỉ ảnh)...\n")

                img_files = sorted(Path(img_folder).glob("line_*.json"))

                self._jsonp_log(f"📁 Tìm thấy {len(img_files)} file image JSON\n")



                subj_mgid = scene_mgid = style_mgid = None

                try:

                    if subject_img and Path(subject_img).suffix.lower() in (".jpg", ".jpeg", ".png") and Path(subject_img).exists():

                        subj_mgid = client.upload_image(subject_img)

                        if subj_mgid:

                            self._jsonp_log(f"✓ Đã upload ảnh Subject: {subj_mgid}\n")

                except Exception as e:

                    self._jsonp_log(f"⚠ Không upload được ảnh Subject: {e}\n")

                try:

                    if scene_img and Path(scene_img).suffix.lower() in (".jpg", ".jpeg", ".png") and Path(scene_img).exists():

                        scene_mgid = client.upload_image(scene_img)

                        if scene_mgid:

                            self._jsonp_log(f"✓ Đã upload ảnh Scene: {scene_mgid}\n")

                except Exception as e:

                    self._jsonp_log(f"⚠ Không upload được ảnh Scene: {e}\n")

                try:

                    if style_img and Path(style_img).suffix.lower() in (".jpg", ".jpeg", ".png") and Path(style_img).exists():

                        style_mgid = client.upload_image(style_img)

                        if style_mgid:

                            self._jsonp_log(f"✓ Đã upload ảnh Style: {style_mgid}\n")

                except Exception as e:

                    self._jsonp_log(f"⚠ Không upload được ảnh Style: {e}\n")



                for idx, img_file in enumerate(img_files, start=1):

                    try:

                        img_prompt = img_file.read_text(encoding="utf-8").strip()

                    except Exception as e:

                        self._jsonp_log(f"✗ Dòng {idx}: Lỗi đọc {img_file.name}: {e}\n")

                        continue



                    workflow_id = client.create_whisk_workflow()

                    if not workflow_id:

                        self._jsonp_log("✗ Không tạo được workflow. Bỏ qua dòng này.\n")

                        continue



                    try:

                        if subj_mgid or scene_mgid or style_mgid:

                            res = client.run_image_recipe(

                                workflow_id=workflow_id,

                                prompt=img_prompt,

                                image_model="R2I",

                                aspect_ratio=img_aspect,

                                subject_mgid=subj_mgid,

                                scene_mgid=scene_mgid,

                                style_mgid=style_mgid,

                                seed=seed,

                            )

                        else:

                            res = client.generate_image_from_text(

                                workflow_id=workflow_id,

                                prompt=img_prompt,

                                image_model="R2I",

                                aspect_ratio=img_aspect,

                                seed=seed if seed is not None else None,

                            )

                        if not res:

                            self._jsonp_log("✗ Lỗi tạo ảnh.\n")

                            continue

                        urls = _extract_file_urls(res)

                        if urls:

                            self._jsonp_log(f"✓ Ảnh dòng {idx:03d}: {urls[0]}\n")

                            downloads_dir = Path(self.ent_wf_downloads.get().strip() or str(Path.home() / "Downloads"))

                            target = downloads_dir / f"jsonp_image_{idx:03d}.png"

                            target = self._ensure_unique_filename(target)

                            method = self.cmb_download_method.get()

                            self.download_queue.put(DownloadTask(url=urls[0], target_path=target, method=method, downloads_dir=downloads_dir))

                        else:

                            self._jsonp_log("⚠ Không tìm thấy URL ảnh trong phản hồi.\n")

                    except Exception as e:

                        self._jsonp_log(f"✗ Lỗi tạo ảnh dòng {idx:03d}: {e}\n")

                        continue



                self._jsonp_log("✅ Hoàn tất tạo ảnh.\n")

            except Exception as e:

                self._jsonp_log(f"❌ Lỗi tổng (ảnh): {e}\n")



        threading.Thread(target=_worker_images_only, daemon=True).start()



    def on_jsonp_run_videos_only(self) -> None:

        cookies = self._get_cookies_source()

        if not cookies:

            Messagebox.show_error("Hãy nhập cookies hợp lệ ở tab Video.")

            return

        client = LabsFlowClient(_parse_cookie_string(cookies))

        if not client.fetch_access_token():

            Messagebox.show_error("Không lấy được access token từ cookies.")

            return



        vid_folder = getattr(self, 'ent_jsonp_vid_folder', None).get().strip() if hasattr(self, 'ent_jsonp_vid_folder') else ""

        if not vid_folder or not Path(vid_folder).exists():

            Messagebox.show_error("Hãy chọn thư mục Video JSON hợp lệ.")

            return



        vid_aspect = self._selected_video_aspect()

        t2v_model = self.ent_jsonp_t2v_model.get().strip() or "veo_3_1_t2v_fast_ultra"

        seed = self._get_jsonp_seed()



        def _worker_videos_only():

            try:

                self._jsonp_log("🚀 Bắt đầu tạo video (chỉ video, T2V)...\n")

                vid_files = sorted(Path(vid_folder).glob("line_*.json"))

                self._jsonp_log(f"📁 Tìm thấy {len(vid_files)} file video JSON\n")

                for idx, vid_file in enumerate(vid_files, start=1):

                    try:

                        vid_prompt = vid_file.read_text(encoding="utf-8").strip()

                    except Exception as e:

                        self._jsonp_log(f"✗ Dòng {idx}: Lỗi đọc {vid_file.name}: {e}\n")

                        continue

                    try:

                        ops = client.generate_videos(

                            project_id=str(__import__('uuid').uuid4()),

                            tool="PINHOLE",

                            user_tier="PAYGATE_TIER_TWO",

                            prompt=vid_prompt,

                            model_key=t2v_model,

                            num_videos=1,

                            aspect_ratio=vid_aspect,

                            fixed_seed=seed,

                        )

                        if not ops:

                            self._jsonp_log("✗ Tạo video thất bại.\n")

                            continue

                        status = client.poll_until_complete(ops, max_wait_seconds=360, poll_interval=10)

                        urls = _extract_file_urls(status)

                        if urls:

                            self._jsonp_log(f"✓ Video dòng {idx:03d}: {urls[0]}\n")

                            downloads_dir = Path(self.ent_wf_downloads.get().strip() or str(Path.home() / "Downloads"))

                            target = downloads_dir / f"jsonp_video_{idx:03d}.mp4"

                            target = self._ensure_unique_filename(target)

                            method = self.cmb_download_method.get()

                            self.download_queue.put(DownloadTask(url=urls[0], target_path=target, method=method, downloads_dir=downloads_dir))

                        else:

                            self._jsonp_log("⚠ Không tìm thấy fileUrl/fifeUrl trong phản hồi.\n")

                    except Exception as e:

                        self._jsonp_log(f"✗ Lỗi tạo/poll video dòng {idx:03d}: {e}\n")

                        continue

                self._jsonp_log("✅ Hoàn tất tạo video.\n")

            except Exception as e:

                self._jsonp_log(f"❌ Lỗi tổng (video): {e}\n")



        threading.Thread(target=_worker_videos_only, daemon=True).start()



    def on_jsonp_generate(self) -> None:

        # Use Gemini to produce strict JSON prompts for image and video per line

        text = self.txt_jsonp_script.get("1.0", "end").strip()

        if not text:

            Messagebox.show_error("Nhập kịch bản trước.")

            return

        lines = [ln.strip() for ln in text.splitlines() if ln.strip()]

        if not lines:

            Messagebox.show_error("Không có dòng nào hợp lệ.")

            return



        # Parse multiple Gemini API keys (comma/newline separated) and validate

        raw_keys = ""

        api_key_entry = getattr(self, "ent_profile_gemini_key", None)

        if api_key_entry and hasattr(api_key_entry, "get"):

            raw_keys = api_key_entry.get().strip()

        if not raw_keys:

            env_key = os.getenv("GEMINI_API_KEY", "").strip()

            raw_keys = env_key or DEFAULT_GEMINI_KEY

        keys: list[str] = []

        if raw_keys:

            # Support comma/newline/whitespace separated

            tmp = raw_keys.replace("\n", ",").replace("\t", ",")

            for part in tmp.split(","):

                k = part.strip()

                if k:

                    keys.append(k)

        if not keys:

            Messagebox.show_error("Chưa cấu hình GEMINI_API_KEY (có thể nhập nhiều key, cách nhau bởi dấu phẩy hoặc xuống dòng).")

            return



        out_root = Path(self.ent_jsonp_outdir.get().strip() or (Path.cwd() / "json_prompt_outputs"))

        out_root.mkdir(parents=True, exist_ok=True)

        out_img = out_root / "image_json"

        out_vid = out_root / "video_json"

        out_img.mkdir(exist_ok=True)

        out_vid.mkdir(exist_ok=True)



        # Clear existing files before generating new ones

        self._jsonp_log("🧹 Xóa file cũ trong thư mục xuất...\n")

        for folder in [out_img, out_vid]:

            if folder.exists():

                for file_path in folder.glob("*"):

                    try:

                        if file_path.is_file():

                            file_path.unlink()

                            self._jsonp_log(f"✓ Đã xóa: {file_path.name}\n")

                    except Exception as e:

                        self._jsonp_log(f"⚠ Không xóa được {file_path.name}: {e}\n")

        self._jsonp_log("=" * 60 + "\n")



        # Hướng dẫn chi tiết cho prompt ảnh

        # Hướng dẫn chi tiết cho prompt ảnh, bổ sung style và seed

        sys_img = (

            "You are an expert cinematic storyteller. Generate STRICT JSON for an IMAGE prompt in English only. "

            "The output must be a single JSON object with these keys:\n"

            "1. stage – a short, evocative title for the scene.\n"

            "2. description – one or two sentences describing the visual scene vividly, including setting, characters, and key action. "

            "Ensure the scene remains consistent with the previous contexts: for this story, the environment revolves around the same small, humble sheep stable and its surroundings.\n"

            "3. camera – an object containing:\n"

            "   • movement – specify the camera movement using film terminology.\n"

            "   • framing – describe the shot composition.\n"

            "4. effects – an object containing at least two cinematic visual effects relevant to the scene.\n"

            "5. sound_effects – a short phrase describing ambient noises.\n"

            "6. mood – a single string with one to three adjectives.\n"

            "7. color_palette – concise description of dominant colors.\n"

            "Additional guidelines:\n"

            "• Do not change the scale or design of key props (e.g., the sheep stable should remain small and humble across scenes).\n"

            "• Avoid mentioning real people, celebrities, brand names, text, or watermarks.\n"

            "• Be specific about lighting direction, textures, and environmental details.\n"

            "Respond ONLY with a valid JSON object following these rules."

        )





        # Hướng dẫn chi tiết cho prompt video, cấu hình theo lựa chọn Audio

        if getattr(self, 'var_jsonp_audio', None) and self.var_jsonp_audio.get() == 'yes':

            sys_vid = (

                "You are an expert cinematic storyteller. Generate STRICT JSON for a VIDEO prompt in English only. "

                "The output must be a single JSON object with these keys:\n"

                "1. stage – a short, descriptive title for the scene.\n"

                "2. description – one or two sentences painting a vivid picture of the video scene, including setting, characters, and primary action.\n"

                "3. camera – an object containing:\n"

                "   • movement – describe the camera movement using film terminology (e.g., 'tracking shot following the hero', 'slow pan upwards').\n"

                "   • framing – describe the shot composition (e.g., 'medium shot of two characters', 'establishing wide shot of the setting').\n"

                "4. effects – an object listing at least two visual effects such as lighting effects, particle systems, or atmospheric details. Use simple key names (e.g., 'heavenly_light': 'soft beam…').\n"

                "5. sound_effects – a brief description of diegetic sounds (e.g., footsteps, wind, rustling leaves) that set the scene.\n"

                "6. audio – an object containing:\n"

                "   • voice_over – a concise English sentence delivering the key message based on the description; it must be coherent with the story and short enough to be spoken in under 8 seconds.\n"

                "   • background_music – describe the style or instrumentation of the music that complements the mood (e.g., 'soft strings and harp').\n"

                "   • ambient – describe the environmental sounds that play under the narration (e.g., 'distant city hum, gentle rain').\n"

                "   • voice – always specify 'male narrator, deep and calm, middle‑aged, conveying wonder'.\n"

                "7. mood – a single string with one to three adjectives summarizing the emotional tone.\n"

                "8. color_palette – a short description of the predominant colors that will dominate the scene’s visual palette.\n"

                "Further guidance:\n"

                "• Maintain continuity of the setting and props: the sheep stable and other key elements should remain the same small, humble structure across all scenes.\n"

                "• Write in a way that evokes a high‑quality animated film.\n"

                "• Do not reference real people, brands, logos or include any on-screen text.\n"

                "• Ensure that the voice_over text stands alone without referencing the prompt or instructions.\n"

                "Respond ONLY with a valid JSON object following these specifications."

            )

        else:

            sys_vid = (

                "You are an expert cinematic storyteller. Generate STRICT JSON for a VIDEO prompt in English only. "

                "The output must be a single JSON object with these keys:\n"

                "1. stage – a short, descriptive title for the scene.\n"

                "2. description – one or two sentences painting a vivid picture of the video scene, including setting, characters, and primary action.\n"

                "3. camera – an object containing:\n"

                "   • movement – describe the camera movement using film terminology (e.g., 'tracking shot following the hero', 'slow pan upwards').\n"

                "   • framing – describe the shot composition (e.g., 'medium shot of two characters', 'establishing wide shot of the setting').\n"

                "4. effects – an object listing at least two visual effects such as lighting effects, particle systems, or atmospheric details. Use simple key names (e.g., 'heavenly_light': 'soft beam…').\n"

                "5. sound_effects – a brief description of diegetic sounds (e.g., footsteps, wind, rustling leaves) that set the scene.\n"

                "6. audio – set to null and DO NOT include voice_over, background_music, ambient, or voice.\n"

                "7. mood – a single string with one to three adjectives summarizing the emotional tone.\n"

                "8. color_palette – a short description of the predominant colors that will dominate the scene’s visual palette.\n"

                "Respond ONLY with a valid JSON object following these specifications."

                "Further guidance:\n"

                "• Maintain continuity of the setting and props: the sheep stable and other key elements should remain the same small, humble structure across all scenes.\n"

                "• Write in a way that evokes a high‑quality animated film.\n"

                "• Do not reference real people, brands, logos or include any on-screen text.\n"

                "• Ensure that the voice_over text stands alone without referencing the prompt or instructions.\n"

                "Respond ONLY with a valid JSON object following these specifications."

            )





        # Run in background thread to prevent GUI freeze

        def _run_gemini_generation():

            try:

                import concurrent.futures as _fut



                # Use gemini-2.5-flash-lite with regular endpoint

                model = "gemini-2.5-flash-lite"

                self._jsonp_log(f"🤖 Sử dụng model: {model} (regular mode)\n")



                def _call_gemini_with_backoff(body: dict, api_key: str) -> str:

                    # Use regular endpoint (no streaming)

                    url = f"https://generativelanguage.googleapis.com/v1beta/models/{model}:generateContent?key={api_key}"

                    headers = {"Content-Type": "application/json; charset=utf-8"}

                    delay = 2.0

                    last_exc: Exception | None = None



                    # Log request details

                    # self._jsonp_log(f"📤 Gửi request đến Gemini (key ****{api_key[-6:]}):\n")

                    self._jsonp_log(f"   URL: {url}\n")

                    self._jsonp_log(f"   Body preview: {str(body)[:200]}...\n")



                    for attempt in range(5):

                        try:

                            resp = requests.post(url, headers=headers, data=json.dumps(body), timeout=120)



                            # Log response status

                            self._jsonp_log(f"📥 Response status: {resp.status_code} (attempt {attempt+1})\n")



                            if resp.status_code == 429 or resp.status_code >= 500:

                                # self._jsonp_log(f"⚠ Gemini {resp.status_code} (key ****{api_key[-6:]}). Thử lại sau {int(delay)}s...\n")

                                _t.sleep(delay)

                                delay = min(delay * 2, 16)

                                continue

                            resp.raise_for_status()



                            # Process regular response

                            data = resp.json()

                            text = GeminiTextGenerator._extract_text(data)

                            json_result = GeminiTextGenerator._extract_json_block(text)

                            self._jsonp_log(f"✅ JSON extracted: {len(json_result)} ký tự\n")

                            return json_result



                        except Exception as ex:

                            last_exc = ex

                            # self._jsonp_log(f"⚠ Lỗi gọi Gemini (attempt {attempt+1}) với key ****{api_key[-6:]}: {ex}\n")

                            _t.sleep(delay)

                            delay = min(delay * 2, 16)

                    raise last_exc if last_exc else Exception("Gemini rate limited or server error too many times")



                # Prepare full script context for better coherence

                full_script = "\n".join(lines)



                def _process_line(idx: int, line_text: str, api_key: str) -> tuple[int, str | None, str | None, str | None]:

                    try:

                        self._jsonp_log(f"🎬 Xử lý dòng {idx}: {line_text[:50]}...\n")



                        body_img = {

                            "contents": [

                                {

                                    "role": "user",

                                    "parts": [

                                        {

                                            "text": (

                                                sys_img +

                                                "\n\nContext story:\n" + full_script +

                                                "\n\nGenerate an IMAGE prompt JSON for this scene:\n" + line_text

                                            )

                                        }

                                    ]

                                }

                            ]

                        }



                        body_vid = {

                            "contents": [

                                {

                                    "role": "user",

                                    "parts": [

                                        {

                                            "text": (

                                                sys_vid +

                                                "\n\nContext story:\n" + full_script +

                                                "\n\nGenerate a VIDEO prompt JSON for this scene:\n" + line_text

                                            )

                                        }

                                    ]

                                }

                            ]

                        }



                        self._jsonp_log(f"🖼️  Tạo IMAGE JSON cho dòng {idx}...\n")

                        j_img = _call_gemini_with_backoff(body_img, api_key)



                        self._jsonp_log(f"🎥 Tạo VIDEO JSON cho dòng {idx}...\n")

                        j_vid = _call_gemini_with_backoff(body_vid, api_key)



                        self._jsonp_log(f"✅ Hoàn thành dòng {idx}\n")

                        return (idx, j_img, j_vid, None)

                    except Exception as ex:

                        self._jsonp_log(f"❌ Lỗi dòng {idx}: {ex}\n")

                        return (idx, None, None, str(ex))



                # Optimize concurrent requests: limit to 3 concurrent requests to respect rate limits

                max_concurrent = min(3, len(keys), len(lines))  # Limit to 3 concurrent tasks

                self._jsonp_log(f"🔑 Sử dụng {len(keys)} API keys, chạy song song tối đa {max_concurrent} dòng.\n")

                self._jsonp_log(f"📊 Tổng cộng {len(lines)} dòng cần xử lý.\n")



                results: list[tuple[int, str | None, str | None, str | None]] = []

                with _fut.ThreadPoolExecutor(max_workers=max_concurrent) as executor:

                    futs = []

                    for idx, line in enumerate(lines, 1):

                        api_key = keys[(idx - 1) % len(keys)]

                        futs.append(executor.submit(_process_line, idx, line, api_key))

                    completed = 0

                    for f in _fut.as_completed(futs):

                        result = f.result()

                        results.append(result)

                        completed += 1

                        self._jsonp_log(f"📈 Tiến độ: {completed}/{len(lines)} dòng hoàn thành\n")



                for idx, j_img, j_vid, err in sorted(results, key=lambda x: x[0]):

                    if err:

                        self._jsonp_log(f"✗ Dòng {idx}: lỗi tạo JSON: {err}\n")

                        continue

                    if j_img:

                        (out_img / f"line_{idx:03d}.json").write_text(j_img, encoding="utf-8")

                    if j_vid:

                        (out_vid / f"line_{idx:03d}.json").write_text(j_vid, encoding="utf-8")



                # Auto-fill folder paths after generation

                self.ent_jsonp_img_folder.delete(0, "end")

                self.ent_jsonp_img_folder.insert(0, str(out_img))

                self.ent_jsonp_vid_folder.delete(0, "end")

                self.ent_jsonp_vid_folder.insert(0, str(out_vid))

                self._jsonp_log(f"📁 Đã điền thư mục ảnh: {out_img}\n")

                self._jsonp_log(f"📁 Đã điền thư mục video: {out_vid}\n")



                # Use after() to call Messagebox from main thread

                self.root.after(0, lambda: Messagebox.show_info("Đã tạo JSON prompts cho tất cả dòng."))

            except Exception as e:

                self._jsonp_log(f"❌ Lỗi tổng thể: {e}\n")

                # Use after() to call Messagebox from main thread

                self.root.after(0, lambda: Messagebox.show_error(f"Lỗi khi gọi Gemini: {e}"))



        # Start background thread

        import threading

        thread = threading.Thread(target=_run_gemini_generation, daemon=True)

        thread.start()



    def on_jsonp_run(self) -> None:

        cookies = self._get_cookies_source()

        if not cookies:

            Messagebox.show_error("Hãy nhập cookies hợp lệ ở tab Video.")

            return

        client = LabsFlowClient(_parse_cookie_string(cookies))

        if not client.fetch_access_token():

            Messagebox.show_error("Không lấy được access token từ cookies.")

            return



        out_root = Path(self.ent_jsonp_outdir.get().strip() or (Path.cwd() / "json_prompt_outputs"))

        out_root.mkdir(parents=True, exist_ok=True)

        folders = {

            "image_json": out_root / "image_json",

            "video_json": out_root / "video_json",

            "images": out_root / "images",

            "videos": out_root / "videos",

        }

        for p in folders.values():

            p.mkdir(exist_ok=True)



        img_aspect = self._image_aspect_map.get(self.cmb_jsonp_img_aspect.get().strip(), "IMAGE_ASPECT_RATIO_LANDSCAPE")

        vid_aspect = self._selected_video_aspect()

        i2v_model = self.ent_jsonp_i2v_model.get().strip() or "veo_3_1_i2v_s_fast_ultra"

        t2v_model = self.ent_jsonp_t2v_model.get().strip() or "veo_3_1_t2v_fast_ultra"

        seed = self._get_jsonp_seed()



        # Override portrait model if needed

        if vid_aspect == "VIDEO_ASPECT_RATIO_PORTRAIT":

            i2v_model = self._i2v_portrait_overrides.get(i2v_model, i2v_model)



        # Upload reference images if provided

        # Prioritize Image tab inputs; fallback to JSON Prompt tab inputs

        subject_img = ""

        scene_img = ""

        style_img = ""



        try:

            subject_img = getattr(self, 'ent_subject_image', None).get().strip() if hasattr(self, 'ent_subject_image') else ""

        except Exception:

            subject_img = ""

        if not subject_img:

            subject_img = getattr(self, 'ent_jsonp_subject_image', None).get().strip() if hasattr(self, 'ent_jsonp_subject_image') else ""



        try:

            scene_img = getattr(self, 'ent_scene_image', None).get().strip() if hasattr(self, 'ent_scene_image') else ""

        except Exception:

            scene_img = ""

        if not scene_img:

            scene_img = getattr(self, 'ent_jsonp_scene_image', None).get().strip() if hasattr(self, 'ent_jsonp_scene_image') else ""



        try:

            style_img = getattr(self, 'ent_style_image', None).get().strip() if hasattr(self, 'ent_style_image') else ""

        except Exception:

            style_img = ""

        if not style_img:

            style_img = getattr(self, 'ent_jsonp_style_image', None).get().strip() if hasattr(self, 'ent_jsonp_style_image') else ""

        subj_mgid = scene_mgid = style_mgid = None



        if subject_img and Path(subject_img).exists():

            if Path(subject_img).suffix.lower() in (".jpg", ".jpeg", ".png"):

                try:

                    up = client.upload_image(subject_img)

                    if up:

                        subj_mgid = up

                        self._jsonp_log(f"✓ Đã upload ảnh Subject: {subj_mgid}\n")

                except Exception as e:

                    self._jsonp_log(f"⚠ Không upload được ảnh Subject: {e}\n")

            else:

                self._jsonp_log("⚠ Bỏ qua ảnh Subject không hỗ trợ (chỉ nhận .jpg/.jpeg/.png).\n")



        if scene_img and Path(scene_img).exists():

            if Path(scene_img).suffix.lower() in (".jpg", ".jpeg", ".png"):

                try:

                    up = client.upload_image(scene_img)

                    if up:

                        scene_mgid = up

                        self._jsonp_log(f"✓ Đã upload ảnh Scene: {scene_mgid}\n")

                except Exception as e:

                    self._jsonp_log(f"⚠ Không upload được ảnh Scene: {e}\n")

            else:

                self._jsonp_log("⚠ Bỏ qua ảnh Scene không hỗ trợ (chỉ nhận .jpg/.jpeg/.png).\n")



        if style_img and Path(style_img).exists():

            if Path(style_img).suffix.lower() in (".jpg", ".jpeg", ".png"):

                try:

                    up = client.upload_image(style_img)

                    if up:

                        style_mgid = up

                        self._jsonp_log(f"✓ Đã upload ảnh Style: {style_mgid}\n")

                except Exception as e:

                    self._jsonp_log(f"⚠ Không upload được ảnh Style: {e}\n")

            else:

                self._jsonp_log("⚠ Bỏ qua ảnh Style không hỗ trợ (chỉ nhận .jpg/.jpeg/.png).\n")



        # Gather prompts: from JSON folders if provided, else from text area

        img_prompts: List[str] = []

        vid_prompts: List[str] = []

        ipath = getattr(self, 'ent_jsonp_img_folder', None).get().strip() if hasattr(self, 'ent_jsonp_img_folder') else ""

        vpath = getattr(self, 'ent_jsonp_vid_folder', None).get().strip() if hasattr(self, 'ent_jsonp_vid_folder') else ""



        # If both folders are provided, use JSON files and ignore script

        if ipath and os.path.exists(ipath) and vpath and os.path.exists(vpath):

            try:

                # Read all line_*.json files and use entire JSON as prompt

                img_folder = Path(ipath)

                vid_folder = Path(vpath)



                # Get all line files from both folders

                img_files = sorted(img_folder.glob("line_*.json"))

                vid_files = sorted(vid_folder.glob("line_*.json"))



                # Match by line number (line_01.json -> line_01.json)

                for img_file in img_files:

                    try:

                        # Extract line number from filename (e.g., line_01.json -> 01)

                        line_num = img_file.stem.split('_')[1] if '_' in img_file.stem else img_file.stem

                        vid_file = vid_folder / f"line_{line_num}.json"



                        if vid_file.exists():

                            # Read image JSON

                            img_data = json.loads(img_file.read_text(encoding="utf-8"))

                            img_prompts.append(json.dumps(img_data, ensure_ascii=False, indent=2))



                            # Read video JSON

                            vid_data = json.loads(vid_file.read_text(encoding="utf-8"))

                            vid_prompts.append(json.dumps(vid_data, ensure_ascii=False, indent=2))

                        else:

                            self._jsonp_log(f"⚠ Không tìm thấy file tương ứng: {vid_file.name}\n")

                    except Exception as e:

                        self._jsonp_log(f"⚠ Không đọc được {img_file.name}: {e}\n")



            except Exception as e:

                self._jsonp_log(f"⚠ Không đọc được thư mục JSON: {e}\n")

        else:

            # JSON Prompt tab now requires JSON folders to be selected

            Messagebox.show_error("Hãy chọn thư mục JSON prompts (image và video).")

            return



        # Process each line sequentially (respecting global semaphore for generation if needed)

        # Run in background thread to avoid GUI freeze

        def _run_jsonp_worker():

            try:

                self._jsonp_log("🚀 Bắt đầu xử lý JSON prompts...\n")



                # Read JSON files from folders

                img_folder = self.ent_jsonp_img_folder.get().strip()

                vid_folder = self.ent_jsonp_vid_folder.get().strip()



                if not img_folder or not vid_folder:

                    self._jsonp_log("✗ Chưa chọn thư mục JSON prompts\n")

                    return



                img_folder_path = Path(img_folder)

                vid_folder_path = Path(vid_folder)



                if not img_folder_path.exists() or not vid_folder_path.exists():

                    self._jsonp_log("✗ Thư mục JSON prompts không tồn tại\n")

                    return



                # Find all line_*.json files

                img_files = sorted(img_folder_path.glob("line_*.json"))

                vid_files = sorted(vid_folder_path.glob("line_*.json"))



                self._jsonp_log(f"📁 Tìm thấy {len(img_files)} file image JSON\n")

                self._jsonp_log(f"📁 Tìm thấy {len(vid_files)} file video JSON\n")

                self._jsonp_log("=" * 60 + "\n")



                total = max(len(img_files), len(vid_files))

                

                # Tạo từng video task riêng trong Video tab nếu đang chạy từ Sync tab

                sync_video_tasks = {}

                if hasattr(self, '_sync_log'):  # Check if running from Sync tab

                    self._sync_log_header(f"🎬 TẠO {total} VIDEO TASKS RIÊNG BIỆT")

                for idx in range(1, total + 1):

                    vid_file = vid_files[(idx - 1) % max(1, len(vid_files))] if vid_files else None

                    if vid_file:

                        try:

                            # Read video prompt for task name

                            vid_prompt = vid_file.read_text(encoding="utf-8").strip()

                            # Extract prompt text from JSON

                            import json as _json

                            try:

                                vid_data = _json.loads(vid_prompt)

                                prompt_text = ""

                                if "scenes" in vid_data and len(vid_data["scenes"]) > 0:

                                    prompt_text = vid_data["scenes"][0].get("prompt", f"Video {idx}")

                                else:

                                    prompt_text = f"Video {idx}"

                            except:

                                prompt_text = f"Video {idx}"

                            

                            # Add individual video task

                            task_iid = self._add_sync_video_task(idx, total, prompt_text, f"SCENE_{idx:02d}")

                            sync_video_tasks[idx] = task_iid

                            self._sync_log_success(f"Đã tạo task cho Video {idx}/{total}")

                        except Exception as e:

                            self._sync_log_error(f"Lỗi tạo task cho Video {idx}: {e}")

                

                # Process video tasks in parallel

                self._process_video_tasks_parallel(

                    total, img_files, vid_files, sync_video_tasks,

                    client, i2v_model, t2v_model, 

                    vid_aspect, seed, subj_mgid, scene_mgid, style_mgid

                )



                self._jsonp_log("✅ Hoàn tất xử lý JSON prompts.\n")

            except Exception as e:

                self._jsonp_log(f"❌ Lỗi tổng worker: {e}\n")



        # Start background worker

        threading.Thread(target=_run_jsonp_worker, daemon=True).start()



