    import re  # helper cho natural sort

    

    # ----- Edit Tab Handlers -----

    def on_edit_add_videos(self) -> None:

        files = filedialog.askopenfilenames(title="Chọn các video để ghép", filetypes=[("Video", "*.mp4;*.mov;*.mkv;*.avi;*.webm"), ("All", "*.*")])

        if not files:

            return

        paths = [Path(f) for f in files]

        paths = natural_sort_paths(paths)

        self.edit_video_paths.extend(paths)

        self._refresh_edit_video_list()

    

    def on_edit_add_folder(self) -> None:

        folder = filedialog.askdirectory(title="Chọn thư mục chứa video")

        if not folder:

            return

        try:

            video_files = []

            for ext in ("*.mp4", "*.mov", "*.mkv", "*.avi", "*.webm"):

                video_files.extend(Path(folder).glob(ext))

            video_files = natural_sort_paths(list(video_files))

            self.edit_video_paths.extend(video_files)

            self._refresh_edit_video_list()

        except Exception as e:

            self._edit_log(f"Lỗi khi thêm video từ thư mục: {e}\n")

    

    def on_edit_rename_selected(self, prefix: Optional[str] = None, start_index: int = 1, apply_to: str = "images"):

        """

        Đổi tên các file đã chọn hoặc toàn bộ list (images/videos) theo thứ tự số.

        - prefix: chuỗi tiền tố (nếu None sẽ dùng 'file')

        - start_index: bắt đầu từ số nào (mặc định 1)

        - apply_to: "images" hoặc "videos" để chọn danh sách nội bộ

        """

        try:

            if apply_to == "videos":

                paths = [Path(p) for p in self.edit_video_paths]

            else:

                paths = [Path(p) for p in getattr(self, "edit_image_paths", [])]

    

            if not paths:

                return

    

            # natural sort theo tên file (stem)

            paths = natural_sort_paths(paths)

    

            total = len(paths)

            pad = len(str(total + start_index - 1))

    

            # Đổi tên an toàn: dùng tên tạm để tránh trùng lặp

            temp_map = {}

            for i, p in enumerate(paths, start=start_index):

                new_name = f"{(prefix or 'file')}_{str(i).zfill(pad)}{p.suffix}"

                temp = p.with_name(f".tmp_rename_{i}{p.suffix}")

                p.rename(temp)

                temp_map[temp] = p.with_name(new_name)

    

            # rename từ tạm -> tên cuối cùng

            for temp, final in temp_map.items():

                temp.rename(final)

    

            # Cập nhật danh sách nội bộ

            new_list = [p for p in natural_sort_paths(list(temp_map.values()))]

            if apply_to == "videos":

                self.edit_video_paths = new_list

                self._refresh_edit_video_list()

            else:

                self.edit_image_paths = new_list

                self._refresh_edit_image_list()

        except Exception as e:

            self._edit_log(f"Lỗi khi đổi tên: {e}\n")



    def on_edit_select_all(self, event=None) -> None:

        """Select all videos in the list."""

        try:

            # Select all items in the Treeview

            items = self.lst_edit_videos.get_children()

            if items:

                self.lst_edit_videos.selection_set(items)

                self._edit_log(f"Đã chọn tất cả {len(items)} video.\n")

            else:

                self._edit_log("Không có video nào để chọn.\n")

        except Exception as e:

            self._edit_log(f"Lỗi chọn tất cả: {e}\n")



    def on_edit_deselect_all(self) -> None:

        """Deselect all videos in the list."""

        try:

            # Clear all selections

            self.lst_edit_videos.selection_clear()

            self._edit_log("Đã bỏ chọn tất cả video.\n")

        except Exception as e:

            self._edit_log(f"Lỗi bỏ chọn: {e}\n")



    def on_edit_remove_selected(self) -> None:

        try:

            sel = self.lst_edit_videos.selection()

            if not sel:

                self._edit_log("Không có video nào được chọn.\n")

                return



            count = len(sel)

            indices = sorted([self.lst_edit_videos.index(i) for i in sel], reverse=True)

            for idx in indices:

                if 0 <= idx < len(self.edit_video_paths):

                    del self.edit_video_paths[idx]

            self._refresh_edit_video_list()

            self._edit_log(f"Đã xóa {count} video.\n")

        except Exception as e:

            self._edit_log(f"Lỗi xóa video: {e}\n")



    def on_edit_move_selected(self, delta: int) -> None:

        try:

            sel = self.lst_edit_videos.selection()

            if not sel:

                return

            idx = self.lst_edit_videos.index(sel[0])

            new_idx = max(0, min(len(self.edit_video_paths) - 1, idx + delta))

            if new_idx != idx:

                self.edit_video_paths[idx], self.edit_video_paths[new_idx] = self.edit_video_paths[new_idx], self.edit_video_paths[idx]

                self._refresh_edit_video_list(select_index=new_idx)

        except Exception:

            pass



    def on_edit_random_order(self) -> None:

        """Xáo trộn thứ tự các video trong danh sách."""

        try:

            if not self.edit_video_paths:

                self._edit_log("⚠️ Không có video nào để xáo trộn.\n")

                return



            import random

            random.shuffle(self.edit_video_paths)

            self._refresh_edit_video_list()

            self._edit_log(f"🎲 Đã xáo trộn thứ tự {len(self.edit_video_paths)} video.\n")

        except Exception as e:

            self._edit_log(f"Lỗi khi xáo trộn: {e}\n")



    def _refresh_edit_video_list(self, select_index: Optional[int] = None) -> None:

        try:

            for i in self.lst_edit_videos.get_children():

                self.lst_edit_videos.delete(i)

            for p in self.edit_video_paths:

                self.lst_edit_videos.insert("", "end", values=(str(p),))

            if select_index is not None and 0 <= select_index < len(self.edit_video_paths):

                iid = self.lst_edit_videos.get_children()[select_index]

                self.lst_edit_videos.selection_set(iid)

        except Exception:

            pass



    def on_edit_choose_bgm(self) -> None:

        f = filedialog.askopenfilename(title="Chọn nhạc nền", filetypes=[("Audio", "*.mp3;*.wav;*.m4a;*.aac;*.flac;*.ogg"), ("All", "*.*")])

        if f:

            try:

                self.ent_bgm_path.delete(0, "end")

                self.ent_bgm_path.insert(0, f)

                self.edit_bgm_path = Path(f)

                # Auto-fill repeat seconds from bgm duration

                d = self._probe_duration_seconds(f)

                if d and d > 0:

                    self.ent_repeat_seconds.delete(0, "end")

                    self.ent_repeat_seconds.insert(0, str(int(d)))

                    self.var_repeat_enable.set(True)

                    self._edit_log(f"Đã điền thời lượng từ nhạc: ~{d:.2f}s")

            except Exception:

                pass



    def on_edit_choose_output(self) -> None:

        f = filedialog.asksaveasfilename(title="Chọn file xuất", defaultextension=".mp4", filetypes=[("MP4", "*.mp4"), ("All", "*.*")])

        if f:

            try:

                self.ent_edit_output.delete(0, "end")

                self.ent_edit_output.insert(0, f)

            except Exception:

                pass



    def _edit_log(self, msg: str) -> None:

        try:

            self.txt_edit_log.insert("end", msg + "\n")

            self.txt_edit_log.see("end")

        except Exception:

            pass



    def on_edit_cancel(self) -> None:

        # Best-effort: mark flag; we spawn ffmpeg as subprocess so we will terminate it

        self.edit_processing = False



    def on_edit_run(self) -> None:

        if self.edit_processing:

            return

        if not self.edit_video_paths:

            Messagebox.show_error("Hãy thêm ít nhất 1 video.")

            return

        out = self.ent_edit_output.get().strip()

        if not out:

            Messagebox.show_error("Hãy chọn file xuất.")

            return

        mode = self.var_audio_mode.get()

        bgm = self.ent_bgm_path.get().strip()

        if mode in ("mix", "bgm") and not bgm and mode != "mute":

            # mix có thể không bgm -> thực tế cần bgm; cảnh báo nhẹ

            if not Messagebox.yesno("Bạn chưa chọn nhạc nền. Tiếp tục?"):

                return



        self.btn_edit_run.configure(state="disabled")

        self.btn_edit_cancel.configure(state="normal")

        self.edit_processing = True



        threading.Thread(target=self._edit_worker, args=(out, mode, bgm), daemon=True).start()



    # ----- Auto Edit handlers -----

    def on_auto_choose_bgm(self) -> None:

        f = filedialog.askopenfilename(title="Chọn nhạc nền", filetypes=[("Audio", "*.mp3;*.wav;*.m4a;*.aac;*.flac;*.ogg"), ("All", "*.*")])

        if not f:

            return

        try:

            self._auto_bgm_path_str = f

            # Reflect into popup entry if present

            if hasattr(self, 'ent_auto_bgm_popup') and self.ent_auto_bgm_popup.winfo_exists():

                with suppress(Exception):

                    self.ent_auto_bgm_popup.delete(0, "end"); self.ent_auto_bgm_popup.insert(0, f)

            # Auto-fill seconds and enable repeat

            d = self._probe_duration_seconds(f)

            if d and d > 0:

                self._auto_seconds_str = str(int(d))

                self.var_auto_repeat.set(True)

                if hasattr(self, 'ent_auto_seconds_popup') and self.ent_auto_seconds_popup.winfo_exists():

                    with suppress(Exception):

                        self.ent_auto_seconds_popup.delete(0, "end"); self.ent_auto_seconds_popup.insert(0, self._auto_seconds_str)

        except Exception:

            pass



    def on_auto_fill_from_bgm(self) -> None:

        f = self._auto_bgm_path_str.strip()

        if not f:

            Messagebox.show_info("Chưa chọn file nhạc nền.")

            return

        d = self._probe_duration_seconds(f)

        if not d or d <= 0:

            Messagebox.show_error("Không đọc được thời lượng bài nhạc.")

            return

        self._auto_seconds_str = str(int(d))

        self.var_auto_repeat.set(True)

        if hasattr(self, 'ent_auto_seconds_popup') and self.ent_auto_seconds_popup.winfo_exists():

            with suppress(Exception):

                self.ent_auto_seconds_popup.delete(0, "end"); self.ent_auto_seconds_popup.insert(0, self._auto_seconds_str)



    def on_auto_choose_output(self) -> None:

        f = filedialog.asksaveasfilename(title="Chọn file xuất", defaultextension=".mp4", filetypes=[("MP4", "*.mp4"), ("All", "*.*")])

        if f:

            self._auto_output_str = f

            # Reflect into popup entry if present

            if hasattr(self, 'ent_auto_output_popup') and self.ent_auto_output_popup.winfo_exists():

                with suppress(Exception):

                    self.ent_auto_output_popup.delete(0, "end"); self.ent_auto_output_popup.insert(0, f)



    def _validate_auto_edit_settings(self) -> Optional[str]:

        if not self.var_auto_edit_enable.get():

            return None

        mode = self.var_auto_audio_mode.get()

        bgm = self.ent_auto_bgm.get().strip()

        if mode in ("bgm", "mix") and not bgm:

            return "Bật Auto Edit với chế độ có nhạc nhưng chưa chọn file nhạc nền."

        if self.var_auto_repeat.get():

            secs = 0

            if bgm:

                d = self._probe_duration_seconds(bgm) or 0

                secs = int(d)

            if secs == 0:

                try:

                    secs = int(float(self.ent_auto_seconds.get().strip()))

                except Exception:

                    secs = 0

            if secs <= 0:

                return "Đã bật lặp nhưng thời lượng mục tiêu không hợp lệ."

        return None



    def _maybe_run_auto_edit(self, profile_name: str) -> None:

        try:

            if not self.var_auto_edit_enable.get():

                return

            err = self._validate_auto_edit_settings()

            if err:

                self._log(f"[Auto Edit] ⚠️ {err}\n");

                return

            files = list({str(p) for p in self._auto_edit_files.get(profile_name, [])})

            if not files:

                # Try to gather from profile output dir as fallback

                prof_out_dir = Path(self.profile_settings["output_dir"]) / f"Profile_{profile_name}"

                if prof_out_dir.exists():

                    exts = {".mp4", ".mov", ".mkv", ".avi", ".webm"}

                    files = [str(p) for p in sorted(prof_out_dir.glob("*")) if p.suffix.lower() in exts]

            if not files:

                self._log(f"[Auto Edit] Không tìm thấy video cho profile {profile_name}.\n")

                return

            # Apply to Edit tab lists and settings

            self.edit_video_paths = [Path(f) for f in files]

            self._refresh_edit_video_list()

            # Mirror settings to Edit tab widgets

            try:

                self.var_audio_mode.set(self.var_auto_audio_mode.get())

                self.var_normalize_audio.set(False)

                self.var_ffmpeg_console.set(self.var_auto_console.get())

                # Repeat

                self.var_repeat_enable.set(self.var_auto_repeat.get())

                self.ent_repeat_seconds.delete(0, "end"); self.ent_repeat_seconds.insert(0, self.ent_auto_seconds.get().strip() or "0")

                # BGM

                self.ent_bgm_path.delete(0, "end"); self.ent_bgm_path.insert(0, self.ent_auto_bgm.get().strip())

                # Output

                out = self.ent_auto_output.get().strip()

                if not out:

                    ts = _t.strftime("%Y%m%d_%H%M%S")

                    out = str((Path(self.profile_settings["output_dir"]) / f"{profile_name}_{ts}.mp4").resolve())

                self.ent_edit_output.delete(0, "end"); self.ent_edit_output.insert(0, out)

            except Exception:

                pass

            # Kick off edit run

            self._edit_log(f"[Auto Edit] Bắt đầu ghép cho profile {profile_name} với {len(files)} video...")

            self.on_edit_run()

        except Exception as e:

            self._log(f"[Auto Edit] Lỗi: {e}\n")



    def _find_tool(self, name: str) -> Optional[str]:

        # Search local folder first, then PATH

        candidates = [

            str(self._app_root() / f"{name}.exe"),

            name,

        ]

        for c in candidates:

            try:

                creationflags = subprocess.CREATE_NO_WINDOW if os.name == 'nt' else 0

                proc = subprocess.run([c, "-version"], stdout=subprocess.PIPE, stderr=subprocess.STDOUT, timeout=3,

                                    creationflags=creationflags)

                if proc.returncode == 0 or proc.stdout:

                    return c

            except Exception:

                continue

        return None



    def _probe_duration_seconds(self, media_path: str) -> Optional[float]:

        ffprobe = self._find_tool("ffprobe")

        if not ffprobe:

            return None

        try:

            creationflags = subprocess.CREATE_NO_WINDOW if os.name == 'nt' else 0

            proc = subprocess.run([

                ffprobe,

                "-v", "error",

                "-show_entries", "format=duration",

                "-of", "default=noprint_wrappers=1:nokey=1",

                media_path

            ], stdout=subprocess.PIPE, stderr=subprocess.STDOUT, text=True, timeout=10, creationflags=creationflags)

            if proc.returncode == 0 and proc.stdout:

                return float(proc.stdout.strip())

        except Exception:

            pass

        return None



    def _probe_video_resolution(self, video_path: str) -> Optional[Tuple[int, int]]:

        """Probe video resolution (width, height) using ffprobe."""

        ffprobe = self._find_tool("ffprobe")

        if not ffprobe:

            return None

        try:

            creationflags = subprocess.CREATE_NO_WINDOW if os.name == 'nt' else 0

            proc = subprocess.run([

                ffprobe,

                "-v", "error",

                "-select_streams", "v:0",

                "-show_entries", "stream=width,height",

                "-of", "csv=p=0",

                video_path

            ], stdout=subprocess.PIPE, stderr=subprocess.STDOUT, text=True, timeout=10, creationflags=creationflags)

            if proc.returncode == 0 and proc.stdout:

                parts = proc.stdout.strip().split(',')

                if len(parts) >= 2:

                    return (int(parts[0]), int(parts[1]))

        except Exception:

            pass

        return None



    def _has_audio_stream(self, media_path: str) -> bool:

        ffprobe = self._find_tool("ffprobe")

        if not ffprobe:

            return True  # assume yes to avoid breaking flow

        try:

            creationflags = subprocess.CREATE_NO_WINDOW if os.name == 'nt' else 0

            proc = subprocess.run([

                ffprobe,

                "-v", "error",

                "-select_streams", "a",

                "-show_entries", "stream=index",

                "-of", "csv=p=0",

                media_path

            ], stdout=subprocess.PIPE, stderr=subprocess.STDOUT, text=True, timeout=10, creationflags=creationflags)

            out = (proc.stdout or "").strip()

            return bool(out)

        except Exception:

            return True



    def _spawn_ffmpeg(self, cmd: List[str]) -> subprocess.Popen:

        # Optionally show console for ffmpeg

        try:

            if self.var_ffmpeg_console.get():

                # Add loglevel for visibility

                if "-loglevel" not in cmd:

                    cmd = cmd[:]

                    cmd.insert(1, "-loglevel")

                    cmd.insert(2, "info")

                creationflags = getattr(subprocess, "CREATE_NEW_CONSOLE", 0)

                return subprocess.Popen(cmd, creationflags=creationflags)

        except Exception:

            pass

        # Hide console by default

        creationflags = subprocess.CREATE_NO_WINDOW if os.name == 'nt' else 0

        return subprocess.Popen(cmd, stdout=subprocess.PIPE, stderr=subprocess.STDOUT, text=True,

                                creationflags=creationflags)



    def on_fill_duration_from_bgm(self) -> None:

        try:

            bgm = self.ent_bgm_path.get().strip()

            if not bgm:

                Messagebox.show_info("Chưa chọn file nhạc nền.")

                return

            d = self._probe_duration_seconds(bgm)

            if not d or d <= 0:

                Messagebox.show_error("Không đọc được thời lượng bài nhạc.")

                return

            self.ent_repeat_seconds.delete(0, "end")

            self.ent_repeat_seconds.insert(0, str(int(d)))

            with suppress(Exception):

                self.var_repeat_enable.set(True)

                self.var_audio_mode.set("bgm")

            self._edit_log(f"Thời lượng nhạc: ~{d:.2f}s")

        except Exception:

            pass



    def _edit_worker(self, out_path: str, mode: str, bgm_path: str) -> None:

        ffmpeg = self._find_tool("ffmpeg")

        if not ffmpeg:

            self._schedule(Messagebox.show_error, "Không tìm thấy ffmpeg. Vui lòng đặt ffmpeg.exe cùng cấp ứng dụng hoặc trong PATH.")

            self._finalize_edit()

            return



        try:

            # 1) Tạo file concat list

            tmpdir = Path(tempfile.mkdtemp(prefix="edit_concat_"))

            concat_txt = tmpdir / "concat.txt"

            # Repeat logic: build list based on desired duration if enabled

            target_seconds: Optional[float] = None

            use_repeat = bool(self.var_repeat_enable.get())

            if use_repeat:

                # Determine desired duration: bgm duration if bgm provided, else from entry

                if bgm_path:

                    d = self._probe_duration_seconds(bgm_path)

                    if d and d > 0:

                        target_seconds = d

                if target_seconds is None:

                    try:

                        target_seconds = float(self.ent_repeat_seconds.get().strip())

                    except Exception:

                        target_seconds = None

                if not target_seconds or target_seconds <= 0:

                    self._edit_log("Thời lượng mục tiêu không hợp lệ. Bỏ qua lặp lại.")

                    use_repeat = False



            if use_repeat:

                self._edit_log(f"Đang lặp video đến ~{int(target_seconds)} giây (tắt tiếng gốc)...")

                # Get durations of inputs

                inputs = list(self.edit_video_paths)

                durations: List[float] = []

                for p in inputs:

                    d = self._probe_duration_seconds(str(p)) or 0.0

                    durations.append(max(0.0, d))

                try:

                    total_src = sum(durations)

                    self._edit_log(f"Tổng thời lượng danh sách nguồn: ~{total_src:.2f}s, số clip: {len(inputs)}")

                except Exception:

                    pass

                # Build repeated sequence until exceed target

                seq: List[Path] = []

                total = 0.0

                i = 0

                if sum(durations) <= 0:

                    # fallback if probe failed: just use one loop

                    seq = inputs.copy()

                else:

                    while total < target_seconds + 0.1 and self.edit_processing:

                        p = inputs[i % len(inputs)]

                        seq.append(p)

                        total += durations[i % len(inputs)]

                        i += 1

                self._edit_log(f"Sau lặp: ~{total:.2f}s, số đoạn: {len(seq)}")

                with open(concat_txt, "w", encoding="utf-8") as f:

                    for p in seq:

                        escaped_path = str(p).replace('\\', '/').replace("'", "'\\''")

                        f.write(f"file '{escaped_path}'\n")

            else:

                with open(concat_txt, "w", encoding="utf-8") as f:

                    for p in self.edit_video_paths:

                        escaped_path = str(p).replace('\\', '/').replace("'", "'\\''")

                        f.write(f"file '{escaped_path}'\n")



            # 2) Ghép video bằng copy codec

            concat_out = tmpdir / "concat.mp4"

            if use_repeat and mode in ("bgm", "mute"):

                # Lặp và chỉ dùng nhạc nền hoặc mute: bỏ audio gốc ngay từ bước concat

                cmd_concat = [

                    ffmpeg,

                    "-y",

                    "-f", "concat",

                    "-safe", "0",

                    "-i", str(concat_txt),

                    "-c:v", "copy",

                    "-an",

                    str(concat_out),

                ]

            else:

                cmd_concat = [

                    ffmpeg,

                    "-y",

                    "-f", "concat",

                    "-safe", "0",

                    "-i", str(concat_txt),

                    "-c:v", "copy",

                    "-c:a", "copy",

                    str(concat_out),

                ]

            self._edit_log("Đang ghép video (copy codec)...")

            proc = self._spawn_ffmpeg(cmd_concat)

            while True:

                if proc.poll() is not None:

                    break

                if not self.edit_processing:

                    with suppress(Exception):

                        proc.terminate()

                    self._finalize_edit(cancelled=True)

                    return

                _t.sleep(0.2)

            if not use_repeat and proc.returncode != 0 and self.var_normalize_audio.get():

                # 2b) Chuẩn hóa audio: re-encode audio của từng clip, copy video

                self._edit_log("Ghép copy thất bại. Đang chuẩn hóa audio từng clip...")

                normalized_files: List[Path] = []

                for i, p in enumerate(self.edit_video_paths):

                    norm_path = tmpdir / f"norm_{i:03d}.mp4"

                    cmd_norm = [

                        ffmpeg, "-y",

                        "-i", str(p),

                        "-c:v", "copy",

                        "-c:a", "aac",

                        "-b:a", "192k",

                        "-ar", "48000",

                        "-ac", "2",

                        str(norm_path),

                    ]

                    self._edit_log(f"Chuẩn hóa audio: {p.name}")

                    procn = self._spawn_ffmpeg(cmd_norm)

                    while True:

                        if procn.poll() is not None:

                            break

                        if not self.edit_processing:

                            with suppress(Exception):

                                procn.terminate()

                            self._finalize_edit(cancelled=True)

                            return

                        _t.sleep(0.2)

                    if procn.returncode != 0:

                        self._schedule(Messagebox.show_error, f"Chuẩn hóa audio thất bại: {p}")

                        self._finalize_edit()

                        return

                    normalized_files.append(norm_path)



                # Concat lại với danh sách mới

                concat_txt2 = tmpdir / "concat_norm.txt"

                with open(concat_txt2, "w", encoding="utf-8") as f2:

                    for npth in normalized_files:

                        escaped_npth = str(npth).replace('\\', '/').replace("'", "'\\''")

                        f2.write(f"file '{escaped_npth}'\n")

                cmd_concat2 = [

                    ffmpeg, "-y",

                    "-f", "concat",

                    "-safe", "0",

                    "-i", str(concat_txt2),

                    "-c:v", "copy",

                    "-c:a", "aac",

                    "-b:a", "192k",

                    str(concat_out),

                ]

                self._edit_log("Đang ghép lại sau khi chuẩn hóa audio...")

                proc2a = self._spawn_ffmpeg(cmd_concat2)

                while True:

                    if proc2a.poll() is not None:

                        break

                    if not self.edit_processing:

                        with suppress(Exception):

                            proc2a.terminate()

                        self._finalize_edit(cancelled=True)

                        return

                    _t.sleep(0.2)

                if proc2a.returncode != 0:

                    self._schedule(Messagebox.show_error, "Ghép video thất bại ngay cả sau khi chuẩn hóa audio.")

                    self._finalize_edit()

                    return



            # If repeat and target_seconds set, trim to exact duration with stream copy

            final_src = concat_out

            if use_repeat and target_seconds and target_seconds > 0:

                trim_out = tmpdir / "concat_trim.mp4"

                if mode in ("bgm", "mute"):

                    cmd_trim = [ffmpeg, "-y", "-i", str(concat_out), "-t", f"{target_seconds}", "-c:v", "copy", "-an", str(trim_out)]

                else:

                    cmd_trim = [ffmpeg, "-y", "-i", str(concat_out), "-t", f"{target_seconds}", "-c:v", "copy", "-c:a", "copy", str(trim_out)]

                self._edit_log("Cắt đúng thời lượng mục tiêu (copy video)...")

                proc_tr = self._spawn_ffmpeg(cmd_trim)

                while True:

                    if proc_tr.poll() is not None:

                        break

                    if not self.edit_processing:

                        with suppress(Exception):

                            proc_tr.terminate()

                        self._finalize_edit(cancelled=True)

                        return

                    _t.sleep(0.2)

                final_src = trim_out if proc_tr.returncode == 0 else concat_out

                # Verify duration and attempt precise container-level clamp without re-encode

                actual_d = self._probe_duration_seconds(str(final_src)) or 0.0

                if abs((target_seconds or 0) - actual_d) > 1.0:

                    self._edit_log("Độ dài sau cắt lệch >1.0s. Thực hiện cắt chính xác không mã hóa (remux)...")

                    trim_out_precise = tmpdir / "concat_trim_precise.mp4"

                    cmd_trim_re = [

                        ffmpeg, "-y",

                        "-i", str(concat_out),

                        "-to", f"{target_seconds}",

                        "-c", "copy",

                        "-copyts",

                        "-start_at_zero",

                        "-avoid_negative_ts", "make_zero",

                        "-shortest",

                        "-muxpreload", "0",

                        "-muxdelay", "0",

                        str(trim_out_precise),

                    ]

                    proc_tr2 = self._spawn_ffmpeg(cmd_trim_re)

                    while True:

                        if proc_tr2.poll() is not None:

                            break

                        if not self.edit_processing:

                            with suppress(Exception):

                                proc_tr2.terminate()

                            self._finalize_edit(cancelled=True)

                            return

                        _t.sleep(0.2)

                    if proc_tr2.returncode == 0:

                        final_src = trim_out_precise



            # 3) Xử lý âm thanh theo mode

            out_path = str(Path(out_path))

            # In repeat mode, allow mix if chosen; otherwise default bgm/mute behavior

            if use_repeat:

                if mode == "mix":

                    effective_mode = "mix"

                else:

                    effective_mode = "bgm" if bgm_path else "mute"

            else:

                effective_mode = mode



            if effective_mode == "mute":

                cmd = [ffmpeg, "-y", "-i", str(final_src), "-an", "-c:v", "copy", out_path]

            elif effective_mode == "bgm":

                if bgm_path:

                    # Match exact duration to bgm if repeating

                    cmd = [ffmpeg, "-y", "-i", str(final_src), "-i", bgm_path, "-map", "0:v:0", "-map", "1:a:0"]

                    if use_repeat and target_seconds and target_seconds > 0:

                        cmd += ["-t", f"{target_seconds}"]

                    else:

                        cmd += ["-shortest"]

                    cmd += ["-c:v", "copy", "-c:a", "copy", out_path]

                else:

                    cmd = [ffmpeg, "-y", "-i", str(final_src), "-an", "-c:v", "copy", out_path]

            else:  # mix -> mix original audio with bgm (audio re-encode allowed), video copy

                if bgm_path:

                    have_aud = self._has_audio_stream(str(final_src))

                    if have_aud:

                        vol = self.ent_bgm_volume.get().strip()

                        try:

                            vol_f = float(vol)

                        except Exception:

                            vol_f = 1.0

                        self._edit_log("Trộn tiếng gốc + nhạc nền (audio sẽ tái mã hóa AAC 192k)...")

                        filter_complex = f"[1:a]volume={vol_f}[bg];[0:a][bg]amix=inputs=2:duration=shortest:dropout_transition=0[aout]"

                        cmd = [

                            ffmpeg, "-y",

                            "-i", str(final_src),

                            "-i", bgm_path,

                            "-filter_complex", filter_complex,

                            "-map", "0:v:0",

                            "-map", "[aout]",

                            "-c:v", "copy",

                            "-c:a", "aac",

                            "-b:a", "192k",

                        ]

                    else:

                        # No original audio, just use bgm as audio (no mix needed)

                        cmd = [

                            ffmpeg, "-y",

                            "-i", str(final_src),

                            "-i", bgm_path,

                            "-map", "0:v:0",

                            "-map", "1:a:0",

                            "-c:v", "copy",

                            "-c:a", "copy",

                        ]

                    if use_repeat and target_seconds and target_seconds > 0:

                        cmd += ["-t", f"{target_seconds}"]

                    else:

                        cmd += ["-shortest"]

                    cmd += [out_path]

                else:

                    # No bgm provided, just keep original audio

                    cmd = [ffmpeg, "-y", "-i", str(final_src), "-c:v", "copy", "-c:a", "copy", out_path]



            self._edit_log("Đang xử lý âm thanh/xuất file...")

            proc2 = self._spawn_ffmpeg(cmd)

            while True:

                if proc2.poll() is not None:

                    break

                if not self.edit_processing:

                    with suppress(Exception):

                        proc2.terminate()

                    self._finalize_edit(cancelled=True)

                    return

                _t.sleep(0.2)

            if proc2.returncode != 0:

                self._schedule(Messagebox.show_error, "Xuất video thất bại.")

                self._finalize_edit()

                return



            self._schedule(Messagebox.show_info, f"Đã xuất video: {out_path}")

            try:

                os.startfile(out_path)

            except Exception:

                pass

            self._finalize_edit()

        except Exception as e:

            self._schedule(Messagebox.show_error, f"Lỗi Edit: {e}")

            self._finalize_edit()



    def _finalize_edit(self, cancelled: bool = False) -> None:

        self.edit_processing = False

        try:

            self.btn_edit_run.configure(state="normal")

            self.btn_edit_cancel.configure(state="disabled")

            if cancelled:

                self._edit_log("Đã hủy.")

            else:

                self._edit_log("Hoàn tất.")

        except Exception:

            pass



    # ----- Group Merge Methods -----

    def on_edit_choose_group_output(self) -> None:

        """Choose output folder for group merge."""

        folder = filedialog.askdirectory(title="Chọn thư mục xuất cho nhóm video")

        if folder:

            self.ent_group_output.delete(0, "end")

            self.ent_group_output.insert(0, folder)



    def on_edit_choose_group_audio(self) -> None:

        """Choose audio folder for group merge."""

        folder = filedialog.askdirectory(title="Chọn thư mục chứa file audio (.mp3)")

        if folder:

            self.ent_group_audio.delete(0, "end")

            self.ent_group_audio.insert(0, folder)



    def on_edit_rename_mp3_folder(self) -> None:

        """Rename all MP3 files in selected folder to merged_group_XXX.mp3 using natural numeric ordering."""

        try:

            audio_folder = self.ent_group_audio.get().strip()

            if not audio_folder or not os.path.exists(audio_folder):

                self._edit_log("⚠️ Vui lòng chọn thư mục audio hợp lệ.\n")

                return



            # Collect mp3 filenames

            mp3_files = [f for f in os.listdir(audio_folder) if f.lower().endswith('.mp3')]

            if not mp3_files:

                self._edit_log("⚠️ Không tìm thấy file .mp3 nào trong thư mục.\n")

                return



            # Natural sort key: splits into text/number parts so "9" < "10"

            def _nat_key(name: str):

                parts = re.split(r'(\d+)', name)

                return [int(p) if p.isdigit() else p.lower() for p in parts]



            mp3_files.sort(key=_nat_key)

            self._edit_log(f"📁 Tìm thấy {len(mp3_files)} file .mp3 trong thư mục.\n")



            # Rename safely using temporary names to avoid collisions

            temp_map = {}

            for i, old_name in enumerate(mp3_files, 1):

                old_path = Path(audio_folder) / old_name

                new_name = f"merged_group_{i:03d}.mp3"

                temp_path = old_path.with_name(f".tmp_rename_mp3_{i}.mp3")

                try:

                    old_path.rename(temp_path)

                    temp_map[temp_path] = Path(audio_folder) / new_name

                    self._edit_log(f"✅ {old_name} → {new_name} (queued)\n")

                except Exception as ex:

                    self._edit_log(f"⚠️ Không thể đổi tên tạm {old_name}: {ex}\n")



            # Finalize renaming

            renamed_count = 0

            for temp, final in temp_map.items():

                try:

                    if temp.exists():

                        temp.rename(final)

                        renamed_count += 1

                except Exception as ex:

                    self._edit_log(f"❌ Không thể đổi {temp.name} → {final.name}: {ex}\n")



            self._edit_log(f"🎉 Hoàn thành! Đã đổi tên {renamed_count} file.\n")



        except Exception as e:

            self._edit_log(f"❌ Lỗi rename MP3 folder: {e}\n")



    def on_edit_create_groups(self) -> None:

        """Create video groups based on group size."""

        try:

            if not self.edit_video_paths:

                self._edit_log("⚠️ Không có video nào để tạo nhóm.\n")

                return



            try:

                group_size_str = self.spn_group_size.get().strip()

                if not group_size_str:

                    group_size = 5  # Default value

                else:

                    group_size = int(group_size_str)

            except ValueError:

                self._edit_log("⚠️ Số video mỗi nhóm không hợp lệ, sử dụng giá trị mặc định: 5\n")

                group_size = 5



            if group_size < 2:

                self._edit_log("⚠️ Số video mỗi nhóm phải >= 2, sử dụng giá trị mặc định: 5\n")

                group_size = 5



            # Create groups

            self.group_video_groups = []

            for i in range(0, len(self.edit_video_paths), group_size):

                group = self.edit_video_paths[i:i + group_size]

                self.group_video_groups.append(group)



            total_groups = len(self.group_video_groups)

            self._edit_log(f"📁 Đã tạo {total_groups} nhóm video:\n")

            for i, group in enumerate(self.group_video_groups, 1):

                self._edit_log(f"  Nhóm {i}: {len(group)} video\n")



            self.lbl_group_status.configure(text=f"Đã tạo {total_groups} nhóm", foreground="blue")



        except Exception as e:

            self._edit_log(f"❌ Lỗi tạo nhóm: {e}\n")



    def on_edit_merge_groups(self) -> None:

        """Merge video groups into individual videos."""

        try:

            if not self.group_video_groups:

                self._edit_log("⚠️ Chưa tạo nhóm nào. Hãy nhấn 'Tạo nhóm' trước.\n")

                return



            output_folder = self.ent_group_output.get().strip()

            if not output_folder:

                self._edit_log("⚠️ Hãy chọn thư mục xuất.\n")

                return



            # Check audio folder if sync is enabled

            audio_folder = None

            if self.var_audio_sync.get():

                audio_folder_str = self.ent_group_audio.get().strip()

                if not audio_folder_str:

                    self._edit_log("⚠️ Hãy chọn thư mục audio để đồng bộ.\n")

                    return

                audio_folder = Path(audio_folder_str)

                if not audio_folder.exists():

                    self._edit_log("⚠️ Thư mục audio không tồn tại.\n")

                    return



            output_path = Path(output_folder)

            output_path.mkdir(parents=True, exist_ok=True)



            self.group_processing = True

            self.group_stop_event.clear()

            self.lbl_group_status.configure(text="Đang ghép nhóm...", foreground="orange")



            # Start merge worker

            threading.Thread(target=self._group_merge_worker, args=(output_path, audio_folder), daemon=True).start()



        except Exception as e:

            self._edit_log(f"❌ Lỗi bắt đầu ghép nhóm: {e}\n")



    def on_edit_stop_groups(self) -> None:

        """Stop group merge process."""

        self.group_stop_event.set()

        self.group_processing = False

        self.lbl_group_status.configure(text="Đã dừng", foreground="red")



    def on_edit_choose_groups_all_output(self) -> None:

        try:

            f = filedialog.asksaveasfilename(

                title="Chọn file xuất cho ghép tất cả nhóm",

                defaultextension=".mp4",

                filetypes=[("MP4", "*.mp4"), ("All", "*.*")]

            )

            if f:

                try:

                    self.ent_groups_all_output.delete(0, "end")

                    self.ent_groups_all_output.insert(0, f)

                except Exception:

                    pass

        except Exception as e:

            self._edit_log(f"Lỗi chọn file xuất: {e}\n")



    def on_edit_merge_all_groups(self) -> None:

        try:

            out_folder = self.ent_group_output.get().strip()

            if not out_folder:

                self._edit_log("⚠️ Hãy chọn thư mục xuất nhóm trước.\n")

                return

            final_path = self.ent_groups_all_output.get().strip()

            if not final_path:

                self._edit_log("⚠️ Hãy chọn file xuất cho ghép tất cả nhóm.\n")

                return

            ok = self._merge_all_groups_to_one(Path(out_folder), Path(final_path))

            if ok:

                self._edit_log(f"✅ Đã ghép tất cả nhóm → {final_path}\n")

            else:

                self._edit_log("❌ Lỗi ghép tất cả nhóm\n")

        except Exception as e:

            self._edit_log(f"❌ Lỗi bắt đầu ghép tất cả nhóm: {e}\n")



    def _merge_all_groups_to_one(self, groups_root: Path, final_output: Path) -> bool:

        """Concat all merged_group_*.mp4 under group_* folders into a single mp4 (copy mode)."""

        try:

            import tempfile

            import subprocess

            videos: List[Path] = []

            # Find group_* folders

            try:

                group_folders = sorted(

                    [p for p in Path(groups_root).iterdir() if p.is_dir() and p.name.lower().startswith("group_")],

                    key=lambda p: p.name.lower()

                )

            except Exception:

                group_folders = []

            for gf in group_folders:

                # Expected current naming

                num = gf.name.replace("group_", "")

                cand = gf / f"merged_group_{num}.mp4"

                if not cand.exists():

                    # Other potential naming fallbacks

                    cand_alt = gf / f"merged_{gf.name}.mp4"

                    if cand_alt.exists():

                        cand = cand_alt

                if cand.exists():

                    videos.append(cand)

            if not videos:

                self._edit_log("⚠️ Không tìm thấy file merged_group_*.mp4 trong các thư mục nhóm\n")

                return False

            # Create concat file

            with tempfile.NamedTemporaryFile(mode='w', suffix='.txt', delete=False, encoding='utf-8') as f:

                concat_file = f.name

                for v in videos:

                    escaped = str(v).replace('\\', '/').replace("'", "'\\''")

                    f.write(f"file '{escaped}'\n")

            ffmpeg_cmd = [

                "ffmpeg", "-y",

                "-f", "concat", "-safe", "0",

                "-i", concat_file,

                "-c", "copy",

                str(final_output)

            ]

            # Run ffmpeg using _spawn_ffmpeg to hide console

            proc = self._spawn_ffmpeg(ffmpeg_cmd)



            # Wait for completion with timeout

            try:

                stdout, stderr = proc.communicate(timeout=600)

                success = proc.returncode == 0

            except subprocess.TimeoutExpired:

                proc.kill()

                self._edit_log("FFmpeg merge-all timeout\n")

                success = False

                stderr = "Timeout"



            try:

                Path(concat_file).unlink()

            except Exception:

                pass



            if success:

                # Thông báo khi ghép xong tất cả thành 1 video

                self._edit_log(f"🎉 Đã ghép tất cả {len(videos)} nhóm thành 1 video: {final_output.name}\n")

                self._edit_log(f"📁 Đường dẫn: {final_output}\n")

                return True

            self._edit_log(f"FFmpeg error (merge-all): {stderr}\n")

            return False

        except Exception as e:

            self._edit_log(f"Lỗi ghép tất cả nhóm: {e}\n")

            return False



    def _group_merge_worker(self, output_path: Path, audio_folder: Optional[Path] = None) -> None:

        """Worker thread for merging video groups."""

        try:

            total_groups = len(self.group_video_groups)

            self._edit_log(f"🎬 Bắt đầu ghép {total_groups} nhóm video...\n")



            for group_idx, group in enumerate(self.group_video_groups, 1):

                if self.group_stop_event.is_set():

                    self._edit_log("⏹️ Đã dừng ghép nhóm.\n")

                    break



                self._edit_log(f"📁 Đang ghép nhóm {group_idx}/{total_groups} ({len(group)} video)...\n")



                # Create group folder

                group_folder = output_path / f"group_{group_idx:03d}"

                group_folder.mkdir(exist_ok=True)



                # Merge videos in this group

                output_file = group_folder / f"merged_group_{group_idx:03d}.mp4"

                success = self._merge_video_group(group, output_file)



                if success:

                    # Check if we need to sync with audio

                    if audio_folder and self.var_audio_sync.get():

                        audio_file = audio_folder / f"merged_group_{group_idx:03d}.mp3"

                        if audio_file.exists():

                            self._edit_log(f"🎵 Đang đồng bộ với audio: {audio_file.name}\n")

                            final_file = group_folder / f"final_group_{group_idx:03d}.mp4"

                            sync_success = self._sync_video_with_audio(output_file, audio_file, final_file)

                            if sync_success:

                                # Kiểm tra thời lượng sau khi đồng bộ

                                final_duration = self._probe_duration_seconds(str(final_file))

                                audio_duration = self._probe_duration_seconds(str(audio_file))

                                if final_duration and audio_duration:

                                    duration_diff = abs(final_duration - audio_duration)

                                    if duration_diff < 1.0:  # Chênh lệch < 1 giây

                                        # Replace original with synced version

                                        output_file.unlink()

                                        final_file.rename(output_file)

                                        self._edit_log(f"✅ Hoàn thành nhóm {group_idx} (đã đồng bộ): {output_file.name} ({final_duration:.1f}s)\n")

                                    else:

                                        self._edit_log(f"⚠️ Thời lượng không khớp sau đồng bộ: video={final_duration:.1f}s, audio={audio_duration:.1f}s\n")

                                        # Vẫn thay thế nhưng cảnh báo

                                        output_file.unlink()

                                        final_file.rename(output_file)

                                        self._edit_log(f"✅ Hoàn thành nhóm {group_idx} (đã đồng bộ với cảnh báo): {output_file.name}\n")

                                else:

                                    # Không kiểm tra được thời lượng, vẫn thay thế

                                    output_file.unlink()

                                    final_file.rename(output_file)

                                    self._edit_log(f"✅ Hoàn thành nhóm {group_idx} (đã đồng bộ): {output_file.name}\n")

                            else:

                                self._edit_log(f"⚠️ Lỗi đồng bộ nhóm {group_idx}, giữ video gốc\n")

                        else:

                            self._edit_log(f"⚠️ Không tìm thấy audio cho nhóm {group_idx}: {audio_file.name}\n")

                            self._edit_log(f"✅ Hoàn thành nhóm {group_idx}: {output_file.name}\n")

                    else:

                        self._edit_log(f"✅ Hoàn thành nhóm {group_idx}: {output_file.name}\n")

                else:

                    self._edit_log(f"❌ Lỗi ghép nhóm {group_idx}\n")



            if not self.group_stop_event.is_set():

                self._edit_log(f"🎉 Hoàn thành ghép tất cả {total_groups} nhóm!\n")

                self.lbl_group_status.configure(text="Hoàn thành", foreground="green")

                # Auto-merge all groups to one file if enabled

                try:

                    if getattr(self, "var_merge_all_after", None) and self.var_merge_all_after.get():

                        self._edit_log("🧩 Đang ghép tất cả nhóm thành 1 video...\n")

                        final_out_str = self.ent_groups_all_output.get().strip()

                        if final_out_str:

                            final_out = Path(final_out_str)

                            ok = self._merge_all_groups_to_one(output_path, final_out)

                            if ok:

                                self._edit_log(f"✅ Hoàn thành ghép tất cả nhóm → {final_out}\n")

                            else:

                                self._edit_log("⚠️ Lỗi khi ghép tất cả nhóm\n")

                        else:

                            self._edit_log("⚠️ Chưa chọn file xuất cho ghép tất cả nhóm\n")

                except Exception as ie:

                    self._edit_log(f"⚠️ Lỗi merge-all sau khi xong nhóm: {ie}\n")

            else:

                self.lbl_group_status.configure(text="Đã dừng", foreground="red")



        except Exception as e:

            self._edit_log(f"❌ Lỗi worker ghép nhóm: {e}\n")

            self.lbl_group_status.configure(text="Lỗi", foreground="red")

        finally:

            self.group_processing = False



    def _merge_video_group(self, video_group: List[Path], output_file: Path) -> bool:

        """Merge a group of videos into one file."""

        try:

            import tempfile

            import subprocess



            # Create temporary concat file

            with tempfile.NamedTemporaryFile(mode='w', suffix='.txt', delete=False, encoding='utf-8') as f:

                concat_file = f.name

                for video_path in video_group:

                    # Escape path for ffmpeg

                    escaped_path = str(video_path).replace('\\', '/').replace("'", "'\\''")

                    f.write(f"file '{escaped_path}'\n")



            # FFmpeg command to merge videos

            ffmpeg_cmd = [

                "ffmpeg", "-y",

                "-f", "concat",

                "-safe", "0",

                "-i", concat_file,

                "-c", "copy",  # Copy streams without re-encoding

                str(output_file)

            ]



            # Run ffmpeg

            # Run ffmpeg using _spawn_ffmpeg to hide console

            proc = self._spawn_ffmpeg(ffmpeg_cmd)



            # Wait for completion with timeout

            try:

                stdout, stderr = proc.communicate(timeout=300)

                success = proc.returncode == 0

            except subprocess.TimeoutExpired:

                proc.kill()

                self._edit_log("FFmpeg merge timeout\n")

                success = False

                stderr = "Timeout"



            # Clean up temp file

            try:

                Path(concat_file).unlink()

            except:

                pass



            if success:

                return True

            else:

                self._edit_log(f"FFmpeg error: {stderr}\n")

                return False



        except Exception as e:

            self._edit_log(f"Lỗi ghép video: {e}\n")

            return False



    def _sync_video_with_audio(self, video_file: Path, audio_file: Path, output_file: Path) -> bool:

        """Sync video duration with audio duration using slow motion if needed."""

        try:

            import subprocess



            # Get video duration

            video_duration = self._probe_duration_seconds(str(video_file))

            if not video_duration:

                self._edit_log(f"Không thể lấy thời lượng video: {video_file}\n")

                return False



            # Get audio duration

            audio_duration = self._probe_duration_seconds(str(audio_file))

            if not audio_duration:

                self._edit_log(f"Không thể lấy thời lượng audio: {audio_file}\n")

                return False



            self._edit_log(f"📊 Video: {video_duration:.2f}s, Audio: {audio_duration:.2f}s\n")



            # Calculate speed factor

            speed_factor = video_duration / audio_duration



            if abs(speed_factor - 1.0) < 0.01:

                # Durations are almost equal, just copy video and replace audio

                self._edit_log("🎵 Thời lượng gần bằng nhau, chỉ thay thế audio\n")

                ffmpeg_cmd = [

                    "ffmpeg", "-y",

                    "-i", str(video_file),

                    "-i", str(audio_file),

                    "-c:v", "copy",  # Copy video stream

                    "-c:a", "aac",   # Re-encode audio

                    "-map", "0:v:0", # Use video from first input

                    "-map", "1:a:0", # Use audio from second input

                    "-shortest",     # End when shortest stream ends

                    str(output_file)

                ]

            else:

                # Need to adjust video speed

                if speed_factor > 1.0:

                    # Video is longer, need to speed up (speed_factor > 1)

                    actual_speed = 1.0 / speed_factor

                    self._edit_log(f"⚡ Tăng tốc video: {actual_speed:.3f}x\n")

                else:

                    # Video is shorter, need to slow down (speed_factor < 1)

                    actual_speed = 1.0 / speed_factor

                    self._edit_log(f"🐌 Slow motion video: {actual_speed:.3f}x (kéo dài từ {video_duration:.1f}s → {audio_duration:.1f}s)\n")



                # For video speed change, we only need to adjust video speed

                # Audio will be replaced with the new audio file

                video_pts = 1.0 / speed_factor



                ffmpeg_cmd = [

                    "ffmpeg", "-y",

                    "-i", str(video_file),

                    "-i", str(audio_file),

                    "-filter_complex", f"[0:v]setpts={video_pts}*PTS[v]",

                    "-map", "[v]",

                    "-map", "1:a:0",  # Use audio from second input

                    "-c:v", "libx264",  # Re-encode video for speed change

                    "-c:a", "aac",      # Re-encode audio

                    "-t", str(audio_duration),  # Kết thúc theo độ dài audio

                    str(output_file)

                ]



            # Run ffmpeg using _spawn_ffmpeg to hide console

            proc = self._spawn_ffmpeg(ffmpeg_cmd)



            # Wait for completion with timeout

            try:

                stdout, stderr = proc.communicate(timeout=600)

                if proc.returncode == 0:

                    return True

                else:

                    self._edit_log(f"FFmpeg sync error: {stderr}\n")

                    return False

            except subprocess.TimeoutExpired:

                proc.kill()

                self._edit_log("FFmpeg sync timeout\n")

                return False



        except Exception as e:

            self._edit_log(f"Lỗi đồng bộ video-audio: {e}\n")

            return False





