    def on_choose_extend_prompt_folder(self) -> None:

        d = filedialog.askdirectory(title="Chọn thư mục chứa prompt (.txt)")

        if d:

            # Update new Extend Text-to-Video input field

            try:

                if hasattr(self, 'ent_extend_txt_folder'):

                    self.ent_extend_txt_folder.delete(0, "end")

                    self.ent_extend_txt_folder.insert(0, d)

                elif hasattr(self, 'ent_extend_prompt_folder'):

                    # Backward compatibility

                    self.ent_extend_prompt_folder.delete(0, "end")

                    self.ent_extend_prompt_folder.insert(0, d)

            except Exception:

                pass



            # Populate table with .txt files in the selected folder (no logging)

            try:

                # Clear current rows

                if hasattr(self, 'lst_extend_tasks') and self.lst_extend_tasks is not None:

                    for item in self.lst_extend_tasks.get_children():

                        self.lst_extend_tasks.delete(item)



                    from pathlib import Path as _P

                    txt_files = sorted(_P(d).glob("*.txt"))

                    for p in txt_files:

                        preview = ""

                        try:

                            first_line = p.read_text(encoding="utf-8", errors="ignore").splitlines()

                            if first_line:

                                preview = first_line[0][:100]

                        except Exception:

                            preview = ""

                        # Insert: File name, Preview, empty status/progress

                        self.lst_extend_tasks.insert("", "end", values=(p.name, preview, "", ""))

            except Exception:

                pass



