    def _retry_project_from_failed_segment(self, project_data) -> None:

        """Retry project từ segment bị lỗi đầu tiên"""

        try:

            self._log(f"🔄 Bắt đầu retry project: {project_data.project_name}\n")

            

            # Find first segment that needs retry (error or pending)

            retry_segment = None

            retry_index = -1

            

            # First, look for segments with error status

            for i, segment in enumerate(project_data.segments):

                if segment.status == "error":

                    retry_segment = segment

                    retry_index = i

                    self._log(f"🔄 Tìm thấy segment lỗi #{segment.index}: {segment.text[:50]}...\n")

                    break

            

            # If no error segments, look for pending segments

            if retry_segment is None:

                for i, segment in enumerate(project_data.segments):

                    if segment.status == "pending":

                        retry_segment = segment

                        retry_index = i

                        self._log(f"🔄 Tìm thấy segment pending #{segment.index}: {segment.text[:50]}...\n")

                        break

            

            # If still no segments to retry, check if project needs concat

            if retry_segment is None:

                if project_data.status != "completed":

                    self._log(f"🔗 Tất cả segments hoàn thành, retry concat...\n")

                    retry_index = len(project_data.segments) - 1  # Start from last segment for concat

                else:

                    self._log(f"✅ Project đã hoàn thành, không cần retry\n")

                    return

            else:

                self._log(f"🔄 Retry từ segment #{retry_segment.index}: {retry_segment.text[:50]}...\n")

            

            # Reset status of retry segment and all subsequent segments

            failed_index = retry_index

            for i in range(failed_index, len(project_data.segments)):

                seg = project_data.segments[i]

                seg.status = "pending"

                seg.error_message = ""

                seg.media_id = None

                seg.video_url = None

            

            # Reset project status

            project_data.status = "pending"

            project_data.concat_url = None

            

            self._log(f"🔄 Đã reset project status và {len(project_data.segments) - failed_index} segments\n")

            self._log(f"📊 Project status: {project_data.status}\n")

            self._log(f"📊 Segments status: {[f'#{s.index}:{s.status}' for s in project_data.segments]}\n")

            

            # Update UI

            self._update_project_table_row(project_data)

            

            # Start retry in background

            cookies = self._get_cookies_source()

            if not cookies:

                Messagebox.show_error("Vui lòng nhập Cookie ở tab Video!")

                return

            

            threading.Thread(

                target=self._retry_single_project,

                args=(project_data, cookies, failed_index),

                daemon=True

            ).start()

            

        except Exception as e:

            self._log(f"❌ Lỗi retry project: {e}\n")

    

    def _retry_single_project(self, project_data, cookies: str, start_segment_index: int) -> None:

        """Retry một project từ segment index cụ thể"""

        try:

            self._log(f"🚀 Bắt đầu _retry_single_project: {project_data.project_name}, start_segment: {start_segment_index}\n")

            from extend_videos import ExtendVideoProcessor

            

            # Build client

            client = self._build_client(cookies)

            if not client or not client.fetch_access_token():

                self._log("❌ Không thể tạo client hoặc lấy token cho retry\n")

                return

            

            # Create processor

            processor = ExtendVideoProcessor(client, log_callback=self._log)

            

            # Get output directory from UI

            output_dir_str = self.ent_extend_output_folder.get().strip()

            if not output_dir_str:

                output_dir_str = str(Path.home() / "Downloads" / "Extended_Videos")

            

            # Get txt filename

            txt_file = self.ent_extend_txt_file.get().strip()

            

            # Status callback

            def status_callback(global_idx: int, status: str, message: str):

                try:

                    self._schedule(self._update_project_table_row, project_data)

                except Exception:

                    pass

            

            # Process project with retry from failed segment

            self._log(f"🔄 Gọi process_project_with_retry với start_from_segment={start_segment_index}\n")

            success = processor.process_project_with_retry(

                project=project_data,

                output_dir=output_dir_str,

                txt_filename=txt_file,

                start_from_segment=start_segment_index,

                status_callback=status_callback

            )

            self._log(f"📊 Kết quả process_project_with_retry: {success}\n")

            

            if success:

                self._log(f"✅ Retry project {project_data.project_name} thành công!\n")

            else:

                self._log(f"❌ Retry project {project_data.project_name} thất bại!\n")

            

            # Update UI

            self._schedule(self._update_project_table_row, project_data)

            

        except Exception as e:

            self._log(f"❌ Lỗi retry single project: {e}\n")

            import traceback

            self._log(f"🔍 Traceback: {traceback.format_exc()}\n")

    

    def _retry_project_from_modal(self, dialog, project_data) -> None:

        """Retry project từ modal dialog"""

        dialog.destroy()

        self._retry_project_from_failed_segment(project_data)



