    def on_run_multi_profile_video(self) -> None:

        """Run video generation for multiple selected profiles concurrently."""

        sel = self.lst_profiles.selection()

        if not sel:

            Messagebox.show_error("Chọn ít nhất 1 profile trong danh sách.")

            return



        if len(sel) > 5:

            if not Messagebox.yesno("Bạn đã chọn {} profile. Chạy quá nhiều profile cùng lúc có thể gây quá tải. Tiếp tục?".format(len(sel))):

                return



        # Check if already running

        if self.executor is not None:

            Messagebox.show_info("Đang chạy, vui lòng dừng trước khi chạy tiếp.")

            return



        self._log(f"\n🚀 Bắt đầu chạy video cho {len(sel)} profile đồng thời...\n")



        # Collect profile data

        profiles_to_run = []

        for iid in sel:

            vals = self.lst_profiles.item(iid, "values")

            if not vals or len(vals) < 3:

                continue



            profile_path = Path(vals[2])

            try:

                data = json.loads(profile_path.read_text(encoding="utf-8"))

                prof_name = data.get("name", profile_path.stem)

                prof_dir = self._app_root() / "workflow" / self._sanitize_name(prof_name)



                # Check if gemini_prompt.txt exists

                gemini_file = prof_dir / "gemini_prompt.txt"

                if not gemini_file.exists():

                    self._log(f"⚠️ Profile {prof_name}: Chưa có file gemini_prompt.txt. Bỏ qua.\n")

                    continue



                profiles_to_run.append({

                    "name": prof_name,

                    "dir": prof_dir,

                    "cookies": data.get("cookies", ""),

                    "data": data

                })

            except Exception as e:

                self._log(f"⚠️ Lỗi đọc profile {vals[0]}: {e}\n")



        if not profiles_to_run:

            self._log("❌ Không có profile nào sẵn sàng để chạy.\n")

            return



        # Start multi-profile execution

        self._set_controls_state("disabled")

        self.stop_event.clear()



        # Use thread pool for concurrent execution (cap to 3 for all tasks)

        max_workers = min(len(profiles_to_run), 3)

        self.executor = ThreadPoolExecutor(max_workers=max_workers)



        # Clear status table

        for item in self.tree.get_children():

            self.tree.delete(item)



        # Run profiles concurrently

        threading.Thread(target=self._run_multi_profile_worker, args=(profiles_to_run,), daemon=True).start()



    def _run_multi_profile_worker(self, profiles: List[Dict[str, Any]]) -> None:

        """Worker thread to run multiple profiles concurrently."""

        futures = []



        for profile in profiles:

            if self.stop_event.is_set():

                break



            future = self.executor.submit(self._run_single_profile_video, profile)

            futures.append((profile["name"], future))



        # Wait for all to complete

        for prof_name, future in futures:

            try:

                future.result()

                self._log(f"✅ Profile {prof_name} hoàn thành.\n")

            except Exception as e:

                self._log(f"❌ Profile {prof_name} lỗi: {e}\n")



        self._finish_run()



    def _run_single_profile_video(self, profile: Dict[str, Any]) -> None:

        """Run video generation for a single profile."""

        prof_name = profile["name"]

        prof_dir = profile["dir"]

        cookies = profile["cookies"]



        self._log(f"\n📁 [Profile: {prof_name}] Bắt đầu xử lý...\n")



        # Parse gemini_prompt.txt

        gemini_file = prof_dir / "gemini_prompt.txt"

        try:

            content = gemini_file.read_text(encoding="utf-8").strip()

            prompts = []

            for line in content.splitlines():

                line = line.strip()

                if line and not line.startswith("#"):

                    prompts.append(line)



            if not prompts:

                self._log(f"[{prof_name}] Không có prompt trong file.\n")

                return



            self._log(f"[{prof_name}] Tìm thấy {len(prompts)} prompt.\n")



            # Create tasks

            tasks = [PromptTask(prompt_text=p, prompt_index=i+1) for i, p in enumerate(prompts)]



            # Process each prompt (always sequential for a single profile)

            for task in tasks:

                if self.stop_event.is_set():

                    break



                # Use profile-specific cookies

                self._process_single_prompt_with_cookies(task, cookies, prof_name)



        except Exception as e:

            self._log(f"[{prof_name}] Lỗi: {e}\n")



    def _process_single_prompt_with_cookies(self, task: PromptTask, cookies: str, profile_name: str) -> None:

        """Process a single prompt with specific cookies."""

        # Similar to _process_single_prompt but with custom cookies

        prompt = task.prompt_text



        if not cookies:

            self._log(f"[{profile_name}] Thiếu Cookie.\n")

            return



        # Parse cookies

        parsed_cookies = _parse_cookie_string(cookies)

        if not parsed_cookies:

            self._log(f"[{profile_name}] Cookie không hợp lệ.\n")

            return



        client = LabsFlowClient(cookies=parsed_cookies, gui_logger=self.gui_logger)



        # Continue with same logic as _process_single_prompt

        # but prefix logs with profile name

        # GIỮ NGUYÊN model key người dùng chọn

        model_key = self.cmb_model.get().strip() or "veo_3_1_t2v_fast_ultra"

        tool = self.ent_tool.get().strip() or "PINHOLE"

        tier = self.cmb_tier.get().strip() or "PAYGATE_TIER_TWO"

        num_videos = int(self.spn_num_videos.get())

        max_wait = int(self.spn_max_wait.get())

        poll_interval = int(self.spn_poll.get())



        self._log(f"\n[{profile_name}] Prompt #{task.prompt_index}: {prompt}\n")

        self._log(f"🎯 Model: {model_key} (CHÍNH XÁC như người dùng chọn)\n")



        try:

            # Reuse existing logic but with profile context

            if not client.fetch_access_token():

                self._log(f"[{profile_name}] Lấy access token thất bại.\n")

                return



            if not client.set_video_model_key(model_key):

                self._log(f"[{profile_name}] Thiết lập model thất bại.\n")

                return



            if not client.submit_batch_log(tool):

                self._log(f"[{profile_name}] Gửi batch log thất bại.\n")

                return



            # Generate with unique project ID per profile

            import uuid as _uuid

            project = f"{profile_name}_{_uuid.uuid4()}"



            operations = client.generate_videos(

                project_id=project,

                tool=tool,

                user_tier=tier,

                prompt=prompt,

                model_key=model_key,

                num_videos=num_videos,

                aspect_ratio=self._selected_video_aspect(),

                fixed_seed=self._get_fixed_seed(),

            )



            if not operations:

                self._log(f"[{profile_name}] Bắt đầu tạo video thất bại.\n")

                return



            # Update UI with profile prefix

            modified_task = PromptTask(

                prompt_text=f"[{profile_name}] {prompt}",

                prompt_index=task.prompt_index

            )

            self._schedule(self._init_operations_rows_ui, modified_task, operations)



            # Poll for status

            deadline = _t.time() + max_wait

            last_status = None



            while _t.time() < deadline:

                status = client.check_video_status(operations)

                if status is not None:

                    last_status = status

                    self._log(f"[{profile_name}] " + _safe_json(status) + "\n")

                    self._schedule(self._update_operations_rows_ui, modified_task, status)



                    # Check completion

                    if isinstance(status, dict) and "operations" in status:

                        total = len(status["operations"]) or len(operations)

                        done = failed = 0

                        for op in status["operations"]:

                            s = str(op.get("status", "")).upper()

                            if "COMPLETE" in s or "SUCCESS" in s:

                                done += 1

                            elif "FAIL" in s or "ERROR" in s:

                                failed += 1

                            elif "ACTIVE" in s or "RUNNING" in s:

                                active += 1



                        # Extend deadline if videos are still actively processing

                        if active > 0 and _t.time() > deadline - 30:  # Less than 30s left

                            deadline += 60  # Extend by 1 minute

                            self._log(f"⏰ Video vẫn đang xử lý, gia hạn thêm 60s...\n")



                        if done + failed >= total:

                            self._log(f"[{profile_name}] Hoàn thành.\n")

                            break



                if self.stop_event.is_set():

                    break

                _t.sleep(poll_interval)



            # Queue downloads with profile-specific directory

            if last_status:

                out_dir = Path(self.ent_output.get() or "downloaded_videos") / profile_name

                self._enqueue_downloads_from_status_with_dir(modified_task, last_status, out_dir)



        except Exception as e:

            self._log(f"[{profile_name}] Lỗi: {e}\n")



    def _enqueue_downloads_from_status_with_dir(self, task: PromptTask, status: Dict[str, Any], out_dir: Path) -> None:

        """Enqueue downloads with custom output directory."""

        # Similar to _enqueue_downloads_from_status but with custom out_dir

        urls = _extract_file_urls(status)

        if not urls:

            return



        out_dir.mkdir(parents=True, exist_ok=True)

        downloads_dir = Path.cwd() / "downloads"

        method = self.cmb_download_method.get()



        for idx, url in enumerate(urls, 1):

            if self.stop_event.is_set():

                break



            safe_prompt = "".join(ch for ch in task.prompt_text[:40] if ch.isalnum() or ch in (" ", "-", "_"))

            safe_prompt = safe_prompt.strip().replace(" ", "_") or f"prompt_{task.prompt_index}"

            filename = out_dir / f"{safe_prompt}_{idx}"

            filename = self._ensure_unique_filename(filename)



            self._log(f"📋 Xếp hàng tải: {url} → {filename.name}\n")

            self.download_queue.put(DownloadTask(url=url, target_path=filename, method=method, downloads_dir=downloads_dir))






    def _run_profile_video_worker(self, prof_name: str, prof_dir: Path, cookies: str) -> None:

        """Worker for profile video generation using separate table."""

        try:

            # Initialize separate executor for profiles

            self.profile_video_executor = ThreadPoolExecutor(max_workers=1)



            # Parse chatgpt_prompt.txt (format mới)

            prompts = []

            gemini_file = prof_dir / "chatgpt_prompt.txt"

            if not gemini_file.exists():

                # Fallback to old format

                gemini_file = prof_dir / "gemini_prompt.txt"



            for line in gemini_file.read_text(encoding="utf-8").splitlines():

                line = line.strip()

                if line and not line.startswith("#"):

                    try:

                        # Parse JSON line

                        import json as _json

                        obj = _json.loads(line)

                        scene_id = obj.get("scene_id")

                        for idx, sh in enumerate(obj.get("shots") or [], 1):

                            shot_prompt = sh.get("prompt") or ""

                            if shot_prompt:

                                # Rút ngắn prompt - bỏ timeline chi tiết để tránh quá dài

                                clean_prompt = shot_prompt

                                if "Seconds 0-3:" in clean_prompt:

                                    clean_prompt = clean_prompt.split("Seconds 0-3:")[0].strip()

                                # Giới hạn độ dài prompt

                                if len(clean_prompt) > 300:

                                    clean_prompt = clean_prompt[:300] + "..."

                                prompts.append(f"[Scene {scene_id} - Shot {idx}] {clean_prompt}")

                    except Exception:

                        # Fallback: treat as plain text

                        prompts.append(line)



            # Debug: Check if prompts contain IDs

            self._log(f"🔍 [Profile Video] Đọc được {len(prompts)} prompts từ file\n")

            for i, prompt in enumerate(prompts[:2], 1):

                if "_ID" in prompt:

                    self._log(f"🔍 [Profile Video] Prompt {i} chứa IDs: {prompt[:100]}...\n")

                else:

                    self._log(f"🔍 [Profile Video] Prompt {i} KHÔNG chứa IDs: {prompt[:100]}...\n")



            # Nếu prompts chứa IDs và có siêu đồng bộ, thực hiện replace

            if any("_ID" in p for p in prompts) and self.var_enable_char_sync.get():

                self._log("🔄 [Profile Video] Phát hiện IDs trong prompts, thực hiện replace...\n")



                # Đọc character descriptions từ file

                char_file = prof_dir / "character.txt"

                if not char_file.exists():

                    # Fallback to old format

                    char_file = prof_dir / "characters.txt"

                if char_file.exists():

                    character_descriptions = char_file.read_text(encoding="utf-8")

                    self._log(f"📖 [Profile Video] Đọc character descriptions từ file ({len(character_descriptions)} ký tự)\n")

                    self._log(f"📖 [Profile Video] Character file content preview: {character_descriptions[:200]}...\n")



                    # Debug: Ghi toàn bộ character descriptions ra file để kiểm tra

                    debug_file = prof_dir / "debug_characters.txt"

                    with open(debug_file, "w", encoding="utf-8") as f:

                        f.write("=== CHARACTER DESCRIPTIONS DEBUG ===\n")

                        f.write(character_descriptions)

                        f.write("\n=== END DEBUG ===\n")

                    self._log(f"🔍 [Debug] Đã ghi character descriptions ra {debug_file}\n")



                    # Replace IDs trong tất cả prompts

                    enhanced_prompts = []

                    for i, prompt in enumerate(prompts, 1):

                        self._log(f"🔍 [Profile Video] Prompt {i} trước replace: {prompt[:100] if prompt else 'None'}...\n")

                        enhanced = self._replace_ids_with_descriptions(prompt, character_descriptions)



                        # Ensure enhanced is not None

                        if enhanced is None:

                            enhanced = prompt or ""



                        enhanced_prompts.append(enhanced)

                        if enhanced != prompt:

                            self._log(f"🔄 [Profile Video] Đã replace prompt {i}\n")

                            self._log(f"🔍 [Profile Video] Prompt {i} sau replace: {enhanced[:100] if enhanced else 'None'}...\n")

                        else:

                            self._log(f"❌ [Profile Video] Không replace được prompt {i}\n")



                    prompts = enhanced_prompts

                    self._log(f"✅ [Profile Video] Đã replace IDs trong {len(prompts)} prompts\n")

                else:

                    self._log("❌ [Profile Video] Không tìm thấy file characters.txt\n")



            if not prompts:

                self._log(f"[{prof_name}] Không có prompt để chạy.\n")

                return



            self._log(f"[{prof_name}] Bắt đầu tạo {len(prompts)} video...\n")



            # Process each prompt SEQUENTIALLY (wait for each to complete)

            for i, prompt in enumerate(prompts, 1):

                if self.stop_event.is_set():

                    break



                # Add row to profile main status table (prof_tree)

                safe_prompt = prompt if prompt is not None else ""

                task = PromptTask(prompt_text=f"[{prof_name}] {safe_prompt}", prompt_index=i)

                iid = f"prof_vid:{prof_name}:{i}"



                # Add to prof_tree

                self._schedule(self._add_prof_tree_row, iid, task, "Đang chờ")



                # Process prompt and WAIT for completion (sequential)

                self._process_profile_prompt_for_main_table(prof_name, prompt, i, cookies, iid, task)



                # Add delay between prompts to avoid 500 errors

                if i < len(prompts) and not self.stop_event.is_set():

                    delay = self.profile_settings["delay_between_prompts"]

                    self._log(f"[{prof_name}] Chờ {delay}s trước prompt tiếp theo...\n")

                    for _ in range(delay):

                        if self.stop_event.is_set():

                            break

                        _t.sleep(1)



        except Exception as e:

            self._log(f"[{prof_name}] Lỗi tổng: {e}\n")

        finally:

            # Cleanup

            if hasattr(self, 'profile_video_executor') and self.profile_video_executor:

                self.profile_video_executor.shutdown(wait=False, cancel_futures=True)

                self.profile_video_executor = None



            # Re-enable controls

            self._schedule(lambda: self.btn_profile_start.configure(state="normal"))

            self._schedule(lambda: self.btn_profile_stop.configure(state="disabled"))



    # Profile video table functions removed per request



    def _process_profile_prompt(self, prof_name: str, prompt: str, index: int, cookies: str, iid: str) -> None:

        """Process single prompt for profile video generation using Profile settings."""

        try:

            # Parse cookies and create client

            parsed_cookies = _parse_cookie_string(cookies)

            if not parsed_cookies:

                self._schedule(self._update_profile_video_row, iid, "Lỗi Cookie")

                return



            client = self._build_client(cookies)

            if client is None:

                self._schedule(self._update_profile_video_row, iid, "Lỗi Client")

                return



            # Update status

            self._schedule(self._update_profile_video_row, iid, "Đang xử lý")



            # Use settings from Video tab (synced)

            self._sync_video_settings_to_profile()

            # GIỮ NGUYÊN model key người dùng chọn

            model_key = self.cmb_model.get().strip() or "veo_3_1_t2v_fast_ultra"

            tool = self.ent_tool.get().strip() or "PINHOLE"

            tier = self.cmb_tier.get().strip() or "PAYGATE_TIER_TWO"

            num_videos = int(self.spn_num_videos.get())

            max_wait = int(self.spn_max_wait.get())

            poll_interval = int(self.spn_poll.get())



            # Generate video (same logic as _process_single_prompt)

            if not client.fetch_access_token():

                self._schedule(self._update_profile_video_row, iid, "Lỗi Token")

                return



            if not client.set_video_model_key(model_key):

                self._schedule(self._update_profile_video_row, iid, "Lỗi Model")

                return



            if not client.submit_batch_log(tool):

                self._schedule(self._update_profile_video_row, iid, "Lỗi Log")

                return



            # Generate with profile-specific project ID

            import uuid as _uuid

            project = f"{prof_name}_{_uuid.uuid4()}"



            operations = client.generate_videos(

                project_id=project,

                tool=tool,

                user_tier=tier,

                prompt=prompt,

                model_key=model_key,

                num_videos=num_videos,

                aspect_ratio=self._selected_video_aspect(),

                fixed_seed=self._get_fixed_seed(),

            )



            if not operations:

                self._schedule(self._update_profile_video_row, iid, "Lỗi Generate")

                return



            # Poll for completion using Profile settings (already loaded above)

            deadline = _t.time() + max_wait



            while _t.time() < deadline:

                if self.stop_event.is_set():

                    self._schedule(self._update_profile_video_row, iid, "Đã dừng")

                    return



                status = client.check_video_status(operations)

                if status and isinstance(status, dict) and "operations" in status:

                    # Check completion

                    total = len(status["operations"])

                    done = failed = 0

                    for op in status["operations"]:

                        s = str(op.get("status", "")).upper()

                        if "COMPLETE" in s or "SUCCESS" in s:

                            done += 1

                        elif "FAIL" in s or "ERROR" in s:

                            failed += 1



                    if done + failed >= total:

                        if done > 0:

                            self._schedule(self._update_profile_video_row, iid, "Hoàn tất")

                            # Queue downloads for this profile

                            self._enqueue_profile_downloads(prof_name, prompt, index, status)

                        else:

                            self._schedule(self._update_profile_video_row, iid, "Thất bại")

                        break



                _t.sleep(poll_interval)



        except Exception as e:

            self._schedule(self._update_profile_video_row, iid, f"Lỗi: {str(e)[:20]}")



    def _process_profile_prompt_for_main_table(self, prof_name: str, prompt: str, index: int, cookies: str, iid: str, task: PromptTask) -> None:

        """Process profile prompt using exact same logic as _process_single_prompt."""



        # Check for cookie conflicts between Video and Profile tabs

        self._check_cookie_conflict_warning(cookies, prof_name)



        # Parse cookies and create client - EXACTLY like Video tab

        cookies_src = cookies

        if not cookies_src:

            self._log(f"[{prof_name}] Thiếu Cookie.\n")

            self._schedule(self._update_prof_tree_row, iid, "Lỗi Cookie")

            return



        client = self._build_client(cookies_src)

        if client is None:

            self._schedule(self._update_prof_tree_row, iid, "Lỗi Client")

            return



        # Use Profile-specific settings

        ps = self.profile_settings or {}

        # fallback thêm tới các entry UI nếu cần, rồi mới tới hằng mặc định

        ent_model_value = None

        if hasattr(self, "cmb_model") and self.cmb_model is not None:

            try:

                ent_model_value = self.cmb_model.get().strip()

            except:

                ent_model_value = None



        model_key = (ps.get("model_key")

                    or ent_model_value

                    or "veo_3_1_t2v_fast_ultra")

        tool = ps.get("tool") or "PINHOLE"

        tier = ps.get("tier") or "PAYGATE_TIER_TWO"

        num_videos = int(ps.get("num_videos") or 2)

        max_wait = int(ps.get("max_wait") or 300)

        poll_interval = int(ps.get("poll_interval") or 10)

        project_id = ps.get("project_id") or None





        # In ra tiêu đề tác vụ - EXACTLY like Video tab

        self._log(f"\n===== [Profile:{prof_name}] Prompt #{index}: {prompt} =====\n")

        self._log(f"🎯 Model: {model_key} (từ Profile settings hoặc UI)\n")

        slot_acquired = False



        try:

            # Step 1: token - ADD stop_event checks like Video tab

            if self.stop_event.is_set():

                return

            if not client.fetch_access_token():

                self._log(f"[{prof_name}] Lấy access token thất bại.\n")

                self._schedule(self._update_prof_tree_row, iid, "Lỗi Token")

                return



            # Step 2: chọn model - ADD stop_event checks like Video tab

            if self.stop_event.is_set():

                return

            if not client.set_video_model_key(model_key):

                self._log(f"[{prof_name}] Thiết lập model thất bại.\n")

                self._schedule(self._update_prof_tree_row, iid, "Lỗi Model")

                return



            # Step 3: batch log - ADD stop_event checks like Video tab

            if self.stop_event.is_set():

                return

            if not client.submit_batch_log(tool):

                self._log(f"[{prof_name}] Gửi batch log thất bại.\n")

                self._schedule(self._update_prof_tree_row, iid, "Lỗi Log")

                return



            # Step 4: generate - ADD stop_event checks like Video tab

            if self.stop_event.is_set():

                return

            # Acquire global video slot (max 2 concurrent)

            self._log(f"[{prof_name}] ⏳ Chờ slot chạy video (tối đa 2)...\n")

            self.video_semaphore.acquire()

            slot_acquired = True

            self._log(f"[{prof_name}] ✅ Đã giữ slot chạy video.\n")



            project = project_id if project_id else None

            if project is None:

                # tạo ngẫu nhiên tương tự main - EXACTLY like Video tab

                import uuid as _uuid

                project = str(_uuid.uuid4())



            # REMOVE retry logic - Video tab doesn't have it, just direct call

            operations = client.generate_videos(

                project_id=project,

                tool=tool,

                user_tier=tier,

                prompt=prompt,

                model_key=model_key,

                num_videos=num_videos,

                aspect_ratio=self._selected_video_aspect(),

                fixed_seed=self._get_fixed_seed(),

            )

            if not operations:

                self._log(f"[{prof_name}] Bắt đầu tạo video thất bại.\n")

                self._schedule(self._update_prof_tree_row, iid, "Lỗi Generate")

                return



            # Khởi tạo hàng trong bảng prof_tree (UI thread) - giống _init_operations_rows_ui

            self._schedule(self._init_prof_operations_rows_ui, task, operations, iid)



            # Step 5: poll thủ công - y hệt tab Video

            deadline = _t.time() + max_wait

            last_status: Optional[Dict[str, Any]] = None

            while _t.time() < deadline and not self.stop_event.is_set():

                status = client.check_video_status(operations)

                if status is not None:

                    last_status = status

                    # In đầy đủ response - EXACTLY like Video tab

                    self._log(f"[{prof_name}] " + _safe_json(status) + "\n")

                    # Cập nhật bảng prof_tree (UI thread)

                    self._schedule(self._update_prof_operations_rows_ui, task, status, prof_name)

                    # Kiểm tra hoàn tất - EXACTLY like Video tab

                    if isinstance(status, dict) and "operations" in status:

                        ops = status["operations"]

                        total = len(ops) if ops else len(operations)

                        done = 0

                        failed = 0

                        if ops:

                            for op in ops:

                                s = str(op.get("status", "")).upper()

                                if "COMPLETE" in s or "SUCCESS" in s:

                                    done += 1

                                elif "FAIL" in s or "ERROR" in s:

                                    failed += 1

                        if done + failed >= total:

                            self._log(f"[{prof_name}] Tất cả operation đã kết thúc.\n")

                            break

                _t.sleep(poll_interval)



            # ADD stop_event check like Video tab

            if self.stop_event.is_set():

                return



            final_status = last_status or {}



            # Xếp hàng tải về (dùng status cuối cùng)

            self._enqueue_profile_downloads_from_status(task, final_status, prof_name)



        except Exception as e:

            self._log(f"[{prof_name}] Lỗi khi xử lý prompt: {e}\n")

            self._schedule(self._update_prof_tree_row, iid, f"Lỗi: {str(e)[:20]}")

        finally:

            if slot_acquired:

                try:

                    self.video_semaphore.release()

                    self._log(f"[{prof_name}] 🔓 Đã giải phóng slot chạy video.\n")

                except Exception:

                    pass



    def _init_prof_operations_rows_ui(self, task: PromptTask, operations: List[Dict[str, Any]], base_iid: str) -> None:

        """Initialize prof_tree rows for operations (copy from _init_operations_rows_ui)."""

        self._log(f"📊 Khởi tạo {len(operations)} hàng trong bảng Profile operations\n")

        for i, op in enumerate(operations):

            name = op.get("operation", {}).get("name", "")

            scene = op.get("sceneId", "")

            status = self._human_status(op.get("status", "PENDING"))

            iid = f"{base_iid}:op{i}:{name}"



            if hasattr(self, 'prof_tree'):

                self.prof_tree.insert("", "end", iid=iid, values=(

                    task.prompt_text, scene, name, status, "", "Mở | Sao chép"

                ), tags=(self._status_tag(status),))



    def _update_prof_operations_rows_ui(self, task: PromptTask, status: Dict[str, Any], prof_name: str) -> None:

        """Update prof_tree rows for operations (copy from _update_operations_rows_ui)."""

        try:

            ops = status.get("operations")

            if not isinstance(ops, list):

                return

            for i, op in enumerate(ops):

                name = op.get("operation", {}).get("name", "")

                st = self._human_status(op.get("status", ""))

                # Find matching row by pattern

                if hasattr(self, 'prof_tree'):

                    for iid in self.prof_tree.get_children(""):

                        if f":op{i}:" in iid and name in iid:

                            values = list(self.prof_tree.item(iid, "values"))

                            if len(values) >= 4:

                                values[3] = st



                                # nếu có url tệp trong op

                                urls = _extract_file_urls(op)

                                if urls:

                                    values[4] = "; ".join(urls)

                                self.prof_tree.item(iid, values=values)

                                # cập nhật tag màu

                                self.prof_tree.item(iid, tags=(self._status_tag(st),))

                            break

        except Exception:

            pass



    def _enqueue_profile_downloads_from_status(self, task: PromptTask, status: Dict[str, Any], prof_name: str) -> None:

        """Enqueue downloads for profile (copy from _enqueue_downloads_from_status)."""

        # Debug: log the full status for debugging - EXACTLY like Video tab

        self._log(f"[{prof_name}] 🔍 Debug - Checking status for downloads: {_safe_json(status)}\n")



        urls = _extract_file_urls(status)

        if not urls:

            self._log(f"[{prof_name}] ❌ Không tìm thấy fileUrl/fifeUrl trong phản hồi cuối.\n")

            # Try to extract URLs manually for debugging - EXACTLY like Video tab

            all_strings = _extract_strings_recursive(status, ("url", "link", "file", "download", "media"))

            if all_strings:

                self._log(f"[{prof_name}] 🔍 Debug - Found these URL-like strings: {all_strings}\n")

            return



        self._log(f"[{prof_name}] ✅ Tìm thấy {len(urls)} URL để tải: {urls}\n")



        # Use Profile output directory

        out_dir = Path(self.profile_settings["output_dir"]) / f"Profile_{prof_name}"

        out_dir.mkdir(parents=True, exist_ok=True)



        # Use Video tab download method and downloads dir (shared) - EXACTLY like Video tab

        method = self.cmb_download_method.get()

        downloads_dir = Path(self.ent_downloads.get().strip())



        for idx, url in enumerate(urls, 1):

            if self.stop_event.is_set():

                break

            safe_prompt = "".join(ch for ch in task.prompt_text[:40] if ch.isalnum() or ch in (" ", "-", "_"))

            safe_prompt = safe_prompt.strip().replace(" ", "_") or f"prompt_{task.prompt_index}"

            filename = out_dir / f"{safe_prompt}_{idx}"

            filename = self._ensure_unique_filename(filename)

            self._log(f"[{prof_name}] 📋 Xếp hàng tải: {url} → {filename.name} (bằng {method})\n")

            self.download_queue.put(DownloadTask(url=url, target_path=filename, method=method, downloads_dir=downloads_dir, profile_name=prof_name))



    def _enqueue_profile_downloads(self, prof_name: str, prompt: str, index: int, status: Dict[str, Any]) -> None:

        """Enqueue downloads for profile video with profile-specific directory."""

        urls = _extract_file_urls(status)

        if not urls:

            return



        # Create profile-specific output directory using Profile settings

        base_out = Path(self.profile_settings["output_dir"])

        prof_out_dir = base_out / f"Profile_{prof_name}"

        prof_out_dir.mkdir(parents=True, exist_ok=True)



        # Use Video tab download method (this can be shared)

        method = self.cmb_download_method.get()

        downloads_dir = Path(self.ent_downloads.get().strip())



        for idx, url in enumerate(urls, 1):

            if self.stop_event.is_set():

                break



            safe_prompt = "".join(ch for ch in prompt[:40] if ch.isalnum() or ch in (" ", "-", "_"))

            safe_prompt = safe_prompt.strip().replace(" ", "_") or f"prompt_{index}"

            filename = prof_out_dir / f"{safe_prompt}_{idx}"

            filename = self._ensure_unique_filename(filename)



            self._log(f"📋 [{prof_name}] Xếp hàng tải: {filename.name}\n")

            self.download_queue.put(DownloadTask(url=url, target_path=filename, method=method, downloads_dir=downloads_dir))



    def on_run_veo_from_gemini(self) -> None:

        """Parse gemini_prompt.txt in selected Gemini outdir and run Text-to-Video for all shots."""

        # Validation

        if not self._get_cookies_source():

            Messagebox.show_error("Vui lòng nhập Cookie ở tab Video trước.")

            return

        # Determine output dir automatically: workflow/<profile>

        prof_name = ""

        try:

            prof_name = self.ent_profile_name.get().strip()

        except Exception:

            prof_name = ""

        if not prof_name:

            Messagebox.show_error("Vui lòng nhập và lưu Profile trước (tab Profiles).")

            return

        out_dir = str(self._app_root() / "workflow" / self._sanitize_name(prof_name))

        Path(out_dir).mkdir(parents=True, exist_ok=True)

        prompt_file = Path(out_dir) / "gemini_prompt.txt"

        if not prompt_file.exists():

            Messagebox.show_error(f"Không tìm thấy file: {prompt_file}")

            return



        # Ensure gemini files exist: if missing, auto-generate now

        if not Path(out_dir, "gemini_prompt.txt").exists():

            self.on_generate_gemini_files()

        # Collect detailed character map for enriching prompts

        char_map: Dict[str, Dict[str, Any]] = {}

        try:

            chars_path = Path(out_dir) / "characters.txt"

            if chars_path.exists():

                for line in chars_path.read_text(encoding="utf-8").splitlines():

                    s = line.strip().strip('"')

                    if not s:

                        continue

                    if s.startswith("Character Bible:"):

                        import json as _json

                        payload = s.split("Character Bible:", 1)[1].strip()

                        obj = _json.loads(payload)

                        name = obj.get("GEN_ID") or obj.get("Name_ID")

                        if name:

                            char_map[str(name)] = obj

        except Exception:

            pass



        # Collect shot prompts

        prompts: List[str] = []

        try:

            for line in Path(prompt_file).read_text(encoding="utf-8").splitlines():

                s = line.strip()

                if not s:

                    continue

                import json as _json

                obj = _json.loads(s)

                scene_id = obj.get("scene_id")

                for idx, sh in enumerate(obj.get("shots") or [], 1):

                    shot_prompt = sh.get("prompt") or ""

                    style = sh.get("style") or ""

                    camera = sh.get("camera") or ""

                    # Enrich with character details if GEN_IDs are referenced

                    merged_chars: List[str] = []

                    for key, raw in (obj.get("characters") or {}).items():

                        try:

                            ch = _json.loads(raw)

                            gid = ch.get("GEN_ID") or ch.get("Name_ID")

                            if gid and gid in char_map:

                                detail = char_map[gid]

                                merged_chars.append(f"{gid}: {detail}")

                        except Exception:

                            continue

                    char_text = (" Characters: " + "; ".join(merged_chars)) if merged_chars else ""

                    # compose final prompt

                    final_p = f"[Scene {scene_id} - Shot {idx}] {shot_prompt}. Style: {style}. Camera: {camera}.{char_text}"

                    prompts.append(final_p)

        except Exception as e:

            Messagebox.show_error(f"Lỗi đọc prompts: {e}")

            return



        if not prompts:

            Messagebox.show_error("Không đọc được prompt nào từ gemini_prompt.txt")

            return



        # Run as Text-to-Video flow reusing existing logic

        self.var_generation_mode.set("Text-to-Video")

        self._set_controls_state("disabled")

        # Enable Stop button while running

        with suppress(Exception):

            self.btn_stop.configure(state="normal")

        self.stop_event.clear()

        for item in self.tree.get_children():

            self.tree.delete(item)

        mode = self.cmb_mode.get()

        tasks = [PromptTask(prompt_text=p, prompt_index=i) for i, p in enumerate(prompts, 1)]

        self.executor = ThreadPoolExecutor(max_workers=1)

        threading.Thread(target=self._run_sequential, args=(tasks,), daemon=True).start()



    def _collect_wf_prompts(self) -> Tuple[List[str], List[str]]:

        """Collect (image_prompts, video_prompts) for Whisk Ảnh → Video.

        - Accept from textboxes and/or files; merge and deduplicate.

        - Return two parallel lists; if counts differ, shorter list will be cycled.

        """

        img_prompts: List[str] = []

        vid_prompts: List[str] = []



        # From files

        try:

            img_pf = getattr(self, 'ent_wf_img_prompt_file', None)

            if img_pf is not None:

                path = img_pf.get().strip()

                if path and os.path.exists(path):

                    for line in Path(path).read_text(encoding='utf-8').splitlines():

                        s = line.strip()

                        if s:

                            img_prompts.append(s)

        except Exception:

            pass

        try:

            vid_pf = getattr(self, 'ent_wf_video_prompt_file', None)

            if vid_pf is not None:

                path = vid_pf.get().strip()

                if path and os.path.exists(path):

                    for line in Path(path).read_text(encoding='utf-8').splitlines():

                        s = line.strip()

                        if s:

                            vid_prompts.append(s)

        except Exception:

            pass



        # From JSON folders (if provided): read full JSON as prompt

        try:

            img_json_dir = getattr(self, 'ent_wf_img_json_folder', None)

            if img_json_dir is not None:

                d = img_json_dir.get().strip()

                if d and os.path.isdir(d):

                    files = sorted(Path(d).glob('line_*.json'))

                    for fp in files:

                        try:

                            img_prompts.append(fp.read_text(encoding='utf-8').strip())

                        except Exception:

                            pass

        except Exception:

            pass

        try:

            vid_json_dir = getattr(self, 'ent_wf_vid_json_folder', None)

            if vid_json_dir is not None:

                d = vid_json_dir.get().strip()

                if d and os.path.isdir(d):

                    files = sorted(Path(d).glob('line_*.json'))

                    for fp in files:

                        try:

                            vid_prompts.append(fp.read_text(encoding='utf-8').strip())

                        except Exception:

                            pass

        except Exception:

            pass



        # From textboxes

        def collect_from_text(widget, out_list: List[str]) -> None:

            try:

                lines = widget.get('1.0', 'end').splitlines()

            except Exception:

                lines = []

                for ln in lines:

                    s = (ln or '').strip()

                    if not s:

                        continue

                    # strip numbering like "1. "

                    i = 0

                    while i < len(s) and s[i].isdigit():

                        i += 1

                    while i < len(s) and s[i] in ".)- ":

                        i += 1

                    s = s[i:].strip()

                    if s:

                        out_list.append(s)



        collect_from_text(getattr(self, 'txt_wf_img_prompts', None) or self.txt_wf_prompts, img_prompts)

        collect_from_text(self.txt_wf_prompts, vid_prompts)



        # Dedup preserve order

        def dedup(lst: List[str]) -> List[str]:

            seen = set(); res: List[str] = []

            for p in lst:

                if p not in seen:

                    seen.add(p)

                    res.append(p)

            return res



        img_prompts = dedup(img_prompts)

        vid_prompts = dedup(vid_prompts)



        return (img_prompts, vid_prompts)



    def on_wf_stop(self) -> None:

        """Stop WorkFlow operations."""

        self.workflow_stop_event.set()

        self._log("🛑 Yêu cầu dừng WorkFlow...\n")

        self.btn_wf_stop.configure(state="disabled")



        # Also set main stop event for compatibility

        self.stop_event.set()



    def _add_workflow_row(self, iid: str, flow: str, prompt: str, status: str, detail: str = "") -> None:

        """Add row to workflow ops table (UI thread)."""

        try:

            with suppress(Exception):

                self.lst_workflow_ops.delete(iid)

            self.lst_workflow_ops.insert("", "end", iid=iid, values=(flow, prompt, status, detail))

        except Exception:

            pass



    def _update_workflow_row(self, iid: str, status: str, detail: str = "") -> None:

        """Update workflow row status (UI thread)."""

        try:

            if iid in self.lst_workflow_ops.get_children(""):

                values = list(self.lst_workflow_ops.item(iid, "values"))

                if len(values) >= 3:

                    values[2] = status

                    if detail and len(values) >= 4:

                        values[3] = detail

                    self.lst_workflow_ops.item(iid, values=values)

        except Exception:

            pass



    def on_wf_run_whisk_image_to_video(self) -> None:

        """Run Whisk Ảnh → Video workflow."""

        # Check if workflow is already running

        if self.workflow_executor is not None:

            Messagebox.show_info("WorkFlow đang chạy, vui lòng dừng trước khi chạy tiếp.")

            return



        # Get image prompts from text area

        img_prompts_text = self.txt_wf_img_prompts.get("1.0", "end-1c").strip()

        if not img_prompts_text:

            Messagebox.show_error("Vui lòng nhập prompt ảnh.")

            return



        # Split prompts by lines

        img_prompts = [line.strip() for line in img_prompts_text.split('\n') if line.strip()]

        if not img_prompts:

            Messagebox.show_error("Không có prompt ảnh hợp lệ.")

            return



        # Clear workflow status table

        for item in self.lst_workflow_ops.get_children():

            self.lst_workflow_ops.delete(item)



        # Enable stop button for workflow

        self.btn_wf_stop.configure(state="normal")

        self.workflow_stop_event.clear()



        # Initialize workflow executor

        self.workflow_executor = ThreadPoolExecutor(max_workers=1)



        # Start workflow in background

        threading.Thread(target=self._run_whisk_image_to_video_worker, args=(img_prompts,), daemon=True).start()



    def _run_whisk_image_to_video_worker(self, img_prompts: List[str]) -> None:

        """Worker thread for Whisk Ảnh → Video workflow."""

        try:

            self._log(f"🎬 [WorkFlow] Bắt đầu Whisk Ảnh → Video với {len(img_prompts)} prompt...\n")



            for i, img_prompt in enumerate(img_prompts, 1):

                if self.workflow_stop_event.is_set():

                    self._log(f"🛑 [WorkFlow] Dừng workflow tại prompt {i}\n")

                    break



                # Add to workflow status table

                iid = self.lst_workflow_ops.insert("", "end", values=("WhiskẢnh→Video", img_prompt[:50] + "...", "Đang xử lý", ""))



                try:

                    # Step 1: Generate image using Whisk

                    self._update_workflow_status(iid, "Đang tạo ảnh", "Whisk API")



                    # Apply current image tab settings

                    self._apply_image_settings_for_workflow()



                    # Generate image

                    image_result = self._generate_single_image_workflow(img_prompt)



                    if not image_result:

                        self._update_workflow_status(iid, "Lỗi tạo ảnh", "Không tạo được ảnh")

                        continue



                    # Step 2: Generate video from image using I2V

                    self._update_workflow_status(iid, "Đang tạo video", "I2V API")



                    # Apply current video tab settings

                    self._apply_video_settings_for_workflow()



                    # Generate video from image

                    video_result = self._generate_video_from_image_workflow(image_result, img_prompt)



                    if video_result:

                        self._update_workflow_status(iid, "Hoàn thành", f"Tạo được video: {video_result}")

                    else:

                        self._update_workflow_status(iid, "Lỗi tạo video", "Không tạo được video")



                except Exception as e:

                    self._update_workflow_status(iid, "Lỗi", str(e))

                    self._log(f"⚠️ [WorkFlow] Lỗi xử lý prompt {i}: {e}\n")



        except Exception as e:

            self._log(f"❌ [WorkFlow] Lỗi workflow: {e}\n")

        finally:

            # Cleanup

            if self.workflow_executor:

                self.workflow_executor.shutdown(wait=False)

                self.workflow_executor = None

            self.btn_wf_stop.configure(state="disabled")

            self._log(f"✅ [WorkFlow] Hoàn thành Whisk Ảnh → Video\n")



