    def _process_workflow_image_to_video_pair(self, img_prompt: str, vid_prompt: str, index: int, iid: str) -> None:

        """Whisk Ảnh → Video hai bước:

        1) Tạo ảnh từ img_prompt (Text-to-Image)

        2) Lấy ảnh đó + vid_prompt để tạo Video (Image-to-Video)

        """

        try:

            self._schedule(self._update_workflow_row, iid, "Đang xử lý (Ảnh→Video)")



            # 1) Xác thực cookie

            cookies_src = self._get_cookies_source()

            if not cookies_src:

                self._schedule(self._update_workflow_row, iid, "Lỗi Cookie")

                return

            client = self._build_client(cookies_src)

            if client is None:

                self._schedule(self._update_workflow_row, iid, "Lỗi Client")

                return



            # 2) BƯỚC TẠO ẢNH TRƯỚC từ img_prompt (Text-to-Image) - BẮT BUỘC

            image_path: str = ""

            if img_prompt:

                self._schedule(self._update_workflow_row, iid, "Đang tạo ảnh...")



                # Sinh 1 ảnh và lưu vào thư mục ảnh của tab Ảnh

                out_dir = self.ent_image_output.get().strip() or str(Path.cwd() / "downloaded_images")

                Path(out_dir).mkdir(parents=True, exist_ok=True)



                # Gọi pipeline tạo ảnh đơn giản (generate_image_from_text)

                if not client.fetch_access_token():

                    self._schedule(self._update_workflow_row, iid, "Lỗi Token")

                    return



                self._log(f"[WorkFlow] Đang tạo ảnh từ prompt: {img_prompt[:80]}...\n")



                try:

                    workflow_id = client.create_whisk_workflow()

                    if not workflow_id:

                        raise Exception("Không tạo được workflow_id")



                    # Nếu có Subject/Scene/Style từ tab Image thì upload và dùng runImageRecipe

                    # Read reference images primarily from Image tab; fallback to JSON Prompt tab fields if empty

                    subject_path = getattr(self, 'ent_subject_image', None).get().strip() if hasattr(self, 'ent_subject_image') else ""

                    scene_path = getattr(self, 'ent_scene_image', None).get().strip() if hasattr(self, 'ent_scene_image') else ""

                    style_path = getattr(self, 'ent_style_image', None).get().strip() if hasattr(self, 'ent_style_image') else ""

                    if not subject_path and hasattr(self, 'ent_jsonp_subject_image'):

                        subject_path = self.ent_jsonp_subject_image.get().strip()

                    if not scene_path and hasattr(self, 'ent_jsonp_scene_image'):

                        scene_path = self.ent_jsonp_scene_image.get().strip()

                    if not style_path and hasattr(self, 'ent_jsonp_style_image'):

                        style_path = self.ent_jsonp_style_image.get().strip()

                    subj_mgid = scene_mgid = style_mgid = None

                    try:

                        if subject_path and os.path.exists(subject_path):

                            self._log(f"[WorkFlow] Upload Subject: {Path(subject_path).name}\n")

                            subj_mgid = client.upload_image(subject_path)

                        if scene_path and os.path.exists(scene_path):

                            self._log(f"[WorkFlow] Upload Scene: {Path(scene_path).name}\n")

                            scene_mgid = client.upload_image(scene_path)

                        if style_path and os.path.exists(style_path):

                            self._log(f"[WorkFlow] Upload Style: {Path(style_path).name}\n")

                            style_mgid = client.upload_image(style_path)

                    except Exception:

                        pass



                    if subj_mgid or scene_mgid or style_mgid:

                        self._log("[WorkFlow] ➤ Dùng runImageRecipe với Subject/Scene/Style references\n")

                        result = client.run_image_recipe(

                            workflow_id=workflow_id,

                            prompt=img_prompt,

                            image_model="R2I",

                            aspect_ratio=getattr(self, 'cmb_aspect_ratio', None).get() if hasattr(self, 'cmb_aspect_ratio') else "16:9",

                            subject_mgid=subj_mgid,

                            scene_mgid=scene_mgid,

                            style_mgid=style_mgid,

                            seed=self._get_fixed_seed(),

                        )

                    else:

                        self._log("[WorkFlow] ➤ Không có reference → dùng generate_image_from_text\n")

                        result = client.generate_image_from_text(

                            workflow_id=workflow_id,

                            prompt=img_prompt,

                            image_model=getattr(self, 'cmb_image_model', None).get() if hasattr(self, 'cmb_image_model') else "IMAGEN_3_5",

                            aspect_ratio=getattr(self, 'cmb_aspect_ratio', None).get() if hasattr(self, 'cmb_aspect_ratio') else "16:9",

                        )



                    # Nếu chưa có URL ngay → poll operation đến khi COMPLETE rồi tải về

                    url = self._extract_image_url(result) if isinstance(result, dict) else None

                    if not url and isinstance(result, dict):

                        # Thử lấy operation name và sceneId để poll

                        try:

                            op_name = None

                            scene_id = None

                            if 'operation' in result and isinstance(result['operation'], dict):

                                op_name = result['operation'].get('name')

                            if not op_name:

                                op_name = result.get('name')

                            scene_id = result.get('sceneId') or result.get('scene_id')

                            if op_name:

                                fake_ops = [{"operation": {"name": op_name}, "sceneId": scene_id or ""}]

                                deadline = _t.time() + 180

                                while _t.time() < deadline and not self.workflow_stop_event.is_set():

                                    status = client.check_video_status(fake_ops)

                                    if status and isinstance(status, dict) and "operations" in status:

                                        ops = status["operations"]

                                        if ops:

                                            st = str(ops[0].get("status", "")).upper()

                                            if "COMPLETE" in st or "SUCCESS" in st:

                                                url = self._extract_image_url(ops[0])

                                                break

                                            if ("ACTIVE" in st or "PENDING" in st) and (deadline - _t.time()) < 30:

                                                deadline += 60

                                    _t.sleep(3)

                        except Exception:

                            pass



                    if url:

                        try:

                            headers = {"user-agent": "Mozilla/5.0"}

                            local = Path(out_dir) / f"wf_img_{index}.jpg"

                            self._log(f"[WorkFlow] Đang tải ảnh từ: {url[:80]}...\n")

                            with requests.get(url, headers=headers, stream=True, timeout=60) as r:

                                r.raise_for_status()

                                with open(local, 'wb') as f:

                                    for chunk in r.iter_content(8192):

                                        if chunk:

                                            f.write(chunk)

                            image_path = str(local)

                            self._log(f"[WorkFlow] ✅ Đã tạo ảnh thành công: {local.name}\n")

                        except Exception as e:

                            self._log(f"[WorkFlow] ❌ Lỗi tải ảnh: {e}\n")

                            image_path = ""

                    else:

                        # Fallback: thử base64

                        img_bytes, ext = self._extract_base64_image_data(result) if isinstance(result, dict) else (None, "jpg")

                        if img_bytes:

                            local = Path(out_dir) / f"wf_img_{index}.{ext}"

                            with open(local, 'wb') as f:

                                f.write(img_bytes)

                            image_path = str(local)

                            self._log(f"[WorkFlow] ✅ Đã tạo ảnh từ base64: {local.name}\n")

                        else:

                            self._log(f"[WorkFlow] ❌ Không tìm thấy URL hoặc base64 trong response\n")

                except Exception as e:

                    self._log(f"[WorkFlow] ❌ Lỗi tạo ảnh: {e}\n")

                    self._schedule(self._update_workflow_row, iid, f"Lỗi tạo ảnh: {str(e)[:20]}")

                    return



            # 3) KIỂM TRA BẮT BUỘC: Phải có ảnh mới tiếp tục

            if not image_path or not os.path.exists(image_path):

                self._log(f"[WorkFlow] ❌ KHÔNG TẠO ĐƯỢC ẢNH cho prompt: {img_prompt[:50]}...\n")

                self._schedule(self._update_workflow_row, iid, "Lỗi: Không tạo được ảnh")

                return



            # 4) Upload ảnh và chạy Image-to-Video với vid_prompt - COPY EXACT logic từ _process_single_image_task

            model_key = self.ent_image_model.get() or "veo_3_1_i2v_s_fast_ultra"

            tool = self.ent_tool.get().strip() or "PINHOLE"

            tier = self.cmb_tier.get().strip() or "PAYGATE_TIER_TWO"

            num_videos = int(self.spn_num_videos.get())  # Use GUI setting, not hardcoded

            max_wait = int(self.spn_max_wait.get())

            poll_interval = int(self.spn_poll.get())

            project_id = self.ent_project.get().strip() or None



            # Step 1: token - EXACT copy from Video tab

            if self.workflow_stop_event.is_set():

                return

            if not client.fetch_access_token():

                self._schedule(self._update_workflow_row, iid, "Lỗi Token")

                return



            # Step 2: chọn model - EXACT copy from Video tab

            if self.workflow_stop_event.is_set():

                return

            if not client.set_video_model_key(model_key):

                self._schedule(self._update_workflow_row, iid, "Lỗi Model")

                return



            # Step 3: batch log - EXACT copy from Video tab

            if self.workflow_stop_event.is_set():

                return

            if not client.submit_batch_log(tool):

                self._schedule(self._update_workflow_row, iid, "Lỗi Log")

                return



            # Step 4: upload image - EXACT copy from Video tab

            if self.workflow_stop_event.is_set():

                return



            # Prepare image with proper aspect ratio - EXACT copy from Video tab

            processed_image_path = self._prepare_image_for_upload(image_path)



            self._log(f"[WorkFlow] Đang upload ảnh: {Path(image_path).name}\n")

            wf_upload = client.upload_image_full(processed_image_path)

            if not wf_upload:

                self._schedule(self._update_workflow_row, iid, "Lỗi Upload ảnh")

                try:

                    detail = getattr(client, "last_error_detail", None)

                    if detail:

                        self._log(f"[WorkFlow] Chi tiết lỗi: {detail}\n")

                except Exception:

                    pass

                return

            media_id = wf_upload["media_id"]

            wf_img_width = wf_upload.get("width")

            wf_img_height = wf_upload.get("height")

            wf_project = wf_upload.get("project_id")



            # Step 5: generate videos from image - EXACT copy from Video tab

            if self.workflow_stop_event.is_set():

                return

            # Initialize flag before acquire to avoid NameError in finally

            slot_acquired_wf = False

            # Acquire global video slot (max 2 concurrent) - EXACT copy from Video tab

            self._log("[WorkFlow] ⏳ Chờ slot chạy video (tối đa 2)...\n")

            self.video_semaphore.acquire()

            slot_acquired_wf = True

            self._log("[WorkFlow] ✅ Đã giữ slot chạy video.\n")

            project = project_id if project_id else str(__import__('uuid').uuid4())



            operations = client.generate_videos_from_image(

                project_id=wf_project or project,

                tool=tool,

                user_tier=tier,

                prompt=vid_prompt or img_prompt,

                media_id=media_id,

                model_key=model_key,

                num_videos=num_videos,

                aspect_ratio=self._selected_video_aspect(),

                fixed_seed=self._get_fixed_seed(),

                image_width=wf_img_width,

                image_height=wf_img_height,

                crop_coordinates=None,

            )

            if not operations:

                self._schedule(self._update_workflow_row, iid, "Lỗi Generate")

                try:

                    detail = getattr(client, "last_error_detail", None)

                    if detail:

                        self._log(f"[WorkFlow] Chi tiết lỗi: {detail}\n")

                except Exception:

                    pass

                return



            # Step 6: poll thủ công - EXACT copy from Video tab

            deadline = _t.time() + max_wait

            last_status: Optional[Dict[str, Any]] = None

            while _t.time() < deadline and not self.workflow_stop_event.is_set():

                status = client.check_video_status(operations)

                if status is not None:

                    last_status = status

                    # In đầy đủ response - EXACT copy from Video tab

                    self._log(f"[WorkFlow] " + _safe_json(status) + "\n")

                    # Kiểm tra hoàn tất - EXACT copy from Video tab

                    if isinstance(status, dict) and "operations" in status:

                        total = len(status["operations"]) or len(operations)

                        done = 0

                        failed = 0

                        active = 0

                        for op in status["operations"]:

                            s = str(op.get("status", "")).upper()

                            if "COMPLETE" in s or "SUCCESS" in s:

                                done += 1

                            elif "FAIL" in s or "ERROR" in s:

                                failed += 1

                            elif "ACTIVE" in s or "RUNNING" in s:

                                active += 1



                        # Extend deadline if videos are still actively processing

                        if active > 0 and _t.time() > deadline - 30:  # Less than 30s left

                            deadline += 60  # Extend by 1 minute

                            self._log(f"⏰ Video vẫn đang xử lý, gia hạn thêm 60s...\n")



                        if done + failed >= total:

                            self._log("[WorkFlow] Tất cả operation đã kết thúc.\n")

                            break

                _t.sleep(poll_interval)



            if self.workflow_stop_event.is_set():

                return



            final_status = last_status or {}



            # Xếp hàng tải về - EXACT copy from Video tab

            self._enqueue_workflow_downloads(vid_prompt or img_prompt, index, final_status, self.ent_wf_downloads.get().strip())

            self._schedule(self._update_workflow_row, iid, "Hoàn tất")

        except Exception as e:

            self._log(f"[WorkFlow] Lỗi khi xử lý ảnh: {e}\n")

            self._schedule(self._update_workflow_row, iid, f"Lỗi: {str(e)[:20]}")

        finally:

            # Ensure flag exists even if we error out before assignment

            try:

                acquired_flag = bool(slot_acquired_wf)

            except Exception:

                acquired_flag = False

            if acquired_flag:

                with suppress(Exception):

                    self.video_semaphore.release()

                    self._log("[WorkFlow] 🔓 Đã giải phóng slot chạy video.\n")



    def _process_workflow_image_only(self, img_prompt: str, index: int, iid: str) -> None:

        """Chỉ tạo ảnh từ img_prompt (không tạo video) - dùng khi I2V gặp lỗi 500."""

        try:

            self._schedule(self._update_workflow_row, iid, "Đang tạo ảnh")



            if not img_prompt:

                self._schedule(self._update_workflow_row, iid, "Lỗi: Không có prompt ảnh")

                return



            # 1) Xác thực cookie

            cookies_src = self._get_cookies_source()

            if not cookies_src:

                self._schedule(self._update_workflow_row, iid, "Lỗi Cookie")

                return

            client = self._build_client(cookies_src)

            if client is None:

                self._schedule(self._update_workflow_row, iid, "Lỗi Client")

                return



            # 2) Tạo ảnh từ img_prompt

            if not client.fetch_access_token():

                self._schedule(self._update_workflow_row, iid, "Lỗi Token")

                return



            workflow_id = client.create_whisk_workflow()

            if not workflow_id:

                self._schedule(self._update_workflow_row, iid, "Lỗi Workflow")

                return



            result = client.generate_image_from_text(

                workflow_id=workflow_id,

                prompt=img_prompt,

                image_model=getattr(self, 'cmb_image_model', None).get() if hasattr(self, 'cmb_image_model') else "IMAGEN_3_5",

                aspect_ratio=getattr(self, 'cmb_aspect_ratio', None).get() if hasattr(self, 'cmb_aspect_ratio') else "16:9",

            )



            if result:

                # Lưu ảnh vào thư mục WorkFlow

                out_dir = self.ent_wf_downloads.get().strip() or str(Path.cwd() / "WorkFlow_Images")

                Path(out_dir).mkdir(parents=True, exist_ok=True)



                # Check if result has operation that needs polling

                operation = result.get("operation", {})

                if isinstance(operation, dict) and operation.get("name"):

                    # Need to poll for image completion

                    self._schedule(self._update_workflow_row, iid, "Đang chờ ảnh...")



                    # Simple polling for image (reuse video polling logic)

                    op_name = operation.get("name")

                    fake_ops = [{"operation": {"name": op_name}, "sceneId": f"img_{index}", "status": "MEDIA_GENERATION_STATUS_PENDING"}]



                    # Poll for image completion

                    deadline = _t.time() + 120  # 2 minutes max for image

                    while _t.time() < deadline and not self.workflow_stop_event.is_set():

                        status = client.check_video_status(fake_ops)  # Reuse video status checker

                        if status and isinstance(status, dict) and "operations" in status:

                            ops = status["operations"]

                            if ops and len(ops) > 0:

                                op_status = ops[0].get("status", "").upper()

                                if "COMPLETE" in op_status or "SUCCESS" in op_status:

                                    # Extract URL from completed operation

                                    final_result = ops[0]

                                    url = self._extract_image_url(final_result)

                                    if url:

                                        try:

                                            headers = {"user-agent": "Mozilla/5.0"}

                                            local = Path(out_dir) / f"wf_img_only_{index}.jpg"

                                            with requests.get(url, headers=headers, stream=True, timeout=60) as r:

                                                r.raise_for_status()

                                                with open(local, 'wb') as f:

                                                    for chunk in r.iter_content(8192):

                                                        if chunk:

                                                            f.write(chunk)

                                            self._schedule(self._update_workflow_row, iid, f"Hoàn tất - Ảnh: {local.name}")

                                            return

                                        except Exception:

                                            pass

                                    break

                                elif "FAIL" in op_status or "ERROR" in op_status:

                                    break

                        _t.sleep(3)



                # Fallback: try immediate URL/base64 extraction

                url = self._extract_image_url(result) if isinstance(result, dict) else None

                if url:

                    try:

                        headers = {"user-agent": "Mozilla/5.0"}

                        local = Path(out_dir) / f"wf_img_only_{index}.jpg"

                        with requests.get(url, headers=headers, stream=True, timeout=60) as r:

                            r.raise_for_status()

                            with open(local, 'wb') as f:

                                for chunk in r.iter_content(8192):

                                    if chunk:

                                        f.write(chunk)

                        self._schedule(self._update_workflow_row, iid, f"Hoàn tất - Ảnh: {local.name}")

                    except Exception:

                        self._schedule(self._update_workflow_row, iid, "Lỗi tải ảnh")

                else:

                    # Thử base64

                    img_bytes, ext = self._extract_base64_image_data(result) if isinstance(result, dict) else (None, "jpg")

                    if img_bytes:

                        local = Path(out_dir) / f"wf_img_only_{index}.{ext}"

                        with open(local, 'wb') as f:

                            f.write(img_bytes)

                        self._schedule(self._update_workflow_row, iid, f"Hoàn tất - Ảnh: {local.name}")

                    else:

                        self._schedule(self._update_workflow_row, iid, "Lỗi: Không có ảnh")

            else:

                self._schedule(self._update_workflow_row, iid, "Lỗi tạo ảnh")



        except Exception as e:

            self._schedule(self._update_workflow_row, iid, f"Lỗi: {str(e)[:20]}")



    def _enqueue_workflow_downloads(self, prompt: str, index: int, status: Dict[str, Any], downloads_dir: str) -> None:

        """Enqueue downloads for WorkFlow with workflow-specific directory."""

        urls = _extract_file_urls(status)

        if not urls:

            return



        # Create workflow-specific output directory

        wf_out_dir = Path(downloads_dir) / "WorkFlow_Output"

        wf_out_dir.mkdir(parents=True, exist_ok=True)



        method = self.cmb_download_method.get()

        downloads_dir_path = Path(self.ent_downloads.get().strip())



        for idx, url in enumerate(urls, 1):

            if self.workflow_stop_event.is_set():

                break



            safe_prompt = "".join(ch for ch in prompt[:40] if ch.isalnum() or ch in (" ", "-", "_"))

            safe_prompt = safe_prompt.strip().replace(" ", "_") or f"prompt_{index}"

            filename = wf_out_dir / f"WF_{safe_prompt}_{idx}"

            filename = self._ensure_unique_filename(filename)



            self._log(f"📋 [WorkFlow] Xếp hàng tải: {filename.name}\n")

            self.download_queue.put(DownloadTask(url=url, target_path=filename, method=method, downloads_dir=downloads_dir_path))



    def _run_workflow_text_to_image(self, prompts: List[str]) -> None:

        """Use image generation pipeline for each prompt."""

        if self.executor is not None:

            Messagebox.show_info("Đang chạy, vui lòng dừng trước khi chạy tiếp.")

            return

        if not self._get_cookies_source():

            Messagebox.show_error("Vui lòng nhập Cookie ở tab Video trước.")

            return

        out_dir = self.ent_image_output.get().strip()

        if not out_dir:

            Messagebox.show_error("Vui lòng chọn thư mục lưu ảnh (tab Ảnh).")

            return

        Path(out_dir).mkdir(parents=True, exist_ok=True)



        # Disable controls for image tab state

        self._set_image_controls_state("disabled")

        with suppress(Exception):

            self.btn_image_stop.configure(state="normal")

        self.stop_event.clear()

        self._log("[WorkFlow] Bắt đầu tạo ảnh từ AI prompts...\n")



        # Initialize executor and run (limit to 3 concurrent tasks)

        max_workers = min(3, len(prompts))

        self.executor = ThreadPoolExecutor(max_workers=max_workers)

        # Clear image table

        for item in self.img_tree.get_children():

            self.img_tree.delete(item)

        threading.Thread(target=self._run_image_generation, args=(prompts,), daemon=True).start()



    def _run_workflow_text_to_image_to_video(self, prompts: List[str]) -> None:

        """Generate images from prompts, then convert images to videos using Image-to-Video."""

        if self.executor is not None:

            Messagebox.show_info("Đang chạy, vui lòng dừng trước khi chạy tiếp.")

            return

        if not self._get_cookies_source():

            Messagebox.show_error("Vui lòng nhập Cookie ở tab Video trước.")

            return

        out_dir = self.ent_image_output.get().strip()

        # Tạo thư mục tạm riêng cho workflow

        temp_dir = Path.cwd() / f"_wf_tmp_{int(_t.time())}"

        temp_dir.mkdir(parents=True, exist_ok=True)



        # Lưu trạng thái workflow

        self._wf_active = True

        self._wf_chain_prompts = list(prompts)

        self._wf_chain_output = temp_dir

        self._wf_prev_image_out = out_dir

        self._wf_images_by_prompt = {}



        # Hook: after image run finishes, call our chain continuation

        original_finish = getattr(self, "_finish_image_run", None)



        def _chained_finish():

            try:

                if callable(original_finish):

                    original_finish()

            finally:

                # Restore image output entry to previous path

                with suppress(Exception):

                    self.ent_image_output.delete(0, "end")

                    self.ent_image_output.insert(0, str(self._wf_prev_image_out))

                # Proceed to image-to-video automatically

                self._continue_chain_image_to_video()



        # Monkey-patch finish temporarily

        self._finish_image_run = _chained_finish  # type: ignore



        # Chuyển output ảnh sang thư mục tạm cho workflow

        try:

            self.ent_image_output.delete(0, "end")

            self.ent_image_output.insert(0, str(temp_dir))

        except Exception:

            pass



        # Start image generation (reuse Text-to-Image path)

        self._run_workflow_text_to_image(prompts)



    def _continue_chain_image_to_video(self) -> None:

        """Continue workflow: take generated images and prompts, run Image-to-Video automatically."""

        try:

            prompts = getattr(self, "_wf_chain_prompts", []) or []

            temp_dir = getattr(self, "_wf_chain_output", None)

            if not prompts or temp_dir is None:

                return



            # Tạo danh sách tác vụ trực tiếp từ map ảnh đã tạo

            image_tasks: List[ImageTask] = []

            images_map: Dict[str, List[str]] = getattr(self, "_wf_images_by_prompt", {}) or {}

            for idx, p in enumerate(prompts, 1):

                files = images_map.get(p) or []

                img_path = files[0] if files else None

                if img_path and os.path.exists(img_path):

                    image_tasks.append(ImageTask(image_path=img_path, prompt_text=p, task_index=idx))

                else:

                    # fallback: pick first image in temp folder if available

                    candidates = []

                    for ext in ("*.jpg", "*.jpeg", "*.png", "*.webp"):

                        candidates.extend(sorted(str(x) for x in Path(temp_dir).glob(ext)))

                    if candidates:

                        image_tasks.append(ImageTask(image_path=candidates[0], prompt_text=p, task_index=idx))



            if not image_tasks:

                self._log("[WorkFlow] Không tìm thấy ảnh đã tạo để chạy Image-to-Video.\n")

                return



            # Đánh dấu thư mục tạm để dọn dẹp sau khi tạo video xong

            self._wf_cleanup_dir = Path(temp_dir)



            # Prepare executor (use concurrent jobs setting)

            mode = self.cmb_mode.get()

            max_workers = min(self._get_concurrent_jobs_value(), len(image_tasks)) if mode == "Song song" else 1

            self.executor = ThreadPoolExecutor(max_workers=max_workers)



            # Clear operations table and run

            for item in self.tree.get_children():

                self.tree.delete(item)

            if mode == "Tuần tự":

                threading.Thread(target=self._run_image_sequential, args=(image_tasks,), daemon=True).start()

            else:

                threading.Thread(target=self._run_image_parallel, args=(image_tasks,), daemon=True).start()

        finally:

            # Khôi phục hook _finish_image_run về mặc định

            with suppress(Exception):

                import types

                self._finish_image_run = types.MethodType(App._finish_image_run, self)  # type: ignore



