    # Preview panel removed - using modal carousel instead



    def _on_image_mode_change(self) -> None:

        """Switch between Text-to-Image and Image-to-Image modes"""

        mode = self.var_image_mode.get()

        if mode == "Text-to-Image":

            self.text_to_image_frame.pack(fill="x", pady=5)

            self.image_to_image_frame.pack_forget()

        else:  # Image-to-Image

            self.text_to_image_frame.pack_forget()

            self.image_to_image_frame.pack(fill="x", pady=5)



    def _build_image_tree_context_menu(self) -> None:

        """Build context menu for image results table"""

        self.img_ctx_menu = tb.Menu(self.root, tearoff=0)

        self.img_ctx_menu.add_command(label="Mở ảnh", command=self._action_open_image)

        self.img_ctx_menu.add_command(label="Mở thư mục", command=self._action_open_image_folder)

        self.img_ctx_menu.add_command(label="Sao chép đường dẫn", command=self._action_copy_image_path)

        self.img_ctx_menu.add_separator()

        self.img_ctx_menu.add_command(label="Sao chép URL", command=self._action_copy_image_url)

        self.img_tree.bind("<Button-3>", self._on_image_tree_right_click)



    def _on_image_tree_right_click(self, event) -> None:

        """Handle right click on image tree"""

        try:

            row_id = self.img_tree.identify_row(event.y)

            if row_id:

                self.img_tree.selection_set(row_id)

                self.img_ctx_menu.tk_popup(event.x_root, event.y_root)

        finally:

            try:

                self.img_ctx_menu.grab_release()

            except Exception:

                pass



    def _on_image_tree_left_click(self, event) -> None:

        """Handle left click on image tree - show preview if clicking action column"""

        try:

            row_id = self.img_tree.identify_row(event.y)

            col_id = self.img_tree.identify_column(event.x)

            if not row_id or not col_id:

                return

            col_index = int(col_id.replace('#', '')) - 1

            if self.img_tree_columns and col_index == self.img_tree_columns.index("action"):

                # Clicked on action column - show preview

                self.img_tree.selection_set(row_id)

                self._view_image_preview(row_id)

        except Exception:

            pass



    def _view_image_preview(self, row_id: str) -> None:

        """Open preview window for images in selected row"""

        try:

            vals = self.img_tree.item(row_id, "values")

            if len(vals) < 3 or not vals[2]:

                return

            

            # Get all image paths

            image_paths_str = str(vals[2])

            image_paths = [p.strip() for p in image_paths_str.split(";") if p.strip()]

            

            # Filter to existing files

            valid_paths = [p for p in image_paths if os.path.exists(p)]

            if not valid_paths:

                Messagebox.show_info("Không có ảnh để xem", parent=self.root)

                return

            

            # Open preview window

            self._open_image_preview_window(valid_paths)

        except Exception as e:

            self._log(f"❌ Lỗi mở preview ảnh: {e}\n")



    def _open_image_preview_window(self, image_paths: List[str]) -> None:

        """Open carousel modal to view images"""

        try:

            from PIL import Image, ImageTk

            import tkinter as tk

            

            modal = tb.Toplevel(self.root)

            modal.title("Xem ảnh")

            modal.geometry("1000x700")

            modal.resizable(False, False)

            modal.transient(self.root)

            modal.grab_set()

            modal.attributes('-topmost', True)

            self._center_window(modal, 1000, 700)

            

            # Dark theme styling

            modal.configure(bg="#2b2b2b")

            

            # Current image index

            current_idx = [0]

            image_refs = []  # Keep references to images

            

            # Main container

            main_container = tk.Frame(modal, bg="#2b2b2b")

            main_container.pack(fill="both", expand=True, padx=20, pady=20)

            

            # Header with close button

            header = tk.Frame(main_container, bg="#2b2b2b")

            header.pack(fill="x", pady=(0, 15))

            

            close_btn = tk.Button(header, text="✕", font=("Arial", 16), bg="#444", fg="white",

                                 relief="flat", width=3, height=1, command=modal.destroy,

                                 cursor="hand2")

            close_btn.pack(side="right")

            

            # Image display area

            img_container = tk.Frame(main_container, bg="#1a1a1a", relief="flat", bd=2)

            img_container.pack(fill="both", expand=True)

            

            canvas_frame = tk.Frame(img_container, bg="#1a1a1a")

            canvas_frame.pack(fill="both", expand=True, padx=10, pady=10)

            

            img_canvas = tk.Canvas(canvas_frame, bg="#1a1a1a", highlightthickness=0)

            img_canvas.pack(fill="both", expand=True)

            

            # Navigation arrows

            nav_frame = tk.Frame(img_container, bg="#1a1a1a")

            nav_frame.pack(fill="x", padx=10, pady=5)

            

            def update_image():

                """Update displayed image"""

                try:

                    idx = current_idx[0]

                    if idx < 0:

                        current_idx[0] = len(image_paths) - 1

                        idx = current_idx[0]

                    elif idx >= len(image_paths):

                        current_idx[0] = 0

                        idx = 0

                    

                    img_path = image_paths[idx]

                    

                    # Load and resize image to fit canvas

                    img = Image.open(img_path)

                    canvas_width = img_canvas.winfo_width()

                    canvas_height = img_canvas.winfo_height()

                    

                    if canvas_width > 1 and canvas_height > 1:

                        # Calculate size to fit canvas while maintaining aspect ratio

                        img_ratio = img.width / img.height

                        canvas_ratio = canvas_width / canvas_height

                        

                        if img_ratio > canvas_ratio:

                            new_width = canvas_width - 40

                            new_height = int(new_width / img_ratio)

                        else:

                            new_height = canvas_height - 40

                            new_width = int(new_height * img_ratio)

                        

                        img_resized = img.resize((new_width, new_height), Image.LANCZOS)

                        tkimg = ImageTk.PhotoImage(img_resized)

                        image_refs.clear()

                        image_refs.append(tkimg)  # Keep reference

                        

                        img_canvas.delete("all")

                        x = (canvas_width - new_width) // 2

                        y = (canvas_height - new_height) // 2

                        img_canvas.create_image(x, y, image=tkimg, anchor="nw")

                        

                        # Update info

                        info_text = f"Ảnh {idx + 1}/{len(image_paths)} - {Path(img_path).name}"

                        info_label.config(text=info_text)

                        

                        # Update dots

                        for i, dot in enumerate(dots):

                            if i == idx:

                                dot.config(bg="#ffffff")

                            else:

                                dot.config(bg="#666666")

                except Exception as e:

                    self._log(f"❌ Lỗi cập nhật ảnh: {e}\n")

            

            def next_image():

                current_idx[0] += 1

                update_image()

            

            def prev_image():

                current_idx[0] -= 1

                update_image()

            

            # Left arrow

            left_arrow = tk.Button(nav_frame, text="◀", font=("Arial", 24), bg="#444", fg="white",

                                  relief="flat", width=3, command=prev_image, cursor="hand2")

            left_arrow.pack(side="left", padx=5)

            

            # Right arrow

            right_arrow = tk.Button(nav_frame, text="▶", font=("Arial", 24), bg="#444", fg="white",

                                   relief="flat", width=3, command=next_image, cursor="hand2")

            right_arrow.pack(side="right", padx=5)

            

            # Bottom info bar

            info_frame = tk.Frame(main_container, bg="#2b2b2b")

            info_frame.pack(fill="x", pady=(10, 0))

            

            # Dots indicator

            dots_frame = tk.Frame(info_frame, bg="#2b2b2b")

            dots_frame.pack()

            

            dots = []

            for i in range(len(image_paths)):

                dot = tk.Label(dots_frame, text="●", font=("Arial", 12), bg="#2b2b2b", fg="#666666", 

                             cursor="hand2")

                dot.pack(side="left", padx=3)

                dots.append(dot)

                

                def make_click_handler(index):

                    def click_handler(e):

                        current_idx[0] = index

                        update_image()

                    return click_handler

                

                dot.bind("<Button-1>", make_click_handler(i))

            

            # Info label

            info_label = tk.Label(info_frame, text="", font=("Arial", 10), bg="#2b2b2b", fg="white")

            info_label.pack(pady=(5, 0))

            

            # Keyboard bindings

            modal.bind("<Left>", lambda e: prev_image())

            modal.bind("<Right>", lambda e: next_image())

            modal.bind("<Escape>", lambda e: modal.destroy())

            

            # Initial image load

            modal.after(100, update_image)

            

            # Update on resize

            def on_resize(e):

                update_image()

            

            img_canvas.bind("<Configure>", on_resize)

            

        except Exception as e:

            self._log(f"❌ Lỗi mở cửa sổ preview: {e}\n")



    # _open_full_image removed - full size viewing integrated into carousel modal



    def _get_selected_image_row(self) -> Optional[List[str]]:

        """Get selected row from image table"""

        sel = self.img_tree.selection()

        if not sel:

            return None

        values = list(self.img_tree.item(sel[0], "values"))

        return values



    def _action_open_image(self) -> None:

        """Open selected image"""

        vals = self._get_selected_image_row()

        if not vals or len(vals) < 3:

            return

        path = vals[2]

        if path and os.path.exists(path):

            try:

                os.startfile(path)

            except Exception:

                pass



    def _action_open_image_folder(self) -> None:

        """Open folder containing selected image"""

        vals = self._get_selected_image_row()

        if not vals or len(vals) < 3:

            return

        path = vals[2]

        if path and os.path.exists(path):

            folder = os.path.dirname(path)

            try:

                os.startfile(folder)

            except Exception:

                pass



    def _action_copy_image_path(self) -> None:

        """Copy image path to clipboard"""

        vals = self._get_selected_image_row()

        if not vals or len(vals) < 3:

            return

        path = vals[2]

        if path:

            try:

                self.root.clipboard_clear()

                self.root.clipboard_append(path)

            except Exception:

                pass



    def _action_copy_image_url(self) -> None:

        """Copy image URL to clipboard"""

        vals = self._get_selected_image_row()

        if not vals:

            return

        url_col = vals[2] if len(vals) >= 3 else ""

        try:

            self.root.clipboard_clear()

            self.root.clipboard_append(url_col)

        except Exception:

            pass



