    def _on_mode_change(self) -> None:

        """Switch between Text-to-Video, Image-to-Video, Integrate to Video, and Start-End to Video modes"""

        mode = self.var_generation_mode.get()

        if mode == "Text-to-Video":

            self.text_frame.pack(fill="x", pady=(8, 0))

            self.image_frame.pack_forget()

            self.integrate_frame.pack_forget()

            self.start_end_frame.pack_forget()

        elif mode == "Image-to-Video":

            self.text_frame.pack_forget()

            self.image_frame.pack(fill="x", pady=(8, 0))

            self.integrate_frame.pack_forget()

            self.start_end_frame.pack_forget()

        elif mode == "Start-End to Video":

            self.text_frame.pack_forget()

            self.image_frame.pack_forget()

            self.integrate_frame.pack_forget()

            self.start_end_frame.pack(fill="x", pady=(8, 0))

        else:  # Integrate to Video

            self.text_frame.pack_forget()

            self.image_frame.pack_forget()

            self.integrate_frame.pack(fill="x", pady=(8, 0))

            self.start_end_frame.pack_forget()



