    def _collect_start_end_tasks(self) -> List[ImageTask]:

        """Thu thập tasks cho Start-End to Video - tái sử dụng ImageTask"""

        try:

            # Lấy thông tin từ UI

            images_folder = self.ent_start_end_folder.get().strip()

            prompt_file = self.ent_start_end_prompt_file.get().strip()

            

            if not images_folder or not prompt_file:

                self._log("❌ Vui lòng chọn thư mục ảnh và file prompt\n")

                return []

            

            # Kiểm tra file tồn tại

            if not Path(images_folder).exists():

                self._log(f"❌ Thư mục ảnh không tồn tại: {images_folder}\n")

                return []

            

            if not Path(prompt_file).exists():

                self._log(f"❌ File prompt không tồn tại: {prompt_file}\n")

                return []

            

            # Đọc prompts

            with open(prompt_file, 'r', encoding='utf-8') as f:

                prompts = [line.strip() for line in f.readlines() if line.strip() and not line.strip().startswith('#')]

            

            if not prompts:

                self._log("❌ File prompt trống hoặc không có prompt hợp lệ\n")

                return []

            

            # Tìm ảnh và sắp xếp theo natural sort

            image_files = []

            image_extensions = {'.jpg', '.jpeg', '.png', '.bmp', '.gif', '.webp'}

            

            for file_path in Path(images_folder).iterdir():

                if file_path.is_file() and file_path.suffix.lower() in image_extensions:

                    image_files.append(str(file_path))

            

            if len(image_files) < 2:

                self._log("❌ Cần ít nhất 2 ảnh (start + end)\n")

                return []

            

            # Natural sort

            def natural_sort_key(filename):

                parts = re.split(r'(\d+)', Path(filename).name)

                return [int(part) if part.isdigit() else part.lower() for part in parts]

            

            image_files.sort(key=lambda x: natural_sort_key(x))

            

            # Tạo ImageTask objects (2 ảnh = 1 task)

            tasks = []

            for i in range(0, len(image_files) - 1, 2):

                if i + 1 < len(image_files):

                    start_image = image_files[i]

                    end_image = image_files[i + 1]

                    prompt_index = len(tasks) % len(prompts)  # Lặp lại prompts nếu cần

                    

                    # Tạo ImageTask với start_image làm image_path chính

                    # end_image sẽ được lưu trong task.end_image_path

                    task = ImageTask(

                        task_index=len(tasks) + 1,

                        prompt_text=prompts[prompt_index],

                        image_path=start_image,

                        end_image_path=end_image  # Thêm field này

                    )

                    tasks.append(task)

            

            self._log(f"📸 Tìm thấy {len(image_files)} ảnh, tạo {len(tasks)} start-end tasks\n")

            return tasks

            

        except Exception as e:

            self._log(f"❌ Lỗi thu thập start-end tasks: {e}\n")

            return []



