    def _on_integrate_group_size_changed(self, event=None) -> None:

        """Handle integrate group size change"""

        try:

            group_size = int(self.cmb_integrate_images_per_group.get())

            self._log(f"🔢 Đã chọn {group_size} ảnh mỗi nhóm\n")

        except Exception:

            pass



    def _collect_integrate_prompts(self) -> List[Dict]:

        """Collect and merge prompts with images for integrate video generation"""

        # Validate inputs

        images_folder = self.ent_integrate_images_folder.get().strip()

        prompt_file = self.ent_integrate_prompt_file.get().strip()

        

        if not images_folder or not os.path.exists(images_folder):

            Messagebox.show_error("Vui lòng chọn thư mục chứa ảnh hợp lệ.")

            return []

            

        if not prompt_file or not os.path.exists(prompt_file):

            Messagebox.show_error("Vui lòng chọn file txt chứa prompt hợp lệ.")

            return []



        # Get group size from combobox

        try:

            images_per_group = int(self.cmb_integrate_images_per_group.get())

        except Exception:

            images_per_group = 3  # Default

        

        self._log(f"📐 Số ảnh mỗi nhóm: {images_per_group}\n")



        # Read prompts from file

        try:

            with open(prompt_file, 'r', encoding='utf-8') as f:

                prompts = [line.strip() for line in f if line.strip()]

        except Exception as e:

            Messagebox.show_error(f"Lỗi đọc file prompt: {e}")

            return []



        # Get all image files and sort by numeric prefix

        image_extensions = {'.jpg', '.jpeg', '.png', '.bmp', '.gif', '.webp'}

        image_files = []

        import re

        

        for file in os.listdir(images_folder):

            if any(file.lower().endswith(ext) for ext in image_extensions):

                full_path = os.path.join(images_folder, file)

                # Extract numeric prefix for sorting

                match = re.match(r'^(\d+)', file)

                if match:

                    numeric_prefix = int(match.group(1))

                    image_files.append((numeric_prefix, full_path))

            else:

                    self._log(f"⚠️ Bỏ qua ảnh không có số thứ tự ở đầu: '{file}'\n")

        

        # Sort images by numeric prefix

        image_files.sort(key=lambda x: x[0])

        sorted_image_paths = [path for _, path in image_files]

        

        self._log(f"🔍 Tìm thấy {len(sorted_image_paths)} ảnh có số thứ tự:\n")

        for num, path in image_files:

            self._log(f"  - {num}: {os.path.basename(path)}\n")



        # Debug: Show all prompts

        self._log(f"🔍 Các prompt tìm thấy:\n")

        for i, prompt in enumerate(prompts, 1):

            self._log(f"  {i}. '{prompt}'\n")



        # Group images into chunks based on images_per_group

        # Group 1: images 1, 2, 3

        # Group 2: images 4, 5, 6

        # Group 3: images 7, 8, 9...

        tasks = []

        for prompt_index, prompt in enumerate(prompts, 1):

            # Calculate which images belong to this group

            start_idx = (prompt_index - 1) * images_per_group

            end_idx = start_idx + images_per_group

            

            group_images = sorted_image_paths[start_idx:end_idx]

            

            if group_images:  # At least 1 image

                tasks.append({

                'prefix': str(prompt_index),

                    'prompt': prompt,

                'images': group_images

                })

                image_names = [os.path.basename(img) for img in group_images]

                self._log(f"✅ Nhóm {prompt_index}: {len(group_images)} ảnh ({', '.join(image_names)}) ↔ '{prompt[:50]}...'\n")

            else:

                self._log(f"⚠️ Nhóm {prompt_index}: Không đủ ảnh (cần ảnh từ {start_idx+1} đến {end_idx}, chỉ có {len(sorted_image_paths)} ảnh)\n")



        # Summary

        total_images_needed = len(prompts) * images_per_group

        self._log(f"\n📊 Tóm tắt:\n")

        self._log(f"  • {len(prompts)} prompt(s)\n")

        self._log(f"  • {images_per_group} ảnh/nhóm\n")

        self._log(f"  • {len(sorted_image_paths)} ảnh có sẵn\n")

        self._log(f"  • {total_images_needed} ảnh cần thiết\n")

        self._log(f"  • {len(tasks)} nhóm đã tạo thành công\n")

        

        if len(sorted_image_paths) < total_images_needed:

            self._log(f"⚠️ Cảnh báo: Thiếu {total_images_needed - len(sorted_image_paths)} ảnh!\n")

        

        return tasks



    def _run_integrate_sequential(self, tasks: List[Dict]) -> None:

        """Run integrate video tasks sequentially"""

        try:

            for i, task in enumerate(tasks):

                if self.stop_event.is_set():

                    break

                    

                self._log(f"🔄 Xử lý task {i+1}/{len(tasks)}: {task['prefix']}\n")

                self._process_integrate_task(task, i+1)

                

        except Exception as e:

            self._log(f"❌ Lỗi xử lý integrate sequential: {e}\n")

        finally:

            self._schedule(self._finish_run)



    def _run_integrate_parallel(self, tasks: List[Dict]) -> None:

        """Run integrate video tasks in parallel"""

        try:

            if not self.executor:

                return

                

            # Submit all tasks

            future_to_task = {}

            for i, task in enumerate(tasks):

                if self.stop_event.is_set():

                    break

                    

                future = self.executor.submit(self._process_integrate_task, task, i+1)

                future_to_task[future] = task

                

            # Wait for completion

            for future in as_completed(future_to_task):

                if self.stop_event.is_set():

                    break

                    

                task = future_to_task[future]

                try:

                    future.result()

                except Exception as e:

                    self._log(f"❌ Lỗi task {task['prefix']}: {e}\n")

                    

        except Exception as e:

            self._log(f"❌ Lỗi xử lý integrate parallel: {e}\n")

        finally:

            self._schedule(self._finish_run)



    def _process_integrate_task(self, task: Dict, task_index: int) -> None:

        """Process a single integrate video task"""

        try:

            prefix = task['prefix']

            prompt = task['prompt']

            images = task['images']

            

            self._log(f"🎬 Xử lý {prefix}: {len(images)} ảnh + '{prompt}'\n")

            

            # Add to results table

            item_id = self.tree.insert("", "end", values=(

                prompt,

                f"scene_{task_index}",

                f"Integrate {prefix}",

                "Đang xử lý...",

                "",

                "Chờ..."

            ))

            

            # Apply status color

            self.tree.set(item_id, "status", "Đang xử lý...")

            self.tree.item(item_id, tags=("processing",))

            

            # Upload images and get media IDs

            self._log(f"📤 Bắt đầu upload {len(images)} ảnh cho {prefix}...\n")

            media_ids = []

            for i, image_path in enumerate(images, 1):

                self._log(f"📤 Upload ảnh {i}/{len(images)}: {os.path.basename(image_path)}\n")

                media_id = self._upload_image_for_integrate(image_path)

                if media_id:

                    media_ids.append(media_id)

                    self._log(f"✅ Upload thành công ảnh {i}: {media_id}\n")

                else:

                    self._log(f"❌ Upload thất bại ảnh {i}: {os.path.basename(image_path)}\n")

                    

            if not media_ids:

                self._log(f"❌ Không thể upload ảnh nào cho {prefix}\n")

                self.tree.set(item_id, "status", "Lỗi upload ảnh")

                self.tree.item(item_id, tags=("error",))

                return

                

            self._log(f"✅ Đã upload thành công {len(media_ids)}/{len(images)} ảnh cho {prefix}\n")

            

            # Update status to "Đang tạo video"

            self.tree.set(item_id, "status", "Đang tạo video...")

            self.tree.item(item_id, tags=("processing",))

            

            # Generate video using integrate payload

            result = self._generate_integrate_video(prefix, prompt, media_ids, task_index)

            

            if result and result.get('success'):

                operations = result.get('operations', [])

                if operations:

                    # Update status to "Đang tạo video"

                    self.tree.set(item_id, "status", "Đang tạo video...")

                    self.tree.item(item_id, tags=("processing",))

                    

                    # Poll operations for completion (tham khảo từ tab Image to Video)

                    self._log(f"🔄 Bắt đầu poll operations cho {prefix}...\n")

                    final_result = self._poll_integrate_operations(operations, prefix, item_id)

                    

                    if final_result and final_result.get('success'):

                        self.tree.set(item_id, "status", "Hoàn thành")

                        

                        # Hiển thị đường dẫn file đã tải về nếu có

                        downloaded_path = final_result.get('downloaded_path')

                        if downloaded_path:

                            self.tree.set(item_id, "file", str(downloaded_path))

                            self._log(f"✅ Hoàn thành {prefix} - Video đã lưu: {downloaded_path.name}\n")

                        else:

                            self.tree.set(item_id, "file", final_result.get('video_url', ''))

                            self._log(f"✅ Hoàn thành {prefix}\n")

                        

                        self.tree.set(item_id, "action", "Xem")

                        self.tree.item(item_id, tags=("success",))

                    else:

                        self.tree.set(item_id, "status", "Lỗi tạo video")

                        self.tree.item(item_id, tags=("error",))

                        self._log(f"❌ Lỗi tạo video cho {prefix}\n")

                else:

                    self.tree.set(item_id, "status", "Lỗi tạo video")

                    self.tree.item(item_id, tags=("error",))

                    self._log(f"❌ Không có operations cho {prefix}\n")

            else:

                self.tree.set(item_id, "status", "Lỗi tạo video")

                self.tree.item(item_id, tags=("error",))

                self._log(f"❌ Lỗi tạo video cho {prefix}\n")

                

        except Exception as e:

            self._log(f"❌ Lỗi xử lý task {task.get('prefix', 'unknown')}: {e}\n")

            # Update status to error

            try:

                self.tree.set(item_id, "status", "Lỗi")

                self.tree.item(item_id, tags=("error",))

            except:

                pass



    def _upload_image_for_integrate(self, image_path: str) -> Optional[str]:

        """Upload image and return media ID for integrate video - tham khảo từ tab Image to Video"""

        try:

            # Get client from cookies

            cookies = self._get_cookies_source()

            if not cookies:

                self._log(f"❌ Không có cookies để upload ảnh\n")

                return None

                

            client = LabsFlowClient(_parse_cookie_string(cookies))

            

            # Thử lấy access token nhiều lần nếu thất bại

            max_retries = 3

            for attempt in range(max_retries):

                if client.fetch_access_token():

                    break

                else:

                    self._log(f"⚠️ Lần thử {attempt + 1}/{max_retries}: Không lấy được access token\n")

                    if attempt < max_retries - 1:

                        _t.sleep(2)  # Chờ 2 giây trước khi thử lại

                    else:

                        self._log(f"❌ Không lấy được access token sau {max_retries} lần thử\n")

                        return None



            # Prepare image with proper aspect ratio (tham khảo từ tab Image to Video)

            processed_image_path = self._prepare_image_for_upload(image_path)

            

            self._log(f"📤 Upload ảnh: {os.path.basename(image_path)}\n")

            media_id = client.upload_image(processed_image_path)

            

            if media_id:

                self._log(f"✅ Upload thành công: {media_id}\n")

                return media_id

            else:

                self._log(f"❌ Upload thất bại cho {os.path.basename(image_path)}\n")

                return None

                

        except Exception as e:

            self._log(f"❌ Lỗi upload ảnh {image_path}: {e}\n")

            return None



    def _generate_integrate_video(self, prefix: str, prompt: str, media_ids: List[str], task_index: int) -> Optional[Dict]:

        """Generate video using integrate payload with model veo_3_0_r2v_fast_ultra"""

        try:

            # Get client from cookies

            cookies = self._get_cookies_source()

            if not cookies:

                self._log(f"❌ Không có cookies để generate video\n")

                return None

                

            client = LabsFlowClient(_parse_cookie_string(cookies))

            

            # Thử lấy access token nhiều lần nếu thất bại

            max_retries = 3

            for attempt in range(max_retries):

                if client.fetch_access_token():

                    break

                else:

                    self._log(f"⚠️ Lần thử {attempt + 1}/{max_retries}: Không lấy được access token\n")

                    if attempt < max_retries - 1:

                        _t.sleep(2)  # Chờ 2 giây trước khi thử lại

                    else:

                        self._log(f"❌ Không lấy được access token sau {max_retries} lần thử\n")

                        return None



            # Validate media_ids before building payload

            if not media_ids or len(media_ids) == 0:

                self._log(f"❌ Không có media_ids hợp lệ để generate video\n")

                return None

            

            # Filter out invalid media_ids

            valid_media_ids = [mid for mid in media_ids if mid and isinstance(mid, str) and len(mid.strip()) > 0]

            if len(valid_media_ids) != len(media_ids):

                self._log(f"⚠️ Filtered invalid media_ids: {len(media_ids)} → {len(valid_media_ids)}\n")

                media_ids = valid_media_ids

            

            if not media_ids:

                self._log(f"❌ Không có media_ids hợp lệ sau khi filter\n")

                return None

            

            # Create payload according to the specified format (bỏ projectId)
            import time as _t
            session_id = f";{int(_t.time() * 1000)}"
            payload = {

                "mediaGenerationContext": {"batchId": str(uuid.uuid4())},

                "clientContext": {

                    "tool": "PINHOLE",

                    "userPaygateTier": "PAYGATE_TIER_TWO",

                    "sessionId": session_id,  # ✅ Thêm sessionId theo format WebUI

                },

                "requests": [

                    {

                        "aspectRatio": "VIDEO_ASPECT_RATIO_LANDSCAPE",

                        "metadata": {},  # ✅ Metadata rỗng theo format WebUI

                        "referenceImages": [

                            {

                                "imageUsageType": "IMAGE_USAGE_TYPE_ASSET",

                                "mediaId": media_id.strip()  # Ensure no whitespace

                            } for media_id in media_ids

                        ],

                        "seed": int(_t.time()) % 100000,

                        "textInput": {
                            "structuredPrompt": {
                                "parts": [{"text": prompt}]
                            }
                        },  # ✅ Dùng structuredPrompt theo format WebUI

                        "videoModelKey": "veo_3_0_r2v_fast_ultra"

                    }

                ],

                "useV2ModelConfig": True,

            }

            

            self._log(f"🚀 Gửi payload cho {prefix} với model veo_3_0_r2v_fast_ultra\n")

            self._log(f"📋 Payload: {len(media_ids)} ảnh, prompt: '{prompt[:50]}...'\n")

            

            # Send actual API request

            url = "https://aisandbox-pa.googleapis.com/v1/video:batchAsyncGenerateVideoReferenceImages"

            headers = client._aisandbox_headers()

            

            self._log(f"🌐 Gửi request đến: {url}\n")

            self._log(f"📤 Headers: {len(headers)} headers\n")

            

            response = client.session.post(url, headers=headers, json=payload, timeout=120)

            

            self._log(f"📥 Response status: {response.status_code}\n")

            

            if response.status_code == 200:

                result = response.json()

                self._log(f"✅ Request thành công cho {prefix}\n")

                self._log(f"📋 Response: {str(result)[:200]}...\n")

                

                # Extract operations from response

                operations = result.get('operations', [])

                if operations:

                    self._log(f"🎬 Nhận được {len(operations)} operation(s) cho {prefix}\n")

                    return {

                        'success': True,

                        'operations': operations,

                        'prefix': prefix,

                        'task_index': task_index

                    }

                else:

                    self._log(f"⚠️ Không có operations trong response cho {prefix}\n")

                    return None

            else:

                self._log(f"❌ Request thất bại cho {prefix}: {response.status_code}\n")

                self._log(f"📋 Error response: {response.text[:200]}...\n")

                return None

            

        except Exception as e:

            self._log(f"❌ Lỗi generate video cho {prefix}: {e}\n")

            return None



    def _poll_integrate_operations(self, operations: List[Dict], prefix: str, item_id: str) -> Optional[Dict]:

        """Poll operations for completion - tham khảo từ tab Text to Video"""

        try:

            # Get client from cookies

            cookies = self._get_cookies_source()

            if not cookies:

                self._log(f"❌ Không có cookies để poll operations\n")

                return None

                

            client = LabsFlowClient(_parse_cookie_string(cookies))

            

            # Thử lấy access token nhiều lần nếu thất bại

            max_retries = 3

            for attempt in range(max_retries):

                if client.fetch_access_token():

                    break

                else:

                    self._log(f"⚠️ Lần thử {attempt + 1}/{max_retries}: Không lấy được access token\n")

                    if attempt < max_retries - 1:

                        _t.sleep(2)  # Chờ 2 giây trước khi thử lại

                    else:

                        self._log(f"❌ Không lấy được access token sau {max_retries} lần thử\n")

                        return None



            max_wait = 300  # 5 minutes

            poll_interval = 5  # 5 seconds

            deadline = _t.time() + max_wait

            last_status = None

            

            self._log(f"🔄 Polling {len(operations)} operations cho {prefix}...\n")

            

            while _t.time() < deadline and not self.stop_event.is_set():

                # Sử dụng client.check_video_status() như tab Text to Video

                status = client.check_video_status(operations)

                if status is not None:

                    last_status = status

                    # Log response

                    self._log(f"📋 Status response: {str(status)[:200]}...\n")

                    

                    # Kiểm tra hoàn tất

                    if isinstance(status, dict) and "operations" in status:

                        total = len(status["operations"]) or len(operations)

                        done = 0

                        failed = 0

                        active = 0

                        

                        for i, op in enumerate(status["operations"]):

                            s = str(op.get("status", "")).upper()

                            if "COMPLETE" in s or "SUCCESS" in s:

                                done += 1

                                # Extract video URL từ operation hoàn thành

                                video_url = None

                                if 'videoUrl' in op:

                                    video_url = op['videoUrl']

                                elif 'url' in op:

                                    video_url = op['url']

                                

                                if video_url:

                                    self._log(f"🎬 Video URL cho {prefix}: {video_url}\n")

                                    

                                    # Tải về video (tham khảo từ tab Text to Video và Image to Video)

                                    downloaded_path = self._download_integrate_video(video_url, prefix, i+1)

                                    

                                    # Extract mediaGenerationId

                                    media_id = self._extract_media_id_from_operation(op)

                                    result = {

                                        'success': True,

                                        'video_url': video_url,

                                        'downloaded_path': downloaded_path,

                                        'operation': op.get('operation', {}).get('name', f'operation_{i}'),

                                        'media_id': media_id

                                    }

                                    # Don't store media_id here - it's already stored in process_one_video

                                    # to avoid duplicates when running concurrently

                                    return result

                                else:

                                    # Log full operation data để debug

                                    self._log(f"📋 Operation data: {str(op)[:200]}...\n")

                                    

                                    # Thử extract video URL từ metadata hoặc response

                                    video_url_from_metadata = self._extract_video_url_from_operation(op)

                                    if video_url_from_metadata:

                                        self._log(f"🎬 Video URL từ metadata cho {prefix}: {video_url_from_metadata}\n")

                                        

                                        # Tải về video

                                        downloaded_path = self._download_integrate_video(video_url_from_metadata, prefix, i+1)

                                        

                                        # Extract mediaGenerationId

                                        media_id = self._extract_media_id_from_operation(op)

                                        result = {

                                            'success': True,

                                            'video_url': video_url_from_metadata,

                                            'downloaded_path': downloaded_path,

                                            'operation': op.get('operation', {}).get('name', f'operation_{i}'),

                                            'media_id': media_id

                                        }

                                        # Don't store media_id here - it's already stored in process_one_video

                                        # to avoid duplicates when running concurrently

                                        return result

                                    else:

                                        return {

                                            'success': True,

                                            'video_url': f"video_{prefix}_{i}.mp4",  # Fallback

                                            'downloaded_path': None,

                                            'operation': op.get('operation', {}).get('name', f'operation_{i}')

                                        }

                            elif "FAIL" in s or "ERROR" in s:

                                failed += 1

                                # Extract error message if available

                                error_msg = "Unknown error"

                                if "error" in op:

                                    error_info = op.get("error", {})

                                    if isinstance(error_info, dict):

                                        error_msg = error_info.get("message", str(error_info))

                                    else:

                                        error_msg = str(error_info)

                                elif "operation" in op and isinstance(op.get("operation"), dict):

                                    op_error = op["operation"].get("error", {})

                                    if isinstance(op_error, dict):

                                        error_msg = op_error.get("message", str(op_error))

                                

                                self._log(f"❌ Operation {i+1} thất bại cho {prefix}: {error_msg}\n")

                                

                                # If error is "Video not found", it might be a temporary issue

                                # Log more details for debugging

                                if "not found" in error_msg.lower() or "video not found" in error_msg.lower():

                                    self._log(f"⚠️ 'Video not found' error - có thể do media_ids chưa sẵn sàng hoặc không hợp lệ\n")

                                    self._log(f"📋 Operation details: {str(op)[:300]}...\n")

                                

                                return None

                            elif "ACTIVE" in s or "RUNNING" in s or "PENDING" in s:

                                active += 1

                                self._log(f"⏳ Operation {i+1} đang xử lý cho {prefix}...\n")



                        # Extend deadline if videos are still actively processing

                        if active > 0 and _t.time() > deadline - 30:  # Less than 30s left

                            deadline += 60  # Extend by 1 minute

                            self._log(f"⏰ Video vẫn đang xử lý, gia hạn thêm 60s...\n")



                        if done + failed >= total:

                            self._log(f"✅ Tất cả operations hoàn thành cho {prefix}\n")

                            break

                

                _t.sleep(poll_interval)

            

            if self.stop_event.is_set():

                self._log(f"⏹️ Dừng polling cho {prefix}\n")

                return None

            

            if _t.time() >= deadline:

                self._log(f"⏰ Timeout polling cho {prefix}\n")

                return None

            

            return None

            

        except Exception as e:

            self._log(f"❌ Lỗi polling operations cho {prefix}: {e}\n")

            return None



    def _download_integrate_video(self, video_url: str, prefix: str, video_index: int) -> Optional[Path]:

        """Download video for integrate mode - tham khảo từ tab Text to Video và Image to Video"""

        try:

            # Lấy output directory từ UI

            out_dir_str = self.ent_output.get().strip() if hasattr(self, "ent_output") else ""

            if not out_dir_str:

                out_dir = Path.cwd() / "downloaded_videos"

            else:

                out_dir = Path(out_dir_str)

            

            out_dir.mkdir(parents=True, exist_ok=True)

            

            # Tạo tên file an toàn từ prefix

            safe_prefix = "".join(ch for ch in prefix[:30] if ch.isalnum() or ch in (" ", "-", "_"))

            safe_prefix = safe_prefix.strip().replace(" ", "_") or f"integrate_{prefix}"

            

            # Tạo filename

            filename = out_dir / f"{safe_prefix}_{video_index}"

            filename = self._ensure_unique_filename(filename)

            

            self._log(f"📥 Bắt đầu tải video: {video_url}\n")

            self._log(f"📁 Lưu tại: {filename}\n")

            

            # Tải về video sử dụng phương thức đã có

            self._download_via_requests_simple(video_url, filename)

            

            # Kiểm tra file đã tải về thành công

            if filename.exists() and filename.stat().st_size > 0:

                file_size = filename.stat().st_size

                self._log(f"✅ Tải thành công: {filename.name} ({file_size//1024}KB)\n")

                return filename

            else:

                self._log(f"❌ File tải về rỗng hoặc không tồn tại: {filename.name}\n")

                return None

                

        except Exception as e:

            self._log(f"❌ Lỗi tải video cho {prefix}: {e}\n")

            return None



    def _extract_video_url_from_operation(self, op: Dict) -> Optional[str]:

        """Extract video URL from operation metadata - tham khảo từ tab Text to Video"""

        try:

            # Sử dụng _extract_file_urls() như tab Text to Video

            urls = _extract_file_urls(op)

            if urls:

                # Ưu tiên URL có .mp4

                for url in urls:

                    if '.mp4' in url.lower():

                        return url

                # Nếu không có .mp4, lấy URL đầu tiên

                return urls[0]

            

            # Fallback: Thử extract từ operation name (có thể là media ID)

            operation = op.get('operation', {})

            if isinstance(operation, dict):

                operation_name = operation.get('name', '')

                if operation_name and operation_name.startswith('CAUSJ'):

                    # Đây có thể là media ID, cần convert thành URL

                    # Format: https://storage.googleapis.com/aisandbox-media/...

                    return f"https://storage.googleapis.com/aisandbox-media/{operation_name}"

            

            return None

            

        except Exception as e:

            self._log(f"❌ Lỗi extract video URL từ operation: {e}\n")

            return None

    

    def _prepare_image_path_for_upload(self, image_path: str) -> str:

        """Prepare image path for upload - handle special characters and ensure valid format"""

        try:

            from PIL import Image

            import tempfile

            import shutil

            

            img_path = Path(image_path)

            if not img_path.exists():

                self._sync_log_error(f"  ❌ Image not found: {image_path}")

                return image_path

            

            filename = img_path.name

            needs_processing = False

            temp_path = None

            

            # Check if filename contains non-ASCII characters

            try:

                filename.encode('ascii')

                filename_is_safe = True

            except UnicodeEncodeError:

                filename_is_safe = False

                needs_processing = True

            

            # Check image format and size

            try:

                with Image.open(img_path) as img:

                    # Check if image is valid

                    img.verify()

                    

                    # Reopen to get actual image (verify closes it)

                    img = Image.open(img_path)

                    width, height = img.size

                    file_size = img_path.stat().st_size

                    

                    # Check if image is too large (>10MB) or dimensions too large

                    if file_size > 10 * 1024 * 1024:

                        needs_processing = True  # Will resize

                    if width > 4096 or height > 4096:

                        needs_processing = True  # Will resize

                    

                    # Check format - ensure it's JPEG or PNG

                    format_lower = img.format and img.format.lower()

                    if format_lower not in ('jpeg', 'jpg', 'png'):

                        needs_processing = True  # Will convert to JPEG

                    

                    # Check mode - RGBA/LA/P need conversion

                    if img.mode in ('RGBA', 'LA', 'P'):

                        needs_processing = True

                    

                    img.close()

            except Exception as e:

                self._sync_log_error(f"  ⚠️ Error checking image: {e}")

                needs_processing = True

            

            # If filename is safe and format is OK, return original

            if filename_is_safe and not needs_processing:

                return str(img_path)

            

            # Need to create temp file

            temp_dir = Path(tempfile.gettempdir())

            

            # Generate safe filename

            if filename_is_safe:

                safe_name = filename.rsplit('.', 1)[0]  # Remove extension

                safe_name = "".join(c if c.isalnum() or c in ('-', '_') else '_' for c in safe_name[:50])

            else:

                safe_name = "".join(c if c.isalnum() or c in ('-', '_') else '_' for c in filename[:50])

            

            safe_name = safe_name.strip('_')

            if not safe_name:

                safe_name = "upload_image"

            

            # Use JPEG for temp file (most compatible)

            temp_path = temp_dir / f"{safe_name}_{int(_t.time() * 1000)}.jpg"

            

            # Process image if needed

            try:

                with Image.open(img_path) as img:

                    # Convert to RGB if needed (for formats like RGBA)

                    if img.mode in ('RGBA', 'LA', 'P'):

                        rgb_img = Image.new('RGB', img.size, (255, 255, 255))

                        if img.mode == 'P':

                            img = img.convert('RGBA')

                        rgb_img.paste(img, mask=img.split()[-1] if img.mode in ('RGBA', 'LA') else None)

                        img = rgb_img

                    elif img.mode != 'RGB':

                        img = img.convert('RGB')

                    

                    # Resize if too large (max 4096px on longest side, maintain aspect ratio)

                    max_size = 4096

                    if max(img.size) > max_size:

                        ratio = max_size / max(img.size)

                        new_size = (int(img.size[0] * ratio), int(img.size[1] * ratio))

                        img = img.resize(new_size, Image.Resampling.LANCZOS)

                        self._sync_log_info(f"  📏 Resized from {img.size} to {new_size}")

                    

                    # Ensure reasonable file size (max 5MB for upload)

                    # Save as JPEG with quality adjustment

                    quality = 95

                    for attempt in range(3):

                        img.save(temp_path, 'JPEG', quality=quality, optimize=True)

                        file_size_mb = temp_path.stat().st_size / 1024 / 1024

                        

                        if file_size_mb <= 5.0:

                            break  # File size OK

                        

                        # Reduce quality if too large

                        quality = max(70, quality - 10)

                        self._sync_log_info(f"  📉 File too large ({file_size_mb:.2f}MB), reducing quality to {quality}")

                    

                    # Verify saved file is valid

                    try:

                        with Image.open(temp_path) as verify_img:

                            verify_img.verify()

                    except Exception as verify_err:

                        self._sync_log_error(f"  ❌ Saved image is invalid: {verify_err}")

                        raise

                

                self._sync_log_info(f"  📋 Prepared image: {temp_path.name} (original: {filename})")

                return str(temp_path)

                

            except Exception as e:

                self._sync_log_error(f"  ⚠️ Error processing image: {e}, trying simple copy")

                # Fallback: just copy with safe name

                try:

                    shutil.copy2(img_path, temp_path)

                    return str(temp_path)

                except:

                    return str(img_path)

                

        except Exception as e:

            self._sync_log_error(f"  ⚠️ Error preparing image path: {e}, using original")

            return image_path

    

    def _extract_media_id_from_operation(self, op: Dict) -> Optional[str]:

        """Extract mediaGenerationId from operation - tham khảo từ extend_videos.py"""

        try:

            # Try multiple paths to find mediaGenerationId

            # Path 1: operation.metadata.video.mediaGenerationId

            metadata = op.get("operation", {}).get("metadata", {})

            if isinstance(metadata, dict):

                video_data = metadata.get("video", {})

                if isinstance(video_data, dict):

                    media_id = video_data.get("mediaGenerationId")

                    if media_id:

                        return media_id

            

            # Path 2: operation.name (could be media ID)

            operation = op.get("operation", {})

            if isinstance(operation, dict):

                operation_name = operation.get("name", "")

                # Media IDs often start with specific prefixes

                if operation_name and (operation_name.startswith("CAUSJ") or len(operation_name) > 40):

                    # Check if it's a media ID format

                    return operation_name

            

            # Path 3: Search recursively

            mgids = _extract_strings_recursive(op, ("mediaId", "mediaGenerationId", "name"))

            if mgids:

                for mgid in mgids:

                    # Filter valid media IDs (usually long strings starting with CAUSJ or similar)

                    if isinstance(mgid, str) and len(mgid) > 20:

                        return mgid

            

            return None

            

        except Exception as e:

            self._sync_log_error(f"❌ Error extracting media ID: {e}")

            return None



