    def on_run(self) -> None:

        if self.executor is not None:

            # already running

            return



        try:

            # Xác thực đơn giản

            if not self._get_cookies_source():

                Messagebox.show_error("Vui lòng nhập Cookie hợp lệ.")

                return



            # Check generation mode

            generation_mode = self.var_generation_mode.get()

            self._log(f"🔧 Chế độ: {generation_mode}\n")



            # Prepare tasks based on generation mode

            # Prepare tasks based on generation mode

            if generation_mode == "Text-to-Video":

                # Collect text prompts as tasks

                tasks = self._collect_prompts()



            elif generation_mode == "Image-to-Video":

                # For Image-to-Video, collect image tasks with enhanced matching

                self._log("🔧 Bắt đầu thu thập Image-to-Video tasks...\n")

                tasks = self._collect_image_tasks()

                self._log(f"🔧 Đã thu thập {len(tasks)} Image-to-Video tasks\n")



            elif generation_mode == "Start-End to Video":

                # For Start-End to Video, collect start-end tasks

                self._log("🔧 Bắt đầu thu thập Start-End to Video tasks...\n")

                tasks = self._collect_start_end_tasks()

                self._log(f"🔧 Đã thu thập {len(tasks)} Start-End to Video tasks\n")



            else:  # Integrate to Video

                # For Integrate to Video, collect integrate prompts as tasks

                self._log("🔧 Bắt đầu thu thập tasks cho Integrate to Video...\n")

                tasks = self._collect_integrate_prompts()

                self._log(f"🔧 Đã thu thập {len(tasks)} tasks\n")



            out_dir = self.ent_output.get().strip()

            if not out_dir:

                Messagebox.show_error("Vui lòng chọn thư mục xuất.")

                return

            Path(out_dir).mkdir(parents=True, exist_ok=True)

            # Validate tasks

            if not tasks:

                Messagebox.show_error("Không có task nào để xử lý. Vui lòng kiểm tra lại cấu hình.")

                return

            self._log(f"🔧 Bắt đầu xử lý {len(tasks)} tasks...\n")



            # Disable inputs tạm thời

            self._set_controls_state("disabled")

            with suppress(Exception):

                self.btn_run.configure(state="disabled")

                self.btn_stop.configure(state="normal")

            self.stop_event.clear()

            self._log(f"Bắt đầu xử lý {generation_mode}...\n")



            # Determine desired workers from UI setting (and mode)

            try:

                if hasattr(self, "cmb_mode") and self.cmb_mode.get().strip().lower() == "song song":

                    desired_workers = self._get_concurrent_jobs_value() 

                else:

                    desired_workers = 1

            except Exception:

                desired_workers = self._get_concurrent_jobs_value()



            # Ensure tasks variable exists and is a list

            try:

                tasks_len = len(tasks) if isinstance(tasks, (list, tuple)) else 0

            except Exception:

                tasks_len = 0



            # Cap worker count sensibly: no more than number of tasks

            max_workers = max(1, min(desired_workers, max(1, tasks_len)))



            # Create executor with explicit max_workers to avoid default (which may be 12)

            try:

                self.executor = ThreadPoolExecutor(max_workers=max_workers)

            except Exception:

                # fallback to safe single-threaded executor

                self.executor = ThreadPoolExecutor(max_workers=1)



            self._log(f"🔧 Sử dụng {max_workers} worker (yêu cầu: {desired_workers}, tác vụ: {tasks_len})\n")



            # Dọn bảng

            for item in self.tree.get_children():

                self.tree.delete(item)



            # Get mode from combobox

            mode = self.cmb_mode.get()



            # Lên lịch tác vụ theo loại

            # Lên lịch tác vụ theo loại

            if generation_mode == "Text-to-Video":

                if mode == "Tuần tự":

                    threading.Thread(target=self._run_sequential, args=(tasks,), daemon=True).start()

                else:

                    threading.Thread(target=self._run_parallel, args=(tasks,), daemon=True).start()



            elif generation_mode == "Image-to-Video":

                if mode == "Tuần tự":

                    threading.Thread(target=self._run_image_sequential, args=(tasks,), daemon=True).start()

                else:

                    threading.Thread(target=self._run_image_parallel, args=(tasks,), daemon=True).start()



            elif generation_mode == "Start-End to Video":

                # Tái sử dụng logic Image-to-Video

                if mode == "Tuần tự":

                    threading.Thread(target=self._run_image_sequential, args=(tasks,), daemon=True).start()

                else:

                    threading.Thread(target=self._run_image_parallel, args=(tasks,), daemon=True).start()



            elif generation_mode == "Integrate to Video":

                if mode == "Tuần tự":

                    threading.Thread(target=self._run_integrate_sequential, args=(tasks,), daemon=True).start()

                else:

                    threading.Thread(target=self._run_integrate_parallel, args=(tasks,), daemon=True).start()





        except Exception as e:

            self._log(f"❌ Lỗi trong on_run: {e}\n")

            Messagebox.show_error(f"Lỗi khi bắt đầu xử lý: {e}")

            # Khôi phục trạng thái controls

            self._set_controls_state("normal")

            with suppress(Exception):

                self.btn_run.configure(state="normal")

                self.btn_stop.configure(state="disabled")



    def on_stop(self) -> None:

        self.stop_event.set()

        self._log("🛑 Yêu cầu dừng đã được gửi. Sẽ dừng sau khi hoàn thành prompt hiện tại...\n")

        # Disable stop to prevent double-clicks

        with suppress(Exception):

            self.btn_stop.configure(state="disabled")



    def on_image_run(self) -> None:

        """Start image generation process"""

        if self.executor is not None:

            Messagebox.show_info("Đang chạy, vui lòng dừng trước khi chạy tiếp.")

            return



        # Validation

        if not self._get_cookies_source():

            Messagebox.show_error("Vui lòng nhập Cookie ở tab Video trước.")

            return



        # Collect image prompts

        image_prompts = self._collect_image_prompts()

        if not image_prompts:

            Messagebox.show_error("Vui lòng nhập prompt hoặc chọn file chứa prompt.")

            return



        out_dir = self.ent_image_output.get().strip()

        if not out_dir:

            Messagebox.show_error("Vui lòng chọn thư mục lưu ảnh.")

            return

        Path(out_dir).mkdir(parents=True, exist_ok=True)



        # Disable controls

        self._set_image_controls_state("disabled")

        with suppress(Exception):

            self.btn_image_stop.configure(state="normal")

        self.stop_event.clear()

        self._log("Bắt đầu tạo ảnh...\n")



        # Initialize executor (limit to 3 concurrent tasks)

        max_workers = min(3, len(image_prompts))

        self.executor = ThreadPoolExecutor(max_workers=max_workers)



        # Clear image table

        for item in self.img_tree.get_children():

            self.img_tree.delete(item)



        # Start image generation

        threading.Thread(target=self._run_image_generation, args=(image_prompts,), daemon=True).start()



    def on_image_stop(self) -> None:

        """Stop image generation"""

        self.stop_event.set()

        self._log("Yêu cầu dừng tạo ảnh đã được gửi...\n")

        with suppress(Exception):

            self.btn_image_stop.configure(state="disabled")



    def _collect_image_prompts(self) -> List[str]:

        """Collect prompts for image generation"""

        prompts = []



        # Single prompt

        single = self.ent_image_prompt.get().strip()

        if single:

            prompts.append(single)



        # Batch prompts

        batch_file = self.ent_image_prompt_batch.get().strip()

        if batch_file and os.path.exists(batch_file):

            try:

                lines = Path(batch_file).read_text(encoding="utf-8").splitlines()

                for line in lines:

                    text = line.strip()

                    if text:

                        prompts.append(text)

            except Exception as e:

                self._log(f"Không thể đọc file prompt: {e}\n")



        return prompts



    def _set_image_controls_state(self, state: str) -> None:

        """Set state for image generation controls"""

        widget_names = [

            'ent_image_prompt', 'ent_image_prompt_batch',

            'cmb_image_model', 'cmb_aspect_ratio', 'spn_num_images',

            'ent_image_output', 'btn_image_run', 'btn_image_stop',

            # Optional selectors (may not exist in some builds)

            'ent_subject_image', 'ent_scene_image', 'ent_style_image',

        ]

        widgets = []

        for name in widget_names:

            w = getattr(self, name, None)

            if w is not None:

                widgets.append(w)

        for w in widgets:

            try:

                w.configure(state=state)

            except Exception:

                pass



    # ---------------- Helpers -----------------

    def _set_controls_state(self, state: str) -> None:

        widgets = [

            self.ent_cookie, self.ent_prompt, self.ent_prompt_file,

            self.cmb_model, self.ent_image_model, self.spn_num_videos, self.spn_max_wait, self.spn_poll,

            self.cmb_mode, self.spn_delay, self.ent_tool, self.cmb_tier, self.ent_project,

            self.ent_output, self.btn_run, self.btn_stop,

            self.ent_image_file, self.ent_image_folder, self.ent_image_prompt_file,

        ]

        for w in widgets:

            try:

                w.configure(state=state)

            except Exception:

                pass



    def _get_cookies_source(self) -> Optional[str]:

        # First try to get cookie from pool

        cookie_data = self._get_next_cookie()

        if cookie_data and cookie_data.get('cookies'):

            self._log(f"🍪 Sử dụng cookie từ pool: {cookie_data.get('name', 'Unknown')}\n")

            return cookie_data['cookies']



        # Fallback to single cookie entry

        cookie_text = self.ent_cookie.get().strip()

        if cookie_text:

            self._log("🍪 Sử dụng cookie đơn (fallback)\n")

            return cookie_text



        return None



    def _collect_prompts(self) -> List[PromptTask]:

        prompts: List[PromptTask] = []



        # Check if multi-file processing is enabled

        if self.var_multi_txt_files.get():

            multi_folder = self.ent_multi_txt_folder.get().strip()

            if not multi_folder or not os.path.exists(multi_folder):

                self._log("Vui lòng chọn thư mục chứa các file .txt\n")

                return prompts



            # Process multiple .txt files

            txt_files = list(Path(multi_folder).glob("*.txt"))

            if not txt_files:

                self._log(f"Không tìm thấy file .txt nào trong thư mục: {multi_folder}\n")

                return prompts



            # Sort files by numeric prefix first, then alphabetically

            def sort_key(file_path):

                stem = file_path.stem

                # Try to extract numeric prefix

                import re

                match = re.match(r'^(\d+)', stem)

                if match:

                    return (0, int(match.group(1)))  # Numeric files first

                else:

                    return (1, stem)  # Non-numeric files after



            txt_files = sorted(txt_files, key=sort_key)

            self._log(f"Tìm thấy {len(txt_files)} file .txt\n")



            for i, txt_file in enumerate(txt_files, 1):

                try:

                    lines = txt_file.read_text(encoding="utf-8").splitlines()

                    file_prompts = []

                    for line in lines:

                        text = line.strip()

                        if text:

                            file_prompts.append(text)



                    if file_prompts:

                        # Create a folder name based on txt file name

                        folder_name = txt_file.stem



                        # Create a separate PromptTask for each line in the file

                        for line_idx, prompt_text in enumerate(file_prompts, 1):

                            # Use file index and line index for unique prompt_index

                            prompt_index = (i - 1) * 1000 + line_idx  # File 1: 1,2,3... File 2: 1001,1002,1003...

                            prompts.append(PromptTask(

                                prompt_text=prompt_text,

                                prompt_index=prompt_index,

                                output_folder=folder_name

                            ))



                        self._log(f"Đã load {len(file_prompts)} prompt từ {txt_file.name} (file {i})\n")

                except Exception as e:

                    self._log(f"Không thể đọc file {txt_file.name}: {e}\n")

        else:

            # Single file processing (original logic)

            one = self.ent_prompt.get().strip()

        prompt_file = self.ent_prompt_file.get().strip()

            

            # Ưu tiên file prompt nếu có, nếu không mới dùng prompt đơn

        if prompt_file and os.path.exists(prompt_file):

            try:

                lines = Path(prompt_file).read_text(encoding="utf-8").splitlines()

                for i, line in enumerate(lines, 1):

                    text = line.strip()

                    if text:

                        prompts.append(PromptTask(prompt_text=text, prompt_index=len(prompts) + 1))

                    self._log(f"📝 Đã load {len(prompts)} prompts từ file\n")

            except Exception as e:

                self._log(f"Không thể đọc file prompt: {e}\n")

        elif one:

            # Chỉ dùng prompt đơn nếu không có file

            prompts.append(PromptTask(prompt_text=one, prompt_index=1))

            self._log(f"📝 Đã load 1 prompt đơn\n")

        else:

            self._log("❌ Vui lòng nhập prompt hoặc chọn file prompt\n")



        return prompts



    def _collect_image_tasks(self) -> List[ImageTask]:

        """Collect image tasks by sequential order: 1 ảnh = 1 dòng prompt (theo STT)"""

        tasks: List[ImageTask] = []



        # Get image sources

        single_image = self.ent_image_file.get().strip()

        image_folder = self.ent_image_folder.get().strip()

        prompt_file = self.ent_image_prompt_file.get().strip()



        if not prompt_file or not os.path.exists(prompt_file):

            self._log("Cần chọn file prompt cho chế độ Image-to-Video\n")

            return tasks



        # Load prompts - ĐƠN GIẢN: mỗi dòng = 1 prompt (từ trên xuống dưới)

        prompts = []

        try:

            prompt_lines = Path(prompt_file).read_text(encoding="utf-8").splitlines()

            for line in prompt_lines:

                line = line.strip()

                if line:

                    prompts.append(line)

            self._log(f"📝 Đọc được {len(prompts)} dòng prompt từ file\n")

        except Exception as e:

            self._log(f"Không thể đọc file prompt: {e}\n")

            return tasks



        # Collect images và sắp xếp theo STT tự nhiên

        image_paths = []

        if single_image and os.path.exists(single_image):

            image_paths.append(Path(single_image))



        if image_folder and os.path.exists(image_folder):

            folder_path = Path(image_folder)

            folder_images = []

            for ext in ['*.jpg', '*.jpeg', '*.png', '*.bmp', '*.gif', '*.webp']:

                folder_images.extend(folder_path.glob(ext))

            

            # Sắp xếp theo natural sort (1, 2, 3... không phải 1, 10, 11, 2)

            folder_images = natural_sort_paths(folder_images)

            image_paths.extend(folder_images)

            self._log(f"📁 Sắp xếp {len(folder_images)} ảnh theo thứ tự tự nhiên\n")



        if not image_paths:

            self._log("❌ Không tìm thấy ảnh nào\n")

            return tasks



        # GỘP ĐƠN GIẢN: ảnh thứ 1 → prompt dòng 1, ảnh thứ 2 → prompt dòng 2...

        for idx, img_path in enumerate(image_paths, 1):

            # Lấy prompt tương ứng theo thứ tự (nếu hết prompt thì lặp lại)

            prompt_index = (idx - 1) % len(prompts) if prompts else 0

            prompt_text = prompts[prompt_index] if prompts else "Default prompt"

            

            tasks.append(ImageTask(

                image_path=str(img_path),

                prompt_text=prompt_text,

                task_index=idx

            ))

            

            self._log(f"✅ Ảnh {idx}: '{img_path.name}' ↔ Dòng {prompt_index + 1}: '{prompt_text[:50]}...'\n")

        

        # Cảnh báo nếu số ảnh > số prompt

        if len(image_paths) > len(prompts):

            self._log(f"⚠️ Cảnh báo: {len(image_paths)} ảnh nhưng chỉ có {len(prompts)} prompt → sẽ lặp lại prompt\n")

        

        self._log(f"📊 Tổng cộng: {len(tasks)} tasks (ảnh theo STT ↔ prompt từ trên xuống)\n")

        return tasks



    def _build_client(self, cookies_str: str) -> Optional[LabsFlowClient]:

        try:

            cookies = _parse_cookie_string(cookies_str)

            if not cookies:

                self._log("Cookie không hợp lệ.\n")

                return None

            return LabsFlowClient(cookies)

        except Exception as e:

            self._log(f"Lỗi khởi tạo client: {e}\n")

            return None



    def _selected_video_aspect(self) -> str:

        try:

            # Check main Video tab first, then fallback to JSON Prompt tab

            choice = self.cmb_video_aspect.get().strip()

            if choice:

                return self._video_aspect_map.get(choice, "VIDEO_ASPECT_RATIO_LANDSCAPE")

            # Fallback to JSON Prompt tab

            if hasattr(self, 'cmb_jsonp_vid_aspect'):

                choice = self.cmb_jsonp_vid_aspect.get().strip()

                if choice:

                    return self._video_aspect_map.get(choice, "VIDEO_ASPECT_RATIO_LANDSCAPE")

            return "VIDEO_ASPECT_RATIO_LANDSCAPE"

        except Exception:

            return "VIDEO_ASPECT_RATIO_LANDSCAPE"



    def _get_concurrent_jobs_value(self) -> int:

        """Get current concurrent jobs value from combobox"""

        try:

            if hasattr(self, "cmb_concurrent_jobs"):

                try:

                    return int(self.cmb_concurrent_jobs.get())

                except (ValueError, AttributeError):

                    pass

            return int(getattr(self, "_concurrent_jobs_count", 3) or 3)

        except Exception:

            return 3



    def _update_concurrent_jobs_values(self) -> None:

        """Update combobox values based on current max concurrent jobs"""

        try:

            max_jobs = self._calculate_max_concurrent_jobs()

            values = [str(i) for i in range(1, max(max_jobs + 1, 21))]

            if hasattr(self, 'cmb_concurrent_jobs'):

                current_value = self.cmb_concurrent_jobs.get()

                self.cmb_concurrent_jobs.configure(values=values)

                # Keep current value if valid, otherwise set to 1

                if current_value in values:

                    self.cmb_concurrent_jobs.set(current_value)

                else:

                    self.cmb_concurrent_jobs.set("1")

        except Exception as e:

            self._log(f"⚠️ Lỗi khi cập nhật giá trị combobox concurrent jobs: {e}\n")



    def _on_concurrent_jobs_changed(self) -> None:

        """Update semaphore and internal count when concurrent jobs setting changes."""

        try:

            n = self._get_concurrent_jobs_value()

            n = max(1, n)

            

            # Limit to max concurrent jobs

            max_jobs = self._calculate_max_concurrent_jobs()

            if n > max_jobs:

                n = max_jobs

                if hasattr(self, "cmb_concurrent_jobs"):

                    self.cmb_concurrent_jobs.set(str(n))

            

            self._concurrent_jobs_count = n

            # Recreate semaphore to enforce new parallel limit

            # (replace the existing semaphore so new tasks respect it)

            self.video_semaphore = threading.Semaphore(value=n)

            self._log(f"🔧 Cập nhật số công việc đồng thời: {n}\n")

        except Exception as e:

            # non-fatal: keep previous setting

            try:

                self._log(f"⚠️ Lỗi khi cập nhật concurrent jobs: {e}\n")

            except Exception:

                pass



    def _get_fixed_seed(self) -> Optional[int]:

        """Get fixed seed from GUI input, return None if empty or invalid."""

        try:

            seed_str = self.ent_seed.get().strip()

            if seed_str:

                return int(seed_str)

            return None

        except Exception:

            return None



