            safe_prompt = safe_prompt.strip().replace(" ", "_") or f"prompt_{task.prompt_index}"

            filename = out_dir / f"{safe_prompt}_{idx}"

            filename = self._ensure_unique_filename(filename)

            self._log(f"📋 Xếp hàng tải: {url} → {filename.name} (bằng {method})\n")

            self.download_queue.put(DownloadTask(url=url, target_path=filename, method=method, downloads_dir=downloads_dir))



