    def _download_via_requests_simple(self, url: str, filename: Path) -> bool:

        """Download file using requests with better error handling"""

        try:

            # Ensure unique filename to prevent overwrite

            filename = self._ensure_unique_filename(filename)

            # Ensure output directory exists

            filename.parent.mkdir(parents=True, exist_ok=True)



            headers = {

                "user-agent": "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36"

            }



            self._log(f"📥 Bắt đầu tải: {url}\n")



            with requests.get(url, headers=headers, stream=True, timeout=120) as r:

                r.raise_for_status()



                # Get file size if available

                total_size = int(r.headers.get('content-length', 0))

                downloaded = 0



                with open(filename, "wb") as f:

                    for chunk in r.iter_content(chunk_size=8192):

                        if self.stop_event.is_set():

                            self._log(f"⏹️ Dừng tải: {filename.name}\n")

                            break

                        if chunk:

                            f.write(chunk)

                            downloaded += len(chunk)



                            # Log progress for large files

                            if total_size > 0 and downloaded % (1024 * 1024) == 0:  # Every MB

                                progress = (downloaded / total_size) * 100

                                self._log(f"📊 Tiến trình: {progress:.1f}% ({downloaded//1024//1024}MB/{total_size//1024//1024}MB)\n")



                if not self.stop_event.is_set():

                    file_size = filename.stat().st_size

                    self._log(f"✅ Tải thành công: {filename.name} ({file_size//1024}KB)\n")

                    return True

                else:

                    self._log(f"⏹️ Tải bị dừng: {filename.name}\n")

                    return False



        except requests.exceptions.RequestException as e:

            self._log(f"❌ Lỗi mạng khi tải {url}: {e}\n")

            return False

        except Exception as e:

            self._log(f"❌ Lỗi không xác định khi tải {url}: {e}\n")

            return False



    def _download_worker(self) -> None:

        while True:

            if self.stop_event.is_set():

                _t.sleep(0.2)

                continue

            try:

                dtask: DownloadTask = self.download_queue.get(timeout=0.2)

            except queue.Empty:

                continue



            def process_download():

                try:

                    # Validate URL

                    if not dtask.url or not dtask.url.startswith("http"):

                        self._log(f"❌ URL không hợp lệ: {dtask.url}\n")

                        return



                    # Validate target path

                    if not dtask.target_path:

                        self._log(f"❌ Đường dẫn lưu không hợp lệ\n")

                        return



                    # Ensure file has unique filename to prevent overwrite

                    dtask.target_path = self._ensure_unique_filename(dtask.target_path)

                    

                    # Update status to "Đang download"

                    self._schedule(self._update_task_status_for_url, dtask.url, "Đang download")



                    # Execute download based on method

                    if dtask.method == "Trình duyệt":

                        self._log(f"🌐 Mở trình duyệt để tải: {dtask.url}\n")

                        self._download_via_browser(dtask.url, dtask.target_path)

                    elif dtask.method == "Trình duyệt ẩn":

                        self._log(f"🤖 Tải bằng trình duyệt ẩn: {dtask.url}\n")

                        self._download_via_headless(dtask.url, dtask.target_path)

                    else:  # Default: requests

                        self._download_via_requests_simple(dtask.url, dtask.target_path)



                    # Update UI on success

                    self._schedule(self._update_file_for_url_ui, dtask.url, str(dtask.target_path))

                    # Auto Edit removed per request

                except Exception as e:

                    error_msg = f"❌ Tải thất bại {dtask.target_path.name}: {str(e)}"

                    self._log(f"{error_msg}\n")



                    # Try to clean up partial download

                    try:

                        if dtask.target_path.exists() and dtask.target_path.stat().st_size == 0:

                            dtask.target_path.unlink()

                            self._log(f"🧹 Đã xóa file rỗng: {dtask.target_path.name}\n")

                    except Exception:

                        pass

                finally:

                    self.download_queue.task_done()



            # Run download in separate thread to prevent blocking

            if dtask.method == "Trình duyệt ẩn":

                # For selenium downloads, use separate thread to prevent UI lag

                threading.Thread(target=process_download, daemon=True).start()

            else:

                # For other methods, run directly

                process_download()



    def _download_via_browser(self, url: str, target_path: Path) -> None:

        downloads_dir = Path(self.ent_downloads.get().strip())

        downloads_dir.mkdir(parents=True, exist_ok=True)

        before = {p for p in downloads_dir.glob('*') if p.is_file()}

        start = _t.time()

        # mở trình duyệt hiển thị (mặc định)

        webbrowser.open_new(url)

        # Chờ file mới xuất hiện và ổn định

        timeout = 600

        stable_wait = 2

        chosen: Optional[Path] = None

        last_size = -1

        last_path: Optional[Path] = None

        deadline = _t.time() + timeout

        while _t.time() < deadline and not self.stop_event.is_set():

            # Bỏ qua file tạm .crdownload/.tmp

            candidates = []

            for p in downloads_dir.glob('*'):

                if not p.is_file():

                    continue

                if p.name.endswith('.crdownload') or p.name.endswith('.tmp'):

                    continue

                if p in before:

                    continue

                try:

                    mtime = p.stat().st_mtime

                    if mtime >= start - 1:

                        candidates.append((mtime, p))

                except Exception:

                    continue

            if candidates:

                candidates.sort(reverse=True)

                cur = candidates[0][1]

                try:

                    size = cur.stat().st_size

                except Exception:

                    size = -1

                if last_path == cur and size == last_size:

                    chosen = cur

                    break

                last_path = cur

                last_size = size

            _t.sleep(stable_wait)

        if self.stop_event.is_set():

            return

        if not chosen:

            raise RuntimeError("Không tìm thấy file đã tải về từ trình duyệt.")

        # Di chuyển/đổi tên sang target_path, đảm bảo tên file unique

        try:

            target_path = self._ensure_unique_filename(target_path)

            target_path.parent.mkdir(parents=True, exist_ok=True)

            if target_path.exists():

                target_path.unlink()

            shutil.move(str(chosen), str(target_path))

            # thông báo UI cập nhật bảng

            self._schedule(self._update_file_for_url_ui, url, str(target_path))

        except Exception as e:

            raise RuntimeError(f"Không thể di chuyển tệp: {e}")



    def _get_headless_driver(self):

        """Get a reusable headless Chrome driver from pool"""

        with self._selenium_lock:

            if self._driver_pool:

                return self._driver_pool.pop()



        try:

            from selenium import webdriver

            from selenium.webdriver.chrome.options import Options

            from selenium.webdriver.chrome.service import Service

        except Exception:

            raise RuntimeError("Chưa cài selenium. Vui lòng: pip install selenium")



        downloads_dir = Path(self.ent_downloads.get().strip())

        downloads_dir.mkdir(parents=True, exist_ok=True)



        chrome_options = Options()

        chrome_options.add_argument("--headless=new")

        chrome_options.add_argument("--disable-gpu")

        chrome_options.add_argument("--no-sandbox")

        chrome_options.add_argument("--disable-dev-shm-usage")

        chrome_options.add_argument("--disable-extensions")

        chrome_options.add_argument("--disable-logging")

        chrome_options.add_argument("--disable-web-security")

        chrome_options.add_argument("--allow-running-insecure-content")

        chrome_options.add_argument("--silent")



        # Fix: Add unique user data directory to prevent session conflicts

        import tempfile

        import uuid

        temp_user_data = tempfile.mkdtemp(prefix=f"chrome_user_data_{uuid.uuid4().hex[:8]}_")

        chrome_options.add_argument(f"--user-data-dir={temp_user_data}")



        chrome_options.add_experimental_option('useAutomationExtension', False)

        chrome_options.add_experimental_option("excludeSwitches", ["enable-automation"])



        prefs = {

            "download.default_directory": str(downloads_dir.resolve()),

            "download.prompt_for_download": False,

            "download.directory_upgrade": True,

            "safebrowsing.enabled": False,

            "safebrowsing.disable_download_protection": True,

            "profile.default_content_settings.popups": 0,

            "profile.default_content_setting_values.notifications": 2,

        }

        chrome_options.add_experimental_option("prefs", prefs)



        # Use Service to suppress logs

        service = Service()

        try:

            service.creation_flags = 0x08000000  # CREATE_NO_WINDOW on Windows

        except Exception:

            pass



        driver = webdriver.Chrome(service=service, options=chrome_options)

        driver.set_page_load_timeout(30)



        # Store temp directory path for cleanup

        driver._temp_user_data = temp_user_data



        return driver



    def _return_headless_driver(self, driver):

        """Return driver to pool for reuse"""

        with self._selenium_lock:

            if len(self._driver_pool) < self._max_drivers:

                self._driver_pool.append(driver)

            else:

                with suppress(Exception):

                    driver.quit()

                    # Cleanup temp user data directory

                    if hasattr(driver, '_temp_user_data'):

                        import shutil

                        shutil.rmtree(driver._temp_user_data, ignore_errors=True)



    def _download_via_headless(self, url: str, target_path: Path) -> None:

        # Tải bằng Chrome headless tối ưu để không gây lag UI

        downloads_dir = Path(self.ent_downloads.get().strip())

        downloads_dir.mkdir(parents=True, exist_ok=True)

        before = {p for p in downloads_dir.glob('*') if p.is_file()}



        driver = None

        try:

            # Get driver from pool (non-blocking)

            driver = self._get_headless_driver()



            # Navigate in background thread context

            driver.get(url)



            # Monitor for downloaded file

            start = _t.time()

            timeout = 300  # Reduced timeout

            stable_wait = 1  # Faster polling

            chosen = None

            last_size = -1

            last_path = None

            deadline = _t.time() + timeout



            while _t.time() < deadline and not self.stop_event.is_set():

                candidates = []

                for p in downloads_dir.glob('*'):

                    if not p.is_file() or p in before:

                        continue

                    if p.name.endswith(('.crdownload', '.tmp', '.part')):

                        continue

                    with suppress(Exception):

                        mtime = p.stat().st_mtime

                        if mtime >= start - 1:

                            candidates.append((mtime, p))



                if candidates:

                    candidates.sort(reverse=True)

                    cur = candidates[0][1]

                    with suppress(Exception):

                        size = cur.stat().st_size

                        if size > 0 and last_path == cur and size == last_size:

                            chosen = cur

                            break

                        last_path = cur

                        last_size = size



                _t.sleep(stable_wait)



            if self.stop_event.is_set():

                return

            if not chosen:

                raise RuntimeError("Không tìm thấy file đã tải về (headless).")



            target_path = self._ensure_unique_filename(target_path)

            target_path.parent.mkdir(parents=True, exist_ok=True)

            if target_path.exists():

                target_path.unlink()

            shutil.move(str(chosen), str(target_path))

            self._schedule(self._update_file_for_url_ui, url, str(target_path))



        finally:

            if driver:

                self._return_headless_driver(driver)



    def _update_file_for_url_ui(self, url: str, filename: str) -> None:

        try:

            # Update Video tab tree

            for iid in self.tree.get_children(""):

                vals = self.tree.item(iid, "values")

                if len(vals) >= 5 and url in str(vals[4]):

                    new_vals = list(vals)

                    new_vals[4] = filename

                    # cập nhật trạng thái thành hoàn tất

                    if len(new_vals) >= 4:

                        new_vals[3] = "Hoàn tất"

                    # cập nhật hành động phù hợp

                    if len(new_vals) >= 6:

                        new_vals[5] = "Mở | Sao chép"

                    self.tree.item(iid, values=new_vals, tags=('status_ok',))



            # Update Profiles tab tree

            for iid in self.prof_tree.get_children(""):

                vals = self.prof_tree.item(iid, "values")

                if len(vals) >= 5 and url in str(vals[4]):

                    new_vals = list(vals)

                    new_vals[4] = filename

                    # cập nhật trạng thái thành hoàn tất

                    if len(new_vals) >= 4:

                        new_vals[3] = "Hoàn tất"

                    # cập nhật hành động phù hợp

                    if len(new_vals) >= 6:

                        new_vals[5] = "Mở | Sao chép"

                    self.prof_tree.item(iid, values=new_vals, tags=('status_ok',))



            # Update WorkFlow tab tree if exists

            if hasattr(self, 'lst_workflow_ops'):

                for iid in self.lst_workflow_ops.get_children(""):

                    vals = self.lst_workflow_ops.item(iid, "values")

                    if len(vals) >= 5 and url in str(vals[4]):

                        new_vals = list(vals)

                        new_vals[4] = filename

                        # cập nhật hành động phù hợp

                        if len(new_vals) >= 6:

                            new_vals[5] = "Mở | Sao chép"

                        self.lst_workflow_ops.item(iid, values=new_vals)

        except Exception:

            pass



    def _check_cookie_conflict_warning(self, profile_cookies: str, prof_name: str) -> None:

        """Check if the same cookie is being used in Video tab and warn user."""

        try:

            # Get current Video tab cookies

            video_cookies = self._get_cookies_source()



            if not video_cookies or not profile_cookies:

                return



            # Normalize cookies for comparison (remove spaces, sort)

            def normalize_cookie(cookie_str: str) -> str:

                if not cookie_str:

                    return ""

                # Extract key parts for comparison

                parts = []

                for part in cookie_str.split(';'):

                    part = part.strip()

                    if '=' in part:

                        key, value = part.split('=', 1)

                        parts.append(f"{key.strip()}={value.strip()}")

                return ';'.join(sorted(parts))



            video_normalized = normalize_cookie(video_cookies)

            profile_normalized = normalize_cookie(profile_cookies)



            # Check if they're the same (at least 80% similar)

            if video_normalized and profile_normalized:

                # Simple similarity check - count matching cookie pairs

                video_parts = set(video_normalized.split(';'))

                profile_parts = set(profile_normalized.split(';'))



                if video_parts and profile_parts:

                    common = len(video_parts.intersection(profile_parts))

                    total = len(video_parts.union(profile_parts))

                    similarity = common / total if total > 0 else 0



                    if similarity > 0.7:  # 70% similar cookies

                        # Check if Video tab is currently running

                        video_running = (hasattr(self, 'executor') and

                                        self.executor is not None and

                                        not self.executor._shutdown)



                        if video_running:

                            warning_msg = (f"⚠️ CẢNH BÁO: Profile '{prof_name}' đang sử dụng cookie tương tự "

                                            f"với tab Video đang chạy!\n"

                                            f"Điều này có thể gây xung đột API và lỗi 500.\n"

                                            f"Khuyến nghị: Dừng tab Video trước khi chạy Profile này.\n")

                            self._log(warning_msg)



                            # Show popup warning

                            def show_warning():

                                # ✅ BUG FIX: Conditional import

                                if HAS_TTKBootstrap:

                                    from ttkbootstrap.dialogs import Messagebox

                                    Messagebox.show_warning(

                                    title="Cookie Conflict Warning",

                                    message=(f"Profile '{prof_name}' đang dùng cùng cookie với tab Video!\n\n"

                                            f"Tab Video đang chạy {self._count_active_video_tasks()} task.\n"

                                            f"Chạy cùng lúc có thể gây lỗi 500.\n\n"

                                            f"Bạn có muốn tiếp tục?")

                                )



                            self._schedule(show_warning)

                        else:

                            # Just log info if Video tab is not running

                            self._log(f"ℹ️ [Profile:{prof_name}] Sử dụng cookie tương tự tab Video (đã dừng).\n")



        except Exception as e:

            # Don't break execution if warning check fails

            self._log(f"⚠️ Lỗi kiểm tra cookie conflict: {e}\n")



    def _count_active_video_tasks(self) -> int:

        """Count how many video tasks are currently running in Video tab."""

        try:

            if not hasattr(self, 'tree'):

                return 0



            active_count = 0

            for iid in self.tree.get_children(""):

                vals = self.tree.item(iid, "values")

                if len(vals) >= 4:

                    status = str(vals[3]).lower()

                    if any(word in status for word in ["đang", "chạy", "xử lý", "chờ"]):

                        active_count += 1

            return active_count

        except Exception:

            return 0



