    def _on_tree_right_click(self, event) -> None:

        try:

            row_id = self.tree.identify_row(event.y)

            if row_id:

                self.tree.selection_set(row_id)

                self._update_action_menu_states(row_id)

                self.ctx_menu.tk_popup(event.x_root, event.y_root)

        finally:

            try:

                self.ctx_menu.grab_release()

            except Exception:

                pass



    def _on_tree_left_click(self, event) -> None:

        # nếu click vào cột hành động, bật menu thao tác

        try:

            row_id = self.tree.identify_row(event.y)

            col_id = self.tree.identify_column(event.x)

            if not row_id or not col_id:

                return

            col_index = int(col_id.replace('#', '')) - 1

            if self.tree_columns and col_index == self.tree_columns.index("action"):

                self.tree.selection_set(row_id)

                self._update_action_menu_states(row_id)

                # hiển thị menu ngay vị trí chuột

                self.ctx_menu.tk_popup(event.x_root, event.y_root)

        finally:

            with suppress(Exception):

                self.ctx_menu.grab_release()



    def _update_action_menu_states(self, row_id: str) -> None:

        ctrl = self.row_controls.get(row_id, {"can_stop": False, "can_pause": False, "can_resume": False})

        try:

            self.ctx_menu.entryconfig("Dừng (Stop)", state="normal" if ctrl.get("can_stop") else "disabled")

            self.ctx_menu.entryconfig("Tạm dừng (Pause)", state="normal" if ctrl.get("can_pause") else "disabled")

            self.ctx_menu.entryconfig("Tiếp tục (Resume)", state="normal" if ctrl.get("can_resume") else "disabled")

        except Exception:

            pass



    def _action_stop_operation(self) -> None:

        # Hiện tại API chưa lộ endpoint cancel/stop; tạm thời chỉ đánh dấu bỏ qua tải và ẩn log

        sel = self.tree.selection()

        if not sel:

            return

        iid = sel[0]

        try:

            values = list(self.tree.item(iid, "values"))

            if len(values) >= 4:

                values[3] = "Đã hủy"

                self.tree.item(iid, values=values, tags=(self._status_tag("Đã hủy"),))

            # Nếu có URL đang map tới iid, bỏ qua các URL này để worker không cập nhật

            for u, mapped in list(self.url_to_iid.items()):

                if mapped == iid:

                    self.ignore_urls.add(u)

        except Exception:

            pass



