    # ---------------- Logging -----------------

    def _log(self, text: str) -> None:

        self.log_queue.put(text)



    def _poll_log_queue(self) -> None:

        processed = 0

        max_per_tick = 20  # Giảm từ 50 xuống 20 để tránh block UI

        try:

            while processed < max_per_tick:

                text = self.log_queue.get_nowait()

                # nếu popup log đang mở, đẩy vào đó; nếu chưa, gom hàng đợi

                if hasattr(self, "_log_text") and self._log_text is not None:

                    try:

                        self._log_text.insert("end", text)

                        # Chỉ scroll mỗi 10 lần để giảm tải

                        if processed % 10 == 0:

                            self._log_text.see("end")

                    except Exception:

                        pass

                else:

                    # gom buffer để khi mở popup sẽ đổ ra

                    self._log_buffer.append(text)

                    self._log_buffer_chars += len(text)

                    if self._log_buffer_chars > 200000:

                        # cắt bớt đầu buffer

                        while self._log_buffer and self._log_buffer_chars > 150000:

                            removed = self._log_buffer.pop(0)

                            self._log_buffer_chars -= len(removed)

                processed += 1

        except queue.Empty:

            pass

        # Chỉ scroll cuối cùng nếu cần

        if hasattr(self, "_log_text") and self._log_text is not None and processed > 0:

                try:

                    self._log_text.see("end")

                except Exception:

                    pass

        self.root.after(100, self._poll_log_queue)



    def on_show_logs(self) -> None:

        # tạo popup logs nếu chưa có

        if hasattr(self, "_logs_win") and self._logs_win is not None:

            try:

                self._logs_win.focus_set()

                return

            except Exception:

                pass

        self._logs_win = tb.Toplevel(self.root)

        self._logs_win.title("Nhật ký (Logs)")

        self._logs_win.geometry("900x500")

        with suppress(Exception):

            self._center_window(self._logs_win, 900, 500)

        # đặt icon cho popup nếu có

        try:

            icon_path = Path(__file__).resolve().parent / "play.ico"

            if icon_path.exists():

                try:

                    self._logs_win.iconbitmap(default=str(icon_path))

                except Exception:

                    pass

        except Exception:

            pass

        fr = tb.Frame(self._logs_win, padding=10)

        fr.pack(fill="both", expand=True)

        self._log_text = scrolledtext.ScrolledText(fr)

        self._log_text.pack(fill="both", expand=True)

        # đổ buffer tích luỹ trước đó

        try:

            if self._log_buffer:

                self._log_text.insert("end", "".join(self._log_buffer))

        except Exception:

            pass

        def _on_close():

            try:

                self._log_text = None

            except Exception:

                pass

            try:

                self._logs_win.destroy()

            finally:

                self._logs_win = None

        self._logs_win.protocol("WM_DELETE_WINDOW", _on_close)



    def _schedule_expire_check(self) -> None:

        """Lên lịch kiểm tra expire định kỳ"""

        self._check_subscription_expire()

        # Lặp lại định kỳ:

        # - 30000ms = 30 giây (dùng cho test)

        # - 300000ms = 5 phút (dùng cho production)

        self.root.after(30000, self._schedule_expire_check)  # Đang dùng 30s để test nhanh



    def _check_subscription_expire(self) -> None:

        """Kiểm tra subscription có hết hạn không bằng cách gọi API trong background thread"""

        def _background_check():

            """Logic kiểm tra chạy trong background thread"""

            try:

                from iting_api import ItingAPI

                api = ItingAPI()

                token = api.load_auth_token()



                if not token:

                    return  # Chưa đăng nhập, bỏ qua



                # Lấy user_id từ token

                user_id = None

                try:

                    import json

                    token_data = json.loads(token)

                    user_id = token_data.get("user_info", {}).get("id")

                except Exception:

                    return  # Token không hợp lệ



                if not user_id:

                    return



                # Gọi API check subscription mới nhất từ database

                try:

                    check_url = f"https://itinggroup.com/NCTTPY/api/check_subscription/{user_id}"

                    response = requests.get(check_url, timeout=10)



                    if response.status_code == 200:

                        data = response.json()

                        # Debug log để xem API trả về gì

                        self.root.after(0, lambda: self._log(f"🔍 Check subscription API response: {json.dumps(data, indent=2, default=str)}\n"))



                        if data.get("success"):

                            subscription = data.get("subscription", {})

                            permissions = data.get("permissions", {})



                            # Kiểm tra expire từ database - dùng trường status thay vì is_valid

                            status = subscription.get("status", "").lower()

                            if "hết hạn" in status or "expired" in status:

                                self.root.after(0, lambda: self._handle_subscription_expired("Gói dịch vụ đã hết hạn"))

                                return



                            if subscription.get("is_active") == 0 or subscription.get("is_active") == False:

                                self.root.after(0, lambda: self._handle_subscription_expired("Tài khoản đã bị tạm khóa"))

                                return



                            # Kiểm tra quyền tạo video

                            if not permissions.get("can_generate_video", True):

                                videos_today = subscription.get("videos_used_today", 0)

                                max_videos = subscription.get("max_videos_per_day", 5)

                                if videos_today >= max_videos:

                                    msg = f"⚠️ Đã đạt giới hạn {max_videos} video/ngày!"

                                    self.root.after(0, lambda m=msg: self._show_expire_warning(m))



                            # Cảnh báo sắp hết hạn và kiểm tra đã hết hạn

                            end_date = subscription.get("end_date")

                            if end_date:

                                try:

                                    from datetime import datetime, timezone

                                    # Parse end_date and ensure it has timezone info

                                    if isinstance(end_date, str):

                                        # Handle both ISO format with Z and without timezone

                                        if 'Z' in end_date or '+' in end_date or end_date.endswith('00:00'):

                                            end_dt = datetime.fromisoformat(end_date.replace('Z', '+00:00'))

                                        else:

                                            # No timezone info, assume UTC

                                            end_dt = datetime.fromisoformat(end_date).replace(tzinfo=timezone.utc)

                                    else:

                                        # If not string, skip

                                        raise ValueError("end_date is not a string")

                                    

                                    # Get current time with timezone (UTC)

                                    now = datetime.now(timezone.utc)

                                    

                                    # Kiểm tra đã hết hạn

                                    if now > end_dt:

                                        self.root.after(0, lambda: self._handle_subscription_expired("Gói dịch vụ đã hết hạn"))

                                        return

                                    

                                    # Cảnh báo sắp hết hạn

                                    days_left = (end_dt - now).days

                                    if days_left <= 1:

                                        msg = f"⚠️ Gói dịch vụ sẽ hết hạn trong {days_left} ngày!"

                                        self.root.after(0, lambda m=msg: self._show_expire_warning(m))

                                except Exception as ex:

                                    self.root.after(0, lambda e=ex: self._log(f"Lỗi kiểm tra end_date: {e}\n"))



                    elif response.status_code == 404:

                        self.root.after(0, lambda: self._handle_subscription_expired("Tài khoản không tồn tại"))

                        return



                except requests.exceptions.RequestException:

                    # Lỗi mạng, bỏ qua lần này

                    pass



            except Exception as e:

                # Lỗi kiểm tra, ghi log nhưng không làm gì

                self.root.after(0, lambda err=e: self._log(f"Lỗi kiểm tra expire: {err}\n"))

        

        # Chạy trong background thread để không block UI

        threading.Thread(target=_background_check, daemon=True, name="ExpireCheckThread").start()



    def _handle_subscription_expired(self, message: str) -> None:

        """Xử lý khi subscription hết hạn - logout, clear config và thông báo"""

        try:

            # Dừng tất cả tác vụ đang chạy

            self.stop_event.set()

            if self.executor:

                self.executor.shutdown(wait=False, cancel_futures=True)

                self.executor = None



            # Xóa token và clear toàn bộ config.json về {}

            from iting_api import ItingAPI

            api = ItingAPI()

            

            # Lấy user_id nếu có

            user_id = None

            try:

                import json

                token = api.load_auth_token()

                if token:

                    token_data = json.loads(token)

                    user_id = token_data.get("user_info", {}).get("id")

            except Exception:

                pass

            

            # Logout với clear_all_config=True để xóa hết config

            api.logout(user_id=user_id, clear_all_config=True)

            

            self._log("🗑️ Đã clear toàn bộ config.json khi hết hạn\n")



            # Hiển thị thông báo tùy chỉnh và đóng app khi user ấn Đóng

            self._show_custom_dialog(

                title="Hết hạn sử dụng",

                message=message,

                detail="Ứng dụng sẽ đóng. Vui lòng liên hệ quản trị viên để gia hạn.",

                dialog_type="error",

                on_close=self._force_close_app

            )



        except Exception as e:

            # Nếu có lỗi, vẫn cố gắng clear config rồi đóng app

            try:

                from iting_api import ItingAPI

                api = ItingAPI()

                api.clear_auth_token(clear_all=True)

            except Exception:

                pass

            self._force_close_app()



    def _force_close_app(self) -> None:

        """Đóng ứng dụng dứt điểm khi hết hạn hoặc khi cần thoát ngay."""

        try:

            # Dừng mọi tác vụ

            with suppress(Exception):

                self.stop_event.set()

            with suppress(Exception):

                if self.executor:

                    self.executor.shutdown(wait=False, cancel_futures=True)

                    self.executor = None

            # Thoát vòng lặp chính và hủy cửa sổ

            with suppress(Exception):

                self.root.quit()

            with suppress(Exception):

                self.root.update_idletasks()

            with suppress(Exception):

                self.root.destroy()

        finally:

            # Dùng os._exit để đảm bảo tiến trình kết thúc ngay cả khi Tkinter nuốt SystemExit

            try:

                import os

                os._exit(0)

            except Exception:

                pass



    def _show_expire_warning(self, message: str) -> None:

        """Hiển thị cảnh báo sắp hết hạn"""

        try:

            # Chỉ hiện 1 lần mỗi session

            if not hasattr(self, '_expire_warning_shown'):

                self._expire_warning_shown = True

                self._show_custom_dialog(

                    title="Cảnh báo",

                    message=message,

                    detail="Vui lòng gia hạn để tiếp tục sử dụng.",

                    dialog_type="warning"

                )

        except Exception:

            pass



    def _show_custom_dialog(self, title: str, message: str, detail: str = "", dialog_type: str = "info", on_close = None) -> None:

        """Hiển thị dialog tùy chỉnh đẹp mắt"""

        try:

            dialog = tb.Toplevel(self.root)

            dialog.title(title)

            dialog.geometry("450x200")

            dialog.resizable(False, False)



            # Bỏ dấu X nếu là popup hết hạn

            if dialog_type == "error" and "hết hạn" in title.lower():

                dialog.overrideredirect(True)



            # Căn giữa

            with suppress(Exception):

                self._center_window(dialog, 450, 200)



            # Icon

            with suppress(Exception):

                icon_path = Path(__file__).resolve().parent / "play.ico"

                if icon_path.exists():

                    dialog.iconbitmap(default=str(icon_path))



            # Màu nền theo loại

            bg_colors = {

                "error": "#FFE6E6",

                "warning": "#FFF7E6",

                "info": "#E6F3FF"

            }

            bg_color = bg_colors.get(dialog_type, "#F5F5F5")



            main_frame = tb.Frame(dialog, padding=20)

            main_frame.configure(style="Custom.TFrame")

            main_frame.pack(fill="both", expand=True)



            # Tạo style tùy chỉnh

            style = tb.Style()

            style.configure("Custom.TFrame", background=bg_color)

            style.configure("Title.TLabel", background=bg_color, font=("Arial", 14, "bold"))

            style.configure("Message.TLabel", background=bg_color, font=("Arial", 11))

            style.configure("Detail.TLabel", background=bg_color, font=("Arial", 10), foreground="#666666")



            # Tiêu đề

            title_label = tb.Label(main_frame, text=title, style="Title.TLabel")

            title_label.pack(pady=(0, 10))



            # Thông điệp chính

            msg_label = tb.Label(main_frame, text=message, style="Message.TLabel")

            msg_label.pack(pady=(0, 10))



            # Chi tiết (nếu có)

            if detail:

                detail_label = tb.Label(main_frame, text=detail, style="Detail.TLabel")

                detail_label.pack(pady=(0, 15))



            # Nút đóng

            btn_frame = tb.Frame(main_frame)

            btn_frame.configure(style="Custom.TFrame")

            btn_frame.pack()



            def close_action():

                try:

                    dialog.destroy()

                finally:

                    if on_close:

                        on_close()



            btn_close = tb.Button(

                btn_frame,

                text="Đóng",

                bootstyle="danger" if dialog_type == "error" else "warning" if dialog_type == "warning" else "primary",

                command=close_action,

                width=12

            )

            btn_close.pack()



            # Đặt focus và modal

            dialog.transient(self.root)

            dialog.grab_set()

            dialog.focus_set()



            # Đóng bằng ESC hoặc X

            dialog.bind('<Escape>', lambda e: close_action())

            dialog.protocol("WM_DELETE_WINDOW", close_action)



            # Nếu là popup hết hạn, buộc đóng ứng dụng khi popup bị hủy theo bất kỳ cách nào

            try:

                if dialog_type == "error" and "hết hạn" in title.lower():

                    dialog.bind("<Destroy>", lambda e: self._force_close_app())

            except Exception:

                pass

        except Exception:

            # Fallback về messagebox đơn giản, sau đó buộc đóng nếu là lỗi hết hạn

            try:

                Messagebox.show_info(f"{title}: {message}")

            finally:

                if dialog_type == "error" and "hết hạn" in title.lower():

                    # Đảm bảo đóng khi fallback

                    self._force_close_app()



    def _show_loading_dialog(self, parent, message: str):

        """Hiển thị dialog loading không chặn UI với spinner và message"""

        try:

            loading = tb.Toplevel(parent)

            loading.title("Đang tải...")

            loading.geometry("320x120")

            loading.resizable(False, False)



            # Căn giữa theo parent

            with suppress(Exception):

                parent.update_idletasks()

                x = parent.winfo_x() + (parent.winfo_width() // 2) - 160

                y = parent.winfo_y() + (parent.winfo_height() // 2) - 60

                loading.geometry(f"320x120+{x}+{y}")



            # Icon

            with suppress(Exception):

                icon_path = Path(__file__).resolve().parent / "play.ico"

                if icon_path.exists():

                    loading.iconbitmap(default=str(icon_path))



            # Frame chính với nền xanh nhạt

            main_frame = tb.Frame(loading, padding=20)

            main_frame.configure(style="Loading.TFrame")

            main_frame.pack(fill="both", expand=True)



            # Style cho loading

            style = tb.Style()

            style.configure("Loading.TFrame", background="#E6F3FF")

            style.configure("Loading.TLabel", background="#E6F3FF", font=("Arial", 11))



            # Progress bar (indeterminate - xoay vô hạn)

            progress = tb.Progressbar(main_frame, mode="indeterminate", bootstyle="info")

            progress.pack(pady=(0, 10), fill="x")

            progress.start(8)  # Smoother animation



            # Message với khả năng cập nhật

            msg_label = tb.Label(main_frame, text=message, style="Loading.TLabel")

            msg_label.pack()



            # Store reference for updates

            loading._msg_label = msg_label

            loading._progress = progress



            # Đặt modal nhưng không chặn hoàn toàn

            loading.transient(parent)

            loading.grab_set()



            # Allow processing events to keep UI responsive

            def keep_responsive():

                try:

                    if loading.winfo_exists():

                        loading.update_idletasks()

                        parent.after(50, keep_responsive)

                except Exception:

                    pass



            parent.after(50, keep_responsive)



            # Method to update message

            def update_message(new_msg):

                try:

                    if loading.winfo_exists():

                        loading._msg_label.configure(text=new_msg)

                        loading.update_idletasks()

                except Exception:

                    pass



            loading.update_message = update_message



            # Cho phép đóng bằng X và Escape

            def close_loading():

                try:

                    loading.destroy()

                except Exception:

                    pass



            loading.protocol("WM_DELETE_WINDOW", close_loading)

            loading.bind("<Escape>", lambda e: close_loading())



            # Đảm bảo window có thể đóng được

            loading.focus_set()



            return loading



        except Exception:

            # Fallback: return dummy object

            class DummyLoading:

                def destroy(self): pass

                def update_message(self, msg): pass

            return DummyLoading()



    def _refresh_account_info(self) -> None:

        """Làm mới thông tin tài khoản từ token hoặc API"""

        try:

            # Sử dụng check_iting_session để lấy thông tin mới nhất

            from iting_api import check_iting_session

            session_valid, session_data = check_iting_session()



            if not session_valid:

                self._update_account_display("Chưa đăng nhập", "", "", "")

                return



            # Sử dụng dữ liệu từ session

            username = session_data.get("username", "N/A")

            subscription = session_data.get("subscription", {})

            limits = session_data.get("limits", {})



                # Cập nhật thông tin lưu trữ

            self.user_info = {"username": username}

            self.subscription_info = subscription



            # Loại gói với màu

            sub_type = subscription.get("type", "free").title()

            sub_status = subscription.get("status", "")

            if "hết hạn" in sub_status.lower() or "expired" in sub_status.lower():

                sub_display = f"{sub_type} (Hết hạn)"

                sub_color = "#FF6B6B"

            elif "còn hiệu lực" in sub_status.lower():

                sub_display = f"{sub_type} (Hoạt động)"

                sub_color = "#51CF66"

            else:

                sub_display = sub_type

                sub_color = "#339AF0"



            # Video hôm nay

            used_today = limits.get("videos_used_today", 0)

            max_today = limits.get("max_videos_per_day", 5)

            remaining = max_today - used_today

            video_display = f"{used_today}/{max_today} (còn {remaining})"



            # Thời gian hết hạn

            days_remaining = subscription.get("days_remaining")

            if days_remaining is None:

                expire_display = "Không giới hạn"

                expire_color = "#51CF66"

            elif days_remaining < 0:

                # Đã hết hạn - logout ngay lập tức

                expire_display = "Đã hết hạn"

                expire_color = "#FF6B6B"

                self._update_account_display(username, sub_display, video_display, expire_display)

                self.lbl_subscription.configure(foreground=sub_color)

                self.lbl_expire.configure(foreground=expire_color)

                # Gọi logout sau khi cập nhật UI

                self.root.after(100, lambda: self._handle_subscription_expired("Gói dịch vụ đã hết hạn"))

                return

            elif days_remaining == 0:

                expire_display = "Hết hạn hôm nay"

                expire_color = "#FF6B6B"

            elif days_remaining <= 3:

                expire_display = f"{days_remaining} ngày"

                expire_color = "#FFD43B"

            else:

                expire_display = f"{days_remaining} ngày"

                expire_color = "#339AF0"



            self._update_account_display(username, sub_display, video_display, expire_display)



            # Đặt màu cho các label

            self.lbl_subscription.configure(foreground=sub_color)

            self.lbl_expire.configure(foreground=expire_color)

            

            # Kiểm tra status hết hạn

            if "hết hạn" in sub_status.lower() or "expired" in sub_status.lower():

                self.root.after(100, lambda: self._handle_subscription_expired("Gói dịch vụ đã hết hạn"))

                return



        except Exception as e:

            self._update_account_display("Lỗi kết nối", "", "", "")



    def _update_account_display(self, username: str, subscription: str, videos: str, expire: str) -> None:

        """Cập nhật hiển thị thông tin tài khoản"""

        try:

            self.lbl_username.configure(text=username)

            self.lbl_subscription.configure(text=subscription)

            self.lbl_videos.configure(text=videos)

            self.lbl_expire.configure(text=expire)

        except Exception:

            pass



